window.ATHANAS_BIBLE_BOOKS=window.ATHANAS_BIBLE_BOOKS||{};window.ATHANAS_BIBLE_BOOKS[19]={"id":19,"name":"Zaburi","testament":"OT","chapterCount":150,"chapters":[{"c":1,"verses":[{"v":1,"t":"Heri mtu yule asiyekwenda Katika shauri la wasio haki; Wala hakusimama katika njia ya wakosaji; Wala hakuketi barazani pa wenye mizaha."},{"v":2,"t":"Bali sheria ya Bwana ndiyo impendezayo, Na sheria yake huitafakari mchana na usiku."},{"v":3,"t":"Naye atakuwa kama mti uliopandwa Kandokando ya vijito vya maji, Uzaao matunda yake kwa majira yake, Wala jani lake halinyauki; Na kila alitendalo litafanikiwa."},{"v":4,"t":"Sivyo walivyo wasio haki; Hao ni kama makapi yapeperushwayo na upepo."},{"v":5,"t":"Kwa hiyo wasio haki hawatasimama hukumuni, Wala wakosaji katika kusanyiko la wenye haki."},{"v":6,"t":"Kwa kuwa Bwana anaijua njia ya wenye haki, Bali njia ya wasio haki itapotea."}]},{"c":2,"verses":[{"v":1,"t":"Mbona mataifa wanafanya ghasia, Na makabila wanatafakari ubatili?"},{"v":2,"t":"Wafalme wa dunia wanajipanga, Na wakuu wanafanya shauri pamoja, Juu ya Bwana, Na juu ya masihi wake."},{"v":3,"t":"Na tuvipasue vifungo vyao, Na kuzitupia mbali nasi kamba zao."},{"v":4,"t":"Yeye aketiye mbinguni anacheka, Bwana anawafanyia dhihaka."},{"v":5,"t":"Ndipo atakaposema nao kwa hasira yake, Na kuwafadhaisha kwa ghadhabu yake."},{"v":6,"t":"Nami nimemweka mfalme wangu Juu ya Sayuni, mlima wangu mtakatifu."},{"v":7,"t":"Nitaihubiri amri; Bwana aliniambia, Ndiwe mwanangu, Mimi leo nimekuzaa."},{"v":8,"t":"Uniombe, nami nitakupa mataifa kuwa urithi wako, Na miisho ya dunia kuwa milki yako."},{"v":9,"t":"Utawaponda kwa fimbo ya chuma, Na kuwavunja kama chombo cha mfinyanzi."},{"v":10,"t":"Na sasa, enyi wafalme, fanyeni akili, Enyi waamuzi wa dunia, mwadibiwe."},{"v":11,"t":"Mtumikieni Bwana kwa kicho, Shangilieni kwa kutetemeka."},{"v":12,"t":"Shikeni yaliyo bora asije akafanya hasira, Nanyi mkapotea njiani,Kwa kuwa hasira yake itawaka upesi,Heri wote wanaomkimbilia."}]},{"c":3,"verses":[{"v":1,"t":"Bwana, watesi wangu wamezidi kuwa wengi, Ni wengi wanaonishambulia,"},{"v":2,"t":"Ni wengi wanaoiambia nafsi yangu, Hana wokovu huyu kwa Mungu."},{"v":3,"t":"Na Wewe, Bwana, U ngao yangu pande zote, Utukufu wangu na mwinua kichwa changu."},{"v":4,"t":"Kwa sauti yangu namwita Bwana Naye aniitikia toka mlima wake mtakatifu."},{"v":5,"t":"Nalijilaza nikalala usingizi, nikaamka, Kwa kuwa Bwana ananitegemeza."},{"v":6,"t":"Sitayaogopa makumi elfu ya watu, Waliojipanga juu yangu pande zote."},{"v":7,"t":"Bwana, uinuke, Mungu wangu, uniokoe, Maana umewapiga taya adui zangu wote; Umewavunja meno wasio haki."},{"v":8,"t":"Wokovu una Bwana; Baraka yako na iwe juu ya watu wako."}]},{"c":4,"verses":[{"v":1,"t":"Ee Mungu wa haki yangu, uniitikie niitapo; Umenifanyizia nafasi wakati wa shida; Unifadhili na kuisikia sala yangu."},{"v":2,"t":"Enyi wanadamu, hata lini utukufu wangu utafedheheka? Je! Mtapenda ubatili na kutafuta uongo?"},{"v":3,"t":"Bali jueni ya kuwa Bwana amejiteulia mtauwa; Bwana atasikia nimwitapo."},{"v":4,"t":"Mwe na hofu wala msitende dhambi, Tafakarini vitandani mwenu na kutulia."},{"v":5,"t":"Toeni dhabihu za haki, Na kumtumaini Bwana."},{"v":6,"t":"Wengi husema, Nani atakayetuonyesha mema? Bwana, utuinulie nuru ya uso wako."},{"v":7,"t":"Umenitia furaha moyoni mwangu, Kupita yao wanapozidishiwa nafaka na divai."},{"v":8,"t":"Katika amani nitajilaza na kupata usingizi mara, Maana Wewe, Bwana, peke yako, Ndiwe unijaliaye kukaa salama."}]},{"c":5,"verses":[{"v":1,"t":"Ee Bwana, uyasikilize maneno yangu, Ukuangalie kutafakari kwangu."},{"v":2,"t":"Uisikie sauti ya kilio changu, Ee Mfalme wangu na Mungu wangu, Kwa maana Wewe ndiwe nikuombaye."},{"v":3,"t":"Bwana, asubuhi utaisikia sauti yangu, Asubuhi nitakupangia dua yangu na kutazamia."},{"v":4,"t":"Maana huwi Mungu apendezwaye na ubaya; Mtu mwovu hatakaa kwako;"},{"v":5,"t":"Wajivunao hawatasimama mbele za macho yako; Unawachukia wote watendao ubatili."},{"v":6,"t":"Utawaharibu wasemao uongo; Bwana humzira mwuaji na mwenye hila"},{"v":7,"t":"Bali mimi, kwa wingi wa fadhili zako, Nitaingia nyumbani mwako; Na kusujudu kwa kicho, Nikilielekea hekalu lako takatifu."},{"v":8,"t":"Bwana, uniongoze kwa haki yako, Kwa sababu yao wanaoniotea. Uisawazishe njia yako mbele ya uso wangu,"},{"v":9,"t":"Maana vinywani mwao hamna uaminifu; Mtima wao ni shimo tupu, koo lao ni kaburi wazi, Ulimi wao hujipendekeza."},{"v":10,"t":"Wewe, Mungu, uwapatilize, Na waanguke kwa mashauri yao. Uwatoe nje kwa ajili ya wingi wa makosa yao, Kwa maana wamekuasi Wewe."},{"v":11,"t":"Nao wote wanaokukimbilia watafurahi; Watapiga daima kelele za furaha. Kwa kuwa Wewe unawahifadhi, Walipendao jina lako watakufurahia."},{"v":12,"t":"Kwa maana Wewe utambariki mwenye haki; Bwana, utamzungushia radhi kama ngao."}]},{"c":6,"verses":[{"v":1,"t":"Bwana, usinikemee kwa hasira yako, Wala usinirudi kwa ghadhabu yako."},{"v":2,"t":"Bwana, unifadhili, maana ninanyauka; Bwana, uniponye, mifupa yangu imefadhaika."},{"v":3,"t":"Na nafsi yangu imefadhaika sana; Na Wewe, Bwana, hata lini?"},{"v":4,"t":"Bwana urudi, uniopoe nafsi yangu, Uniokoe kwa ajili ya fadhili zako."},{"v":5,"t":"Maana mautini hapana kumbukumbu lako; Katika kuzimu ni nani atakayekushukuru?"},{"v":6,"t":"Nimechoka kwa kuugua kwangu; Kila usiku nakieleza kitanda changu; Nalilowesha godoro langu kwa machozi yangu."},{"v":7,"t":"Jicho langu limeharibika kwa masumbufu, Na kuchakaa kwa sababu yao wanaoniudhi."},{"v":8,"t":"Ondokeni kwangu, ninyi nyote mtendao uovu; Kwa kuwa Bwana ameisikia sauti ya kilio changu."},{"v":9,"t":"Bwana ameisikia dua yangu; Bwana atayatakabali maombi yangu."},{"v":10,"t":"Adui zangu wote wataaibika na kufadhaika, Watarudi nyuma, kwa ghafula wataaibika."}]},{"c":7,"verses":[{"v":1,"t":"Bwana, Mungu wangu, nimekukimbilia Wewe, Uniokoe na wote wanaonifuatia, uniponye."},{"v":2,"t":"Asije akaipapura nafsi yangu kama simba, Akiivunja-vunja pasipokuwa na wa kuponya."},{"v":3,"t":"Bwana, Mungu wangu, ikiwa nimetenda haya, Ikiwa mna uovu mikononi mwangu,"},{"v":4,"t":"Ikiwa nimemlipa mabaya Yeye aliyekaa kwangu salama; (Hasha! Nimemponya yeye Aliyekuwa mtesi wangu bila sababu;)"},{"v":5,"t":"Basi adui na anifuatie, Na kuikamata nafsi yangu; Naam, aukanyage uzima wangu, Na kuulaza utukufu wangu mavumbini."},{"v":6,"t":"Bwana uondoke kwa hasira yako; Ujiinue juu ya jeuri ya watesi wangu; Uamke kwa ajili yangu; Umeamuru hukumu."},{"v":7,"t":"Kusanyiko la mataifa na likuzunguke, Na juu yake uketi utawale."},{"v":8,"t":"Bwana atawaamua mataifa, Bwana, unihukumu mimi, Kwa kadiri ya haki yangu, Sawasawa na unyofu nilio nao."},{"v":9,"t":"Ubaya wao wasio haki na ukome, Lakini umthibitishe mwenye haki. Kwa maana mjaribu mioyo na viuno Ndiye Mungu aliye mwenye haki."},{"v":10,"t":"Ngao yangu ina Mungu, Awaokoaye wanyofu wa moyo."},{"v":11,"t":"Mungu ni mwamuzi mwenye haki, Naam, Mungu aghadhibikaye kila siku."},{"v":12,"t":"Mtu asiporejea ataunoa upanga wake; Ameupinda uta wake na kuuweka tayari;"},{"v":13,"t":"Naye amemtengenezea silaha za kufisha, Akifanya mishale yake kuwa ya moto."},{"v":14,"t":"Tazama, huyu ana utungu wa uovu, Amechukua mimba ya madhara, amezaa uongo."},{"v":15,"t":"Amechimba shimo, amelichimba chini sana, Akatumbukia katika handaki aliyoifanya!"},{"v":16,"t":"Madhara yake yatamrejea kichwani pake, Na dhuluma yake itamshukia utosini."},{"v":17,"t":"Nitamshukuru Bwana kwa kadiri ya haki yake; Nitaliimbia jina la Bwana aliye juu."}]},{"c":8,"verses":[{"v":1,"t":"Wewe, MUNGU, Bwana wetu Jinsi lilivyo tukufu jina lako duniani mwote! Wewe umeuweka utukufu wako mbinguni;"},{"v":2,"t":"Vinywani mwa watoto wachanga na wanyonyao Umeiweka misingi ya nguvu; Kwa sababu yao wanaoshindana nawe; Uwakomeshe adui na mijilipiza kisasi."},{"v":3,"t":"Nikiziangalia mbingu zako, kazi ya vidole vyako, Mwezi na nyota ulizoziratibisha;"},{"v":4,"t":"Mtu ni kitu gani hata umkumbuke, Na binadamu hata umwangalie?"},{"v":5,"t":"Umemfanya mdogo punde kuliko Mungu; Umemvika taji ya utukufu na heshima;"},{"v":6,"t":"Umemtawaza juu ya kazi za mikono yako; Umevitia vitu vyote chini ya miguu yake."},{"v":7,"t":"Kondoo, na ng'ombe wote pia; Naam, na wanyama wa kondeni;"},{"v":8,"t":"Ndege wa angani, na samaki wa baharini; Na kila kipitacho njia za baharini."},{"v":9,"t":"Wewe, MUNGU, Bwana wetu, Jinsi lilivyo tukufu jina lako duniani mwote!"}]},{"c":9,"verses":[{"v":1,"t":"Nitamshukuru Bwana kwa moyo wangu wote; Nitayasimulia matendo yako yote ya ajabu;"},{"v":2,"t":"Nitafurahi na kukushangilia Wewe; Nitaliimbia jina lako, Wewe Uliye juu."},{"v":3,"t":"Kwa sababu adui zangu hurudi nyuma; Hujikwaa na kuangamia mbele zako."},{"v":4,"t":"Kwa maana umenifanyia hukumu na haki Umeketi kitini pa enzi ukihukumu kwa haki."},{"v":5,"t":"Umewakemea mataifa; Na kumwangamiza mdhalimu; Umelifuta jina lao milele na milele;"},{"v":6,"t":"Adui wamekoma na kuachwa ukiwa milele. Nayo miji yao uliing'oa; Hata kumbukumbu lao limepotea."},{"v":7,"t":"Bali Bwana atakaa milele, Ameweka kiti chake tayari kwa hukumu."},{"v":8,"t":"Naye atauhukumu ulimwengu kwa haki; Atawaamua watu kwa adili."},{"v":9,"t":"Bwana atakuwa ngome kwake aliyeonewa, Naam, ngome kwa nyakati za shida."},{"v":10,"t":"Nao wakujuao jina lako wakutumaini Wewe, Maana Wewe, Bwana hukuwaacha wakutafutao."},{"v":11,"t":"Mwimbieni Bwana akaaye Sayuni, Yatangazeni kati ya watu matendo yake."},{"v":12,"t":"Maana mlipiza kisasi cha damu awakumbuka, Hakukisahau kilio cha wanyonge."},{"v":13,"t":"Wewe, Bwana, unifadhili, Tazama mateso niteswayo na wanaonichukia; Wewe uniinuaye katika malango ya mauti,"},{"v":14,"t":"Ili nizisimulie sifa zako zote; Katika malango ya binti Sayuni Nitaufurahia wokovu wako."},{"v":15,"t":"Mataifa wamezama katika shimo walilolifanya; Kwa wavu waliouficha imenaswa miguu yao."},{"v":16,"t":"Bwana amejidhihirisha na kutekeleza hukumu; Amemnasa mdhalimu kwa kazi ya mikono yake."},{"v":17,"t":"Wadhalimu watarejea kuzimu, Naam, mataifa yote wanaomsahau Mungu."},{"v":18,"t":"Kwa maana mhitaji hatasahauliwa daima; Matumaini ya wanyonge hayatapotea milele."},{"v":19,"t":"Bwana, usimame, mwanadamu asipate nguvu, Mataifa wahukumiwe mbele zako."},{"v":20,"t":"Bwana, uwawekee kitisho, Mataifa na wajijue kuwa ni binadamu."}]},{"c":10,"verses":[{"v":1,"t":"Ee Bwana, kwa nini wasimama mbali? Kwani kujificha nyakati za shida?"},{"v":2,"t":"Kwa kiburi chake asiye haki mnyonge anafuatiwa kwa ukali; Na wanaswe kwa hila zizo hizo walizoziwaza."},{"v":3,"t":"Maana mdhalimu hujisifia tamaa ya nafsi yake, Na mwenye choyo humkana Bwana na kumdharau."},{"v":4,"t":"Mdhalimu kwa kiburi cha uso wake Asema, Hatapatiliza. Jumla ya mawazo yake ni, Hakuna Mungu;"},{"v":5,"t":"Njia zake ni thabiti kila wakati. Hukumu zako ziko juu asizione, Adui zake wote awafyonya."},{"v":6,"t":"Asema moyoni mwake, Sitaondoshwa, Kizazi baada ya kizazi sitakuwamo taabuni."},{"v":7,"t":"Kinywa chake kimejaa laana, Na hila na dhuluma. Chini ya ulimi wake kuna madhara na uovu,"},{"v":8,"t":"Hukaa katika maoteo ya vijiji. Mahali pa siri humwua asiye na hatia, Macho yake humvizia mtu duni."},{"v":9,"t":"Huotea faraghani kama simba pangoni, Huotea amkamate mtu mnyonge. Naam, humkamata mtu mnyonge, Akimkokota wavuni mwake."},{"v":10,"t":"Hujikunyata na kuinama; Watu duni huanguka kwa nguvu zake."},{"v":11,"t":"Asema moyoni mwake, Mungu amesahau, Auficha uso wake, haoni kamwe."},{"v":12,"t":"Bwana, uondoke, Ee Mungu, uuinue mkono wako, Usiwasahau wanyonge."},{"v":13,"t":"Kwani mdhalimu kumdharau Mungu. Akisema moyoni mwake, Hutapatiliza?"},{"v":14,"t":"Umeona, maana unaangalia madhara na jeuri, Uyatwae mkononi mwako. Mtu duni hukuachia nafsi yake, Maana umekuwa msaidizi wa yatima."},{"v":15,"t":"Uuvunje mkono wake mdhalimu, Na mbaya, uipatilize dhuluma yake, hata usiione."},{"v":16,"t":"Bwana ndiye Mfalme milele na milele; Mataifa wamepotea kutoka nchi yake."},{"v":17,"t":"Bwana, umeisikia tamaa ya wanyonge, Utaitengeneza mioyo yao, utalitega sikio lako."},{"v":18,"t":"Ili kumhukumu yatima naye aliyeonewa, Binadamu aliye udongo asizidi kudhulumu."}]},{"c":11,"verses":[{"v":1,"t":"Bwana ndiye niliyemkimbilia. Mbona mnaiambia nafsi yangu, Kimbia kama ndege mlimani kwenu?"},{"v":2,"t":"Maana, tazama, wasio haki wanaupinda uta, Wanaitia mishale yao katika upote, Ili kuwapiga gizani wanyofu wa moyo."},{"v":3,"t":"Kama misingi ikiharibika, Mwenye haki atafanya nini?"},{"v":4,"t":"Bwana yu katika hekalu lake takatifu. Bwana ambaye kiti chake kiko mbinguni, Macho yake yanaangalia; Kope zake zinawajaribu wanadamu."},{"v":5,"t":"Bwana humjaribu mwenye haki; Bali nafsi yake humchukia asiye haki, Na mwenye kupenda udhalimu."},{"v":6,"t":"Awanyeshee wasio haki mitego, Moto na kiberiti na upepo wa hari, Na viwe fungu la kikombe chao."},{"v":7,"t":"Kwa kuwa Bwana ndiye mwenye haki, Apenda matendo ya haki, Wanyofu wa moyo watamwona uso wake."}]},{"c":12,"verses":[{"v":1,"t":"Bwana, uokoe, maana mcha Mungu amekoma, Maana waaminifu wametoweka katika wanadamu."},{"v":2,"t":"Husemezana yasiyofaa kila mtu na mwenziwe, Wenye midomo ya kujipendekeza; Husemezana kwa mioyo ya unafiki;"},{"v":3,"t":"Bwana ataikata midomo yote ya kujipendekeza, Nao ulimi unenao maneno ya kiburi;"},{"v":4,"t":"Waliosema, Kwa ndimi zetu tutashinda; Midomo yetu ni yetu wenyewe, Ni nani aliye bwana juu yetu?"},{"v":5,"t":"Kwa ajili ya kuonewa kwao wanyonge, Kwa ajili ya kuugua kwao wahitaji, Sasa nitasimama, asema Bwana, Nitamweka salama yeye wanayemfyonya."},{"v":6,"t":"Maneno ya Bwana ni maneno safi, Ni fedha iliyojaribiwa kalibuni juu ya nchi; Iliyosafishwa mara saba."},{"v":7,"t":"Wewe, Bwana, ndiwe utakayetuhifadhi, Utatulinda na kizazi hiki milele."},{"v":8,"t":"Wasio haki hutembea pande zote, Ufisadi ukitukuka kati ya wanadamu."}]},{"c":13,"verses":[{"v":1,"t":"Ee Bwana, hata lini utanisahau, hata milele? Hata lini utanificha uso wako?"},{"v":2,"t":"Hata lini nifanye mashauri nafsini mwangu, Nikihuzunika moyoni mchana kutwa? Hata lini adui yangu atukuke juu yangu?"},{"v":3,"t":"Ee Bwana, Mungu wangu, uangalie, uniitikie; Uyatie nuru macho yangu, Nisije nikalala usingizi wa mauti."},{"v":4,"t":"Adui yangu asije akasema, Nimemshinda; Watesi wangu wasifurahi ninapoondoshwa."},{"v":5,"t":"Nami nimezitumainia fadhili zako; Moyo wangu na uufurahie wokovu wako."},{"v":6,"t":"Naam, nimwimbie Bwana, Kwa kuwa amenitendea kwa ukarimu."}]},{"c":14,"verses":[{"v":1,"t":"Mpumbavu amesema moyoni, Hakuna Mungu; Wameharibu matendo yao na kuyafanya chukizo, Hakuna atendaye mema."},{"v":2,"t":"Toka mbinguni Bwana aliwachungulia wanadamu, Aone kama yuko mtu mwenye akili, Amtafutaye Mungu."},{"v":3,"t":"Wote wamepotoka, wameoza wote pamoja, Hakuna atendaye mema, La! Hata mmoja."},{"v":4,"t":"Je! Wote wafanyao maovu hawajui? Walao watu wangu kama walavyo mkate, Hawamwiti Bwana."},{"v":5,"t":"Hapo ndipo walipoingiwa na hofu nyingi, Maana Mungu yupo pamoja na kizazi cha haki."},{"v":6,"t":"Mnalitia aibu shauri la mtu mnyonge, Bali Bwana ndiye aliye kimbilio lake."},{"v":7,"t":"Laiti wokovu wa Israeli utoke katika Sayuni! Bwana awarudishapo wafungwa wa watu wake; Yakobo atashangilia, Israeli atafurahi."}]},{"c":15,"verses":[{"v":1,"t":"Bwana, ni nani atakayekaa Katika hema yako? Ni nani atakayefanya maskani yake Katika kilima chako kitakatifu?"},{"v":2,"t":"Ni mtu aendaye kwa ukamilifu, Na kutenda haki. Asemaye kweli kwa moyo wake,"},{"v":3,"t":"Asiyesingizia kwa ulimi wake. Wala hakumtenda mwenziwe mabaya, Wala hakumsengenya jirani yake."},{"v":4,"t":"Machoni pake mtu asiyefaa hudharauliwa, Bali huwaheshimu wamchao Bwana Ingawa ameapa kwa hasara yake, Hayabadili maneno yake."},{"v":5,"t":"Hakutoa fedha yake apate kula riba, Hakutwaa rushwa amwangamize asiye na hatia. Mtu atendaye mambo hayo Hataondoshwa milele."}]},{"c":16,"verses":[{"v":1,"t":"Mungu, unihifadhi mimi, Kwa maana nakukimbilia Wewe."},{"v":2,"t":"Nimemwambia Bwana, Ndiwe Bwana wangu; Sina wema ila utokao kwako."},{"v":3,"t":"Watakatifu waliopo duniani ndio Walio bora, Hao ndio niliopendezwa nao."},{"v":4,"t":"Huzuni zao zitaongezeka Wambadilio Mungu kwa mwingine; Sitazimimina sadaka zao za damu, Wala kuyataja majina yao midomoni mwangu."},{"v":5,"t":"Bwana ndiye fungu la posho langu, Na la kikombe changu; Wewe unaishika kura yangu."},{"v":6,"t":"Kamba zangu zimeniangukia mahali pema, Naam, nimepata urithi mzuri."},{"v":7,"t":"Nitamhimidi Bwana aliyenipa shauri, Naam, mtima wangu umenifundisha usiku."},{"v":8,"t":"Nimemweka Bwana mbele yangu daima, Kwa kuwa yuko kuumeni kwangu, sitaondoshwa."},{"v":9,"t":"Kwa hiyo moyo wangu unafurahi, Nao utukufu wangu unashangilia, Naam, mwili wangu nao utakaa kwa kutumaini."},{"v":10,"t":"Maana hutakuachia kuzimu nafsi yangu, Wala hutamtoa mtakatifu wako aone uharibifu."},{"v":11,"t":"Utanijulisha njia ya uzima; Mbele za uso wako ziko furaha tele; Na katika mkono wako wa kuume Mna mema ya milele."}]},{"c":17,"verses":[{"v":1,"t":"Ee Bwana, usikie haki, ukisikilize kilio changu, Utege sikio lako kwa maombi yangu, Yasiyotoka katika midomo ya hila."},{"v":2,"t":"Hukumu yangu na itoke kwako, Macho yako na yatazame mambo ya adili."},{"v":3,"t":"Umenijaribu moyo wangu, umenijilia usiku, Umenihakikisha usione neno; Nimenuia kinywa changu kisikose,"},{"v":4,"t":"Mintarafu matendo ya wanadamu; Kwa neno la midomo yako Nimejiepusha na njia za wenye jeuri."},{"v":5,"t":"Nyayo zangu zimeshikamana na njia zako, Hatua zangu hazikuondoshwa."},{"v":6,"t":"Ee Mungu, nimekuita kwa maana utaitika, Utege sikio lako ulisikie neno langu."},{"v":7,"t":"Dhihirisha fadhili zako za ajabu Wewe uwaokoaye wanaokukimbilia; Kwa mkono wako wa kuume Uwaokoe nao wanaowaondokea."},{"v":8,"t":"Unilinde kama mboni ya jicho, Unifiche chini ya uvuli wa mbawa zako;"},{"v":9,"t":"Wasinione wasio haki wanaonionea, Adui za roho yangu wanaonizunguka."},{"v":10,"t":"Wameukaza moyo wako, Kwa vinywa vyao hutoa majivuno."},{"v":11,"t":"Sasa wametuzunguka hatua zetu, Na kuyakaza macho yao watuangushe chini."},{"v":12,"t":"Kama mfano wa simba atakaye kurarua, Kama mwana-simba aoteaye katika maoteo yake."},{"v":13,"t":"Ee Bwana, usimame, umkabili, umwinamishe, Kwa upanga wako uniokoe nafsi na mtu mbaya."},{"v":14,"t":"Ee Bwana, kwa mkono wako uniokoe na watu, Watu wa dunia hii ambao fungu lao li katika maisha haya. Matumbo yao wayajaza kwa hazina yako, Hushiba wana, huwaachia watoto wao akiba zao,"},{"v":15,"t":"Bali mimi nikutazame uso wako katika haki, Niamkapo nishibishwe kwa sura yako."}]},{"c":18,"verses":[{"v":1,"t":"Wewe, Bwana, nguvu zangu, nakupenda sana;"},{"v":2,"t":"Bwana ni jabali langu, na boma langu, na mwokozi wangu, Mungu wangu, mwamba wangu ninayemkimbilia, Ngao yangu, na pembe ya wokovu wangu, na ngome yangu."},{"v":3,"t":"Nitamwita Bwana astahiliye kusifiwa, Hivyo nitaokoka na adui zangu."},{"v":4,"t":"Kamba za mauti zilinizunguka, Mafuriko ya uovu yakanitia hofu."},{"v":5,"t":"Kamba za kuzimu zilinizunguka, Mitego ya mauti ikanikabili."},{"v":6,"t":"Katika shida yangu nalimwita Bwana, Na kumlalamikia Mungu wangu. Akaisikia sauti yangu hekaluni mwake, Kilio changu kikaingia masikioni mwake."},{"v":7,"t":"Ndipo nchi iliyotikisika na kutetemeka, Misingi ya milima ikasuka-suka; Ikatikisika kwa sababu alikuwa na ghadhabu."},{"v":8,"t":"Kukapanda moshi kutoka puani mwake, Moto ukatoka kinywani mwake ukala, Makaa yakawashwa nao."},{"v":9,"t":"Aliziinamisha mbingu akashuka, Kukawa na giza kuu chini ya miguu yake."},{"v":10,"t":"Akapanda juu ya kerubi akaruka, Naam, aliruka upesi juu ya mabawa ya upepo."},{"v":11,"t":"Alifanya giza kuwa mahali pake pa kujificha, Kuwa hema yake ya kumzunguka. Giza la maji na mawingu makuu ya mbinguni."},{"v":12,"t":"Toka mwangaza uliokuwa mbele zake Kukapita mawingu yake makuu. Mvua ya mawe na makaa ya moto."},{"v":13,"t":"Bwana alipiga radi mbinguni, Yeye Aliye juu akaitoa sauti yake, Mvua ya mawe na makaa ya moto."},{"v":14,"t":"Akaipiga mishale yake akawatawanya, Naam, umeme mwingi sana, akawatapanya."},{"v":15,"t":"Ndipo ilipoonekana mikondo ya maji, Misingi ya ulimwengu ikafichuliwa, Ee Bwana, kwa kukemea kwako, Kwa mvumo wa pumzi ya puani mwako."},{"v":16,"t":"Alipeleka kutoka juu akanishika, Na kunitoa katika maji mengi."},{"v":17,"t":"Akaniokoa na adui yangu mwenye nguvu, Na wale walionichukia, Maana walikuwa na nguvu kuliko mimi."},{"v":18,"t":"Walinikabili siku ya msiba wangu, Lakini Bwana alikuwa tegemeo langu."},{"v":19,"t":"Akanitoa akanipeleka panapo nafasi, Aliniponya kwa kuwa alipendezwa nami."},{"v":20,"t":"Bwana alinitendea sawasawa na haki yangu, Sawasawa na usafi wa mikono yangu akanilipa."},{"v":21,"t":"Maana nimezishika njia za Bwana, Wala sikumwasi Mungu wangu."},{"v":22,"t":"Hukumu zake zote zilikuwa mbele yangu, Wala amri zake sikujiepusha nazo."},{"v":23,"t":"Nami nalikuwa mkamilifu mbele zake, Nikajilinda na uovu wangu."},{"v":24,"t":"Mradi Bwana amenilipa sawasawa na haki yangu, Sawasawa na usafi wa mikono yangu mbele zake."},{"v":25,"t":"Kwa mtu mwenye fadhili utakuwa mwenye fadhili; Kwa mkamilifu utajionyesha kuwa mkamilifu;"},{"v":26,"t":"Kwake ajitakasaye utajionyesha kuwa mtakatifu; Na kwa mpotovu utajionyesha kuwa mkaidi."},{"v":27,"t":"Maana Wewe utawaokoa watu wanaoonewa, Na macho ya kiburi utayadhili."},{"v":28,"t":"Kwa kuwa Wewe unaiwasha taa yangu; Bwana Mungu wangu aniangazia giza langu."},{"v":29,"t":"Maana kwa msaada wako nafuatia jeshi, Kwa msaada wa Mungu wangu naruka ukuta."},{"v":30,"t":"Mungu, njia yake ni kamilifu, Ahadi ya Bwana imehakikishwa, Yeye ndiye ngao yao. Wote wanaomkimbilia."},{"v":31,"t":"Maana ni nani aliye Mungu ila Bwana? Ni nani aliye mwamba ila Mungu wetu?"},{"v":32,"t":"Mungu ndiye anifungaye mshipi wa nguvu, Naye anaifanya kamilifu njia yangu."},{"v":33,"t":"Miguu yangu anaifanya kuwa ya kulungu, Na kunisimamisha mahali pangu pa juu."},{"v":34,"t":"Ananifundisha mikono yangu vita, Mikono yangu ikaupinda upinde wa shaba."},{"v":35,"t":"Nawe umenipa ngao ya wokovu wako, Mkono wako wa kuume umenitegemeza, Na unyenyekevu wako umenikuza."},{"v":36,"t":"Umezifanyizia nafasi hatua zangu, Na miguu yangu haikuteleza."},{"v":37,"t":"Nitawafuatia adui zangu na kuwapata, Wala sitarudi nyuma hata wakomeshwe."},{"v":38,"t":"Nitawapiga-piga wasiweze kusimama, Wataanguka chini ya miguu yangu."},{"v":39,"t":"Nawe hunifunga mshipi wa nguvu kwa vita, Hunitiishia chini yangu walioniondokea."},{"v":40,"t":"Naam, adui zangu umewafanya wanipe visogo, Nao walionichukia nimewakatilia mbali."},{"v":41,"t":"Walipiga yowe, lakini hakuna wa kuokoa, Walimwita Bwana lakini hakuwajibu,"},{"v":42,"t":"Nikawaponda kama mavumbi mbele ya upepo, Nikawatupa nje kama matope ya njiani."},{"v":43,"t":"Umeniokoa na mashindano ya watu, Umenifanya niwe kichwa cha mataifa. Watu nisiowajua walinitumikia."},{"v":44,"t":"Kwa kusikia tu habari zangu, Mara wakanitii. Wageni walinijia wakinyenyekea."},{"v":45,"t":"Wageni nao walitepetea, Walitoka katika ngome zao wakitetemeka."},{"v":46,"t":"Bwana ndiye aliye hai; Na ahimidiwe mwamba wangu; Na atukuzwe Mungu wa wokovu wangu;"},{"v":47,"t":"Ndiye Mungu anipatiaye kisasi; Na kuwatiisha watu chini yangu."},{"v":48,"t":"Huniponya na adui zangu; Naam, waniinua juu yao walioniinukia, Na kuniponya na mtu wa jeuri."},{"v":49,"t":"Basi, Bwana, nitakushukuru kati ya mataifa, Nami nitaliimbia jina lako."},{"v":50,"t":"Ampa mfalme wake wokovu mkuu, Amfanyia fadhili masihi wake,Daudi na mzao wake hata milele."}]},{"c":19,"verses":[{"v":1,"t":"Mbingu zauhubiri utukufu wa Mungu, Na anga laitangaza kazi ya mikono yake."},{"v":2,"t":"Mchana husemezana na mchana, Usiku hutolea usiku maarifa."},{"v":3,"t":"Hakuna lugha wala maneno, Sauti yao haisikilikani."},{"v":4,"t":"Sauti yao imeenea duniani mwote, Na maneno yao hata miisho ya ulimwengu. Katika hizo ameliwekea jua hema,"},{"v":5,"t":"Kama bwana arusi akitoka chumbani mwake, Lafurahi kama mtu aliye hodari Kwenda mbio katika njia yake."},{"v":6,"t":"Kutoka kwake lautoka mwisho wa mbingu, Na kuzunguka kwake hata miisho yake, Wala kwa hari yake Hakuna kitu kilichositirika."},{"v":7,"t":"Sheria ya Bwana ni kamilifu, Huiburudisha nafsi. Ushuhuda wa Bwana ni amini, Humtia mjinga hekima."},{"v":8,"t":"Maagizo ya Bwana ni ya adili, Huufurahisha moyo. Amri ya Bwana ni safi, Huyatia macho nuru."},{"v":9,"t":"Kicho cha Bwana ni kitakatifu, Kinadumu milele. Hukumu za Bwana ni kweli, Zina haki kabisa."},{"v":10,"t":"Ni za kutamanika kuliko dhahabu, Kuliko wingi wa dhahabu safi. Nazo ni tamu kuliko asali, Kuliko sega la asali."},{"v":11,"t":"Tena mtumishi wako huonywa kwazo, Katika kuzishika kuna thawabu nyingi."},{"v":12,"t":"Ni nani awezaye kuyatambua makosa yake? Unitakase na mambo ya siri."},{"v":13,"t":"Umzuie mtumishi wako asitende mambo ya kiburi, Yasinitawale mimi. Ndipo nitakapokuwa kamili, Nami nitakuwa safi, sina kosa lililo kubwa."},{"v":14,"t":"Maneno ya kinywa changu, Na mawazo ya moyo wangu, Yapate kibali mbele zako, Ee Bwana, Mwamba wangu, na mwokozi wangu."}]},{"c":20,"verses":[{"v":1,"t":"Bwana akujibu siku ya dhiki, Jina la Mungu wa Yakobo likuinue."},{"v":2,"t":"Akupelekee msaada toka patakatifu pake, Na kukutegemeza toka Sayuni."},{"v":3,"t":"Azikumbuke sadaka zako zote, Na kuzitakabali dhabihu zako."},{"v":4,"t":"Akujalie kwa kadiri ya haja ya moyo wako, Na kuyatimiza mashauri yako yote."},{"v":5,"t":"Na tuushangilie wokovu wako, Kwa jina la Mungu wetu tuzitweke bendera zetu. Bwana akutimizie matakwa yako yote."},{"v":6,"t":"Sasa najua kuwa Bwana amwokoa masihi wake;Atamjibu kutoka mbingu zake takatifu."},{"v":7,"t":"Hawa wanataja magari na hawa farasi, Bali sisi tutalitaja jina la Bwana, Mungu wetu."},{"v":8,"t":"Wao wameinama na kuanguka, Bali sisi tumeinuka na kusimama."},{"v":9,"t":"Bwana, umwokoe mfalme, Utuitikie siku tuitayo."}]},{"c":21,"verses":[{"v":1,"t":"Ee Bwana, mfalme atazifurahia nguvu zako, Na wokovu wako ataufanyia shangwe nyingi sana."},{"v":2,"t":"Umempa haja ya moyo wake, Wala hukumzuilia matakwa ya midomo yake."},{"v":3,"t":"Maana umemsogezea baraka za heri, Umemvika taji ya dhahabu safi kichwani pake."},{"v":4,"t":"Alikuomba uhai, ukampa, Muda mrefu wa siku nyingi, milele na milele."},{"v":5,"t":"Utukufu wake ni mkuu kwa wokovu wako, Heshima na adhama waweka juu yake."},{"v":6,"t":"Maana umemfanya kuwa baraka za milele, Wamfurahisha kwa furaha ya uso wako."},{"v":7,"t":"Kwa kuwa mfalme humtumaini Bwana, Na kwa fadhili zake Aliye juu hataondoshwa."},{"v":8,"t":"Mkono wako utawapata adui zako wote, Mkono wako wa kuume utawapata wanaokuchukia."},{"v":9,"t":"Utawafanya kuwa kama tanuru ya moto, Wakati wa ghadhabu yako. Bwana atawameza kwa ghadhabu yake, Na moto utawala."},{"v":10,"t":"Matunda yao utayaharibu na kuyaondoa katika nchi, Na wazao wao katika wanadamu."},{"v":11,"t":"Madhali walinuia kukutenda mabaya, Waliwaza hila wasipate kuitimiza."},{"v":12,"t":"Kwa maana utawafanya kukupa kisogo, Kwa upote wa uta wako ukiwaelekezea mishale."},{"v":13,"t":"Ee Bwana, utukuzwe kwa nguvu zako, Nasi tutaimba na kuuhimidi uweza wako."}]},{"c":22,"verses":[{"v":1,"t":"Mungu wangu, Mungu wangu, Mbona umeniacha? Mbona U mbali na wokovu wangu, Na maneno ya kuugua kwangu?"},{"v":2,"t":"Ee Mungu wangu, nalia mchana lakini hujibu Na wakati wa usiku lakini sipati raha."},{"v":3,"t":"Na Wewe U Mtakatifu, Uketiye juu ya sifa za Israeli."},{"v":4,"t":"Baba zetu walikutumaini Wewe, Walitumaini, na Wewe ukawaokoa."},{"v":5,"t":"Walikulilia Wewe wakaokoka, Walikutumaini wasiaibike."},{"v":6,"t":"Lakini mimi ni mdudu wala si mtu, Laumu ya wanadamu na mzaha wa watu."},{"v":7,"t":"Wote wanionao hunicheka sana, Hunifyonya, wakitikisa vichwa vyao;"},{"v":8,"t":"Husema, Umtegemee Bwana; na amponye; Na amwokoe sasa, maana apendezwa naye."},{"v":9,"t":"Naam, Wewe ndiwe uliyenitoa tumboni, Ulinitumainisha matitini mwa mama yangu."},{"v":10,"t":"Kwako nalitupwa tangu tumboni, Toka tumboni mwa mamangu ndiwe Mungu wangu."},{"v":11,"t":"Usiwe mbali nami maana taabu i karibu, Kwa maana hakuna msaidizi."},{"v":12,"t":"Mafahali wengi wamenizunguka, Walio hodari wa Bashani wamenisonga;"},{"v":13,"t":"Wananifumbulia vinywa vyao, Kama simba apapuraye na kunguruma."},{"v":14,"t":"Nimemwagika kama maji, Mifupa yangu yote imeteguka, Moyo wangu umekuwa kama nta, Na kuyeyuka ndani ya mtima wangu."},{"v":15,"t":"Nguvu zangu zimekauka kama gae, Ulimi wangu waambatana na taya zangu; Unaniweka katika mavumbi ya mauti"},{"v":16,"t":"Kwa maana mbwa wamenizunguka; Kusanyiko la waovu wamenisonga; Wamenizua mikono na miguu."},{"v":17,"t":"Naweza kuihesabu mifupa yangu yote; Wao wananitazama na kunikodolea macho."},{"v":18,"t":"Wanagawanya nguo zangu, Na vazi langu wanalipigia kura."},{"v":19,"t":"Nawe, Bwana, usiwe mbali, Ee Nguvu zangu, fanya haraka kunisaidia."},{"v":20,"t":"Uniponye nafsi yangu na upanga, Mpenzi wangu na nguvu za mbwa."},{"v":21,"t":"Kinywani mwa simba uniokoe; Naam, toka pembe za nyati umenijibu."},{"v":22,"t":"Nitalihubiri jina lako kwa ndugu zangu, Katikati ya kusanyiko nitakusifu."},{"v":23,"t":"Ninyi mnaomcha Bwana, msifuni, Enyi nyote mlio wazao wa Yakobo, mtukuzeni, Mcheni, enyi nyote mlio wazao wa Israeli."},{"v":24,"t":"Maana hakulidharau teso la mteswa, Wala hakuchukizwa nalo; Wala hakumficha uso wake, Bali alipomlilia akamsikia."},{"v":25,"t":"Kwako zinatoka sifa zangu Katika kusanyiko kubwa. Nitaziondoa nadhiri zangu Mbele yao wamchao."},{"v":26,"t":"Wapole watakula na kushiba, Wamtafutao Bwana watamsifu; Mioyo yenu na iishi milele."},{"v":27,"t":"Miisho yote ya dunia itakumbuka, Na watu watamrejea Bwana; Jamaa zote za mataifa watamsujudia."},{"v":28,"t":"Maana ufalme una Bwana, Naye ndiye awatawalaye mataifa."},{"v":29,"t":"Wakwasi wote wa dunia watakula na kusujudu, Humwinamia wote washukao mavumbini; Naam, yeye asiyeweza kujihuisha nafsi yake,"},{"v":30,"t":"Wazao wake watamtumikia. Zitasimuliwa habari za Bwana, Kwa kizazi kitakachokuja,"},{"v":31,"t":"Nao watawahubiri watakaozaliwa haki yake, Ya kwamba ndiye aliyeyafanya."}]},{"c":23,"verses":[{"v":1,"t":"Bwana ndiye mchungaji wangu, Sitapungukiwa na kitu."},{"v":2,"t":"Katika malisho ya majani mabichi hunilaza, Kando ya maji ya utulivu huniongoza."},{"v":3,"t":"Hunihuisha nafsi yangu; na kuniongoza Katika njia za haki kwa ajili ya jina lake."},{"v":4,"t":"Naam, nijapopita kati ya bonde la uvuli wa mauti, Sitaogopa mabaya; Kwa maana Wewe upo pamoja nami, Gongo lako na fimbo yako vyanifariji."},{"v":5,"t":"Waandaa meza mbele yangu, Machoni pa watesi wangu. Umenipaka mafuta kichwani pangu, Na kikombe changu kinafurika."},{"v":6,"t":"Hakika wema na fadhili zitanifuata Siku zote za maisha yangu; Nami nitakaa nyumbani mwa Bwana milele."}]},{"c":24,"verses":[{"v":1,"t":"Nchi na vyote viijazavyo ni mali ya Bwana, Dunia na wote wakaao ndani yake."},{"v":2,"t":"Maana ameiweka misingi yake juu ya bahari, Na juu ya mito ya maji aliithibitisha."},{"v":3,"t":"Ni nani atakayepanda katika mlima wa Bwana? Ni nani atakayesimama katika patakatifu pake?"},{"v":4,"t":"Mtu aliye na mikono safi na moyo mweupe, Asiyeiinua nafsi yake kwa ubatili, Wala hakuapa kwa hila."},{"v":5,"t":"Atapokea baraka kwa Bwana, Na haki kwa Mungu wa wokovu wake."},{"v":6,"t":"Hiki ndicho kizazi cha wamtafutao, Wakutafutao uso wako, Ee Mungu wa Yakobo."},{"v":7,"t":"Inueni vichwa vyenu, enyi malango, Inukeni, enyi malango ya milele, Mfalme wa utukufu apate kuingia."},{"v":8,"t":"Ni nani Mfalme wa utukufu? Bwana mwenye nguvu, hodari, Bwana hodari wa vita."},{"v":9,"t":"Inueni vichwa vyenu, enyi malango, Naam, viinueni, enyi malango ya milele, Mfalme wa utukufu apate kuingia."},{"v":10,"t":"Ni nani huyu Mfalme wa utukufu? Bwana wa majeshi, Yeye ndiye Mfalme wa utukufu."}]},{"c":25,"verses":[{"v":1,"t":"Ee Bwana, nakuinulia nafsi yangu,"},{"v":2,"t":"Ee Mungu wangu, Nimekutumaini Wewe, nisiaibike, Adui zangu wasifurahi kwa kunishinda."},{"v":3,"t":"Naam, wakungojao hawataaibika hata mmoja; Wataaibika watendao uhaini bila sababu."},{"v":4,"t":"Ee Bwana, unijulishe njia zako, Unifundishe mapito yako,"},{"v":5,"t":"Uniongoze katika kweli yako, Na kunifundisha. Maana Wewe ndiwe Mungu wa wokovu wangu, Nakungoja Wewe mchana kutwa."},{"v":6,"t":"Ee Bwana, kumbuka rehema zako na fadhili zako, Maana zimekuwako tokea zamani."},{"v":7,"t":"Usiyakumbuke makosa ya ujana wangu, Wala maasi yangu. Unikumbuke kwa kadiri ya fadhili zako, Ee Bwana kwa ajili ya wema wako."},{"v":8,"t":"Bwana yu mwema, mwenye adili, Kwa hiyo atawafundisha wenye dhambi njia."},{"v":9,"t":"Wenye upole atawaongoza katika hukumu, Wenye upole atawafundisha njia yake."},{"v":10,"t":"Njia zote za Bwana ni fadhili na kweli, Kwao walishikao agano lake na shuhuda zake."},{"v":11,"t":"Ee Bwana, kwa ajili ya jina lako, Unisamehe uovu wangu, maana ni mwingi."},{"v":12,"t":"Ni nani amchaye Bwana? Atamfundisha katika njia anayoichagua."},{"v":13,"t":"Nafsi yake itakaa hali ya kufanikiwa; Wazao wake watairithi nchi."},{"v":14,"t":"Siri ya Bwana iko kwao wamchao, Naye atawajulisha agano lake."},{"v":15,"t":"Macho yangu humwelekea Bwana daima, Naye atanitoa miguu yangu katika wavu."},{"v":16,"t":"Uniangalie na kunifadhili, Maana mimi ni mkiwa na mteswa."},{"v":17,"t":"Katika shida za moyo wangu unifanyie nafasi, Na kunitoa katika dhiki zangu."},{"v":18,"t":"Utazame teso langu na taabu yangu; Unisamehe dhambi zangu zote."},{"v":19,"t":"Uwatazame adui zangu, maana ni wengi, Wananichukia kwa machukio ya ukali."},{"v":20,"t":"Unilinde nafsi yangu na kuniponya, Nisiaibike, maana nakukimbilia Wewe."},{"v":21,"t":"Ukamilifu na unyofu zinihifadhi, Maana nakungoja Wewe."},{"v":22,"t":"Ee Mungu, umkomboe Israeli, Katika taabu zake zote."}]},{"c":26,"verses":[{"v":1,"t":"Ee Bwana, unihukumu mimi, Maana nimekwenda kwa ukamilifu wangu, Nami nimemtumaini Bwana bila wasiwasi."},{"v":2,"t":"Ee Bwana, unijaribu na kunipima; Unisafishe mtima wangu na moyo wangu."},{"v":3,"t":"Maana fadhili zako zi mbele ya macho yangu, Nami nimekwenda katika kweli yako."},{"v":4,"t":"Sikuketi pamoja na watu wa ubatili, Wala sitaingia mnamo wanafiki."},{"v":5,"t":"Nimelichukia kusanyiko la watenda mabaya, Wala sitaketi pamoja na watu waovu."},{"v":6,"t":"Nitanawa mikono yangu kwa kutokuwa na hatia, Na kuizunguka madhabahu yako, Ee Bwana"},{"v":7,"t":"Ili niitangaze sauti ya kushukuru, Na kuzisimulia kazi zako za ajabu."},{"v":8,"t":"Bwana, nimependa makao ya nyumba yako, Na mahali pa maskani ya utukufu wako."},{"v":9,"t":"Usiiondoe nafsi yangu pamoja na wakosaji, Wala uhai wangu pamoja na watu wa damu."},{"v":10,"t":"Mikononi mwao mna madhara, Na mkono wao wa kuume umejaa rushwa."},{"v":11,"t":"Ila mimi nitakwenda kwa ukamilifu wangu; Unikomboe, unifanyie fadhili."},{"v":12,"t":"Mguu wangu umesimama palipo sawa; Katika makusanyiko nitamhimidi Bwana."}]},{"c":27,"verses":[{"v":1,"t":"Bwana ni nuru yangu na wokovu wangu, Nimwogope nani? Bwana ni ngome ya uzima wangu, Nimhofu nani?"},{"v":2,"t":"Watenda mabaya waliponikaribia, Wanile nyama yangu, Watesi wangu na adui zangu, Walijikwaa wakaanguka."},{"v":3,"t":"Jeshi lijapojipanga kupigana nami, Moyo wangu hautaogopa. Vita vijaponitokea, Hata hapo nitatumaini."},{"v":4,"t":"Neno Moja nimelitaka kwa Bwana, Nalo ndilo nitakalolitafuta, Nikae nyumbani mwa Bwana Siku zote za maisha yangu, Niutazame uzuri wa Bwana, Na kutafakari hekaluni mwake."},{"v":5,"t":"Mradi atanisitiri bandani mwake siku ya mabaya, Atanisitiri katika sitara ya hema yake, Na kuniinua juu ya mwamba."},{"v":6,"t":"Na sasa kichwa changu kitainuka Juu ya adui zangu wanaonizunguka. Nami nitatoa dhabihu za shangwe hemani mwake; Nitaimba, naam, nitamhimidi Bwana."},{"v":7,"t":"Ee Bwana, usikie, kwa sauti yangu ninalia, Unifadhili, unijibu."},{"v":8,"t":"Uliposema, Nitafuteni uso wangu, Moyo wangu umekuambia, Bwana, uso wako nitautafuta."},{"v":9,"t":"Usinifiche uso wako, Usijiepushe na mtumishi wako kwa hasira. Umekuwa msaada wangu, usinitupe, Wala usiniache, Ee Mungu wa wokovu wangu."},{"v":10,"t":"Baba yangu na mama yangu wameniacha, Bali Bwana atanikaribisha kwake."},{"v":11,"t":"Ee Bwana, unifundishe njia yako, Na kuniongoza katika njia iliyonyoka; Kwa sababu yao wanaoniotea;"},{"v":12,"t":"Usinitie katika nia ya watesi wangu; Maana mashahidi wa uongo wameniondokea, Nao watoao jeuri kama pumzi."},{"v":13,"t":"Naamini ya kuwa nitauona wema wa Bwana Katika nchi ya walio hai."},{"v":14,"t":"Umngoje Bwana, uwe hodari, Upige moyo konde, naam, umngoje Bwana."}]},{"c":28,"verses":[{"v":1,"t":"Ee Bwana, nitakuita Wewe, mwamba wangu, Usiwe kwangu kama kiziwi. Nisije nikafanana nao washukao shimoni, Ikiwa umeninyamalia."},{"v":2,"t":"Uisikie sauti ya dua yangu nikuombapo, Nikipainulia patakatifu pako mikono yangu."},{"v":3,"t":"Usinikokote pamoja na wasio haki, Wala pamoja na watenda maovu. Wawaambiao jirani zao maneno ya amani, Lakini mioyoni mwao mna madhara."},{"v":4,"t":"Uwape sawasawa na vitendo vyao, Na kwa kadiri ya ubaya wa kufanya kwao, Uwape sawasawa na kazi ya mikono yao, Uwalipe stahili zao."},{"v":5,"t":"Maana hawazifahamu kazi za Bwana, Wala matendo ya mikono yake. Atawavunja wala hatawajenga;"},{"v":6,"t":"Na ahimidiwe Bwana. Maana ameisikia sauti ya dua yangu;"},{"v":7,"t":"Bwana ni nguvu zangu na ngao yangu. Moyo wangu umemtumaini, Nami nimesaidiwa; Basi, moyo wangu unashangilia, Na kwa wimbo wangu nitamshukuru."},{"v":8,"t":"Bwana ni nguvu za watu wake, Naye ni ngome ya wokovu kwa masihi wake."},{"v":9,"t":"Uwaokoe watu wako, uubariki urithi wako, Uwachunge, uwachukue milele."}]},{"c":29,"verses":[{"v":1,"t":"Mpeni Bwana, enyi wana wa Mungu, Mpeni Bwana utukufu na nguvu;"},{"v":2,"t":"Mpeni Bwana utukufu wa jina lake; Mwabuduni Bwana kwa uzuri wa utakatifu."},{"v":3,"t":"Sauti ya Bwana i juu ya maji; Mungu wa utukufu alipiga radi; Bwana yu juu ya maji mengi."},{"v":4,"t":"Sauti ya Bwana ina nguvu; Sauti ya Bwana ina adhama;"},{"v":5,"t":"Sauti ya Bwana yaivunja mierezi; Naam, Bwana aivunja-vunja mierezi ya Lebanoni;"},{"v":6,"t":"Airusha-rusha kama ndama wa ng'ombe; Lebanoni na Sirioni kama mwana-nyati."},{"v":7,"t":"Sauti ya Bwana yaipasua miali ya moto;"},{"v":8,"t":"Sauti ya Bwana yalitetemesha jangwa; Bwana alitetemesha jangwa la Kadeshi."},{"v":9,"t":"Sauti ya Bwana yawazalisha ayala, Na kuifichua misitu; Na ndani ya hekalu lake Wanasema wote, Utukufu."},{"v":10,"t":"Bwana aliketi juu ya Gharika; Naam, Bwana ameketi hali ya mfalme milele."},{"v":11,"t":"Bwana atawapa watu wake nguvu; Bwana atawabariki watu wake kwa amani."}]},{"c":30,"verses":[{"v":1,"t":"Ee Bwana, nitakutukuza kwa maana umeniinua, Wala hukuwafurahisha adui zangu juu yangu."},{"v":2,"t":"Ee Bwana, Mungu wangu, Nalikulilia ukaniponya."},{"v":3,"t":"Umeniinua nafsi yangu, Ee Bwana, kutoka kuzimu. Umenihuisha na kunitoa Miongoni mwao washukao shimoni."},{"v":4,"t":"Mwimbieni Bwana zaburi, Enyi watauwa wake. Na kufanya shukrani. Kwa kumbukumbu la utakatifu wake."},{"v":5,"t":"Maana ghadhabu zake ni za kitambo kidogo, Katika radhi yake mna uhai. Huenda kilio huja kukaa usiku, Lakini asubuhi huwa furaha."},{"v":6,"t":"Nami nilipofanikiwa nalisema, Sitaondoshwa milele."},{"v":7,"t":"Bwana, kwa radhi yako Wewe uliuimarisha mlima wangu. Uliuficha uso wako, Nami nikafadhaika."},{"v":8,"t":"Ee Bwana, nalikulilia Wewe, Naam, kwa Bwana naliomba dua."},{"v":9,"t":"Mna faida gani katika damu yangu Nishukapo shimoni? Mavumbi yatakusifu? Yataitangaza kweli yako?"},{"v":10,"t":"Ee Bwana, usikie, unirehemu, Bwana, uwe msaidizi wangu."},{"v":11,"t":"Uligeuza matanga yangu kuwa machezo; Ulinivua gunia, ukanivika furaha."},{"v":12,"t":"Ili utukufu wangu ukusifu, Wala usinyamaze. Ee Bwana, Mungu wangu, Nitakushukuru milele."}]},{"c":31,"verses":[{"v":1,"t":"Nimekukimbilia Wewe, Bwana, Nisiaibike milele. Kwa haki yako uniponye,"},{"v":2,"t":"Unitegee sikio lako, uniokoe hima. Uwe kwangu mwamba wa nguvu, Nyumba yenye maboma ya kuniokoa."},{"v":3,"t":"Ndiwe genge langu na ngome yangu; Kwa ajili ya jina lako uniongoze, unichunge."},{"v":4,"t":"Utanitoa katika wavu walionitegea kwa siri, Maana Wewe ndiwe ngome yangu."},{"v":5,"t":"Mikononi mwako naiweka roho yangu; Umenikomboa, Ee Bwana, Mungu wa kweli."},{"v":6,"t":"Nawachukia wao washikao yasiyofaa yenye uongo; Bali mimi namtumaini Bwana."},{"v":7,"t":"Na nishangilie, nizifurahie fadhili zako, Kwa kuwa umeyaona mateso yangu. Umeijua nafsi yangu taabuni,"},{"v":8,"t":"Wala hukunitia mikononi mwa adui; Miguu yangu umeisimamisha panapo nafasi."},{"v":9,"t":"Ee Bwana, unifadhili, maana ni katika dhiki, Jicho langu limenyauka kwa masumbufu, Naam, mwili wangu na nafsi yangu."},{"v":10,"t":"Maana maisha yangu yamekoma kwa huzuni, Na miaka yangu kwa kuugua. Nguvu zangu zinatetemeka kwa uovu wangu, Na mifupa yangu imekauka."},{"v":11,"t":"Kwa sababu ya watesi wangu nimekuwa laumu, Naam, hasa kwa jirani zangu; Na kitu cha kutisha kwa rafiki zangu; Walioniona njiani walinikimbia."},{"v":12,"t":"Nimesahauliwa kama mfu asiyekumbukwa; Nimekuwa kama chombo kilichovunjika."},{"v":13,"t":"Maana nimesikia masingizio ya wengi; Hofu ziko pande zote. Waliposhauriana juu yangu, Walifanya hila wauondoe uhai wangu."},{"v":14,"t":"Lakini mimi nakutumaini Wewe, Bwana, Nimesema, Wewe ndiwe Mungu wangu."},{"v":15,"t":"Nyakati zangu zimo mikononi mwako; Uniponye na adui zangu, nao wanaonifuatia."},{"v":16,"t":"Umwangaze mtumishi wako Kwa nuru ya uso wako; Uniokoe kwa ajili ya fadhili zako."},{"v":17,"t":"Ee Bwana, nisiaibishwe, maana nimekuita; Waaibishwe wasio haki, wanyamaze kuzimuni."},{"v":18,"t":"Midomo ya uongo iwe na ububu, Imneneayo mwenye haki maneno ya kiburi, Kwa majivuno na dharau."},{"v":19,"t":"Jinsi zilivyo nyingi fadhili zako Ulizowawekea wakuchao; Ulizowatendea wakukimbiliao Mbele ya wanadamu!"},{"v":20,"t":"Utawasitiri na fitina za watu Katika sitara ya kuwapo kwako; Utawaficha katika hema Na mashindano ya ndimi."},{"v":21,"t":"Bwana ahimidiwe; kwa maana amenitendea Fadhili za ajabu katika mji wenye boma."},{"v":22,"t":"Nami nalisema kwa haraka yangu, Nimekatiliwa mbali na macho yako; Lakini ulisikia sauti ya dua yangu Wakati nilipokulilia."},{"v":23,"t":"Mpendeni Bwana, Ninyi nyote mlio watauwa wake. Bwana huwahifadhi waaminifu, Humlipa atendaye kiburi malipo tele."},{"v":24,"t":"Iweni hodari, mpige moyo konde, Ninyi nyote mnaomngoja Bwana."}]},{"c":32,"verses":[{"v":1,"t":"Heri aliyesamehewa dhambi, Na kusitiriwa makosa yake."},{"v":2,"t":"Heri Bwana asiyemhesabia upotovu, Ambaye rohoni mwake hamna hila."},{"v":3,"t":"Niliponyamaza mifupa yangu ilichakaa Kwa kuugua kwangu mchana kutwa."},{"v":4,"t":"Kwa maana mchana na usiku Mkono wako ulinilemea. Jasho langu likakauka hata nikawa Kama nchi kavu wakati wa kaskazi."},{"v":5,"t":"Nalikujulisha dhambi yangu, Wala sikuuficha upotovu wangu. Nalisema, Nitayakiri maasi yangu kwa Bwana, Nawe ukanisamehe upotovu wa dhambi yangu."},{"v":6,"t":"Kwa hiyo kila mtu mtauwa Akuombe wakati unapopatikana. Hakika maji makuu yafurikapo, Hayatamfikia yeye."},{"v":7,"t":"Ndiwe sitara yangu, utanihifadhi na mateso, Utanizungusha nyimbo za wokovu."},{"v":8,"t":"Nitakufundisha na kukuonyesha njia utakayoiendea; Nitakushauri, jicho langu likikutazama."},{"v":9,"t":"Msiwe kama farasi wala nyumbu, Walio hawana akili. Kwa matandiko ya lijamu na hatamu Sharti kuwazuia hao, au hawatakukaribia."},{"v":10,"t":"Naye mtu mwovu ana mapigo mengi, Bali amtumainiye Bwana fadhili zitamzunguka."},{"v":11,"t":"Mfurahieni Bwana; Shangilieni, enyi wenye haki Pigeni vigelegele vya furaha; Ninyi nyote mlio wanyofu wa moyo."}]},{"c":33,"verses":[{"v":1,"t":"Mpigieni Bwana vigelegele, enyi wenye haki, Kusifu kunawapasa wanyofu wa moyo."},{"v":2,"t":"Mshukuruni Bwana kwa kinubi, Kwa kinanda cha nyuzi kumi mwimbieni sifa."},{"v":3,"t":"Mwimbieni wimbo mpya, Pigeni kwa ustadi kwa sauti ya shangwe."},{"v":4,"t":"Kwa kuwa neno la Bwana lina adili, Na kazi yake yote huitenda kwa uaminifu."},{"v":5,"t":"Huzipenda haki na hukumu, Nchi imejaa fadhili za Bwana."},{"v":6,"t":"Kwa neno la Bwana mbingu zilifanyika, Na jeshi lake lote kwa pumzi ya kinywa chake."},{"v":7,"t":"Hukusanya maji ya bahari chungu chungu, Huviweka vilindi katika ghala."},{"v":8,"t":"Nchi yote na imwogope Bwana, Wote wakaao duniani na wamche."},{"v":9,"t":"Maana Yeye alisema, ikawa; Na Yeye aliamuru, ikasimama."},{"v":10,"t":"Bwana huyabatilisha mashauri ya mataifa, Huyatangua makusudi ya watu."},{"v":11,"t":"Shauri la Bwana lasimama milele, Makusudi ya moyo wake vizazi na vizazi."},{"v":12,"t":"Heri taifa ambalo Bwana ni Mungu wao, Watu aliowachagua kuwa urithi wake."},{"v":13,"t":"Toka mbinguni Bwana huchungulia, Huwatazama wanadamu wote pia."},{"v":14,"t":"Toka mahali pake aketipo Huwaangalia wote wakaao duniani."},{"v":15,"t":"yeye aiumbaye mioyo yao wote Huzifikiri kazi zao zote."},{"v":16,"t":"Hapana mfalme aokokaye kwa wingi wa uwezo, Wala shujaa haokoki kwa wingi wa nguvu."},{"v":17,"t":"Farasi hafai kitu kwa wokovu, Wala hamponyi mtu kwa wingi wa nguvu zake."},{"v":18,"t":"Tazama, jicho la Bwana li kwao wamchao, Wazingojeao fadhili zake."},{"v":19,"t":"Yeye huwaponya nafsi zao na mauti, Na kuwahuisha wakati wa njaa."},{"v":20,"t":"Nafsi zetu zinamngoja Bwana; Yeye ndiye msaada wetu na ngao yetu."},{"v":21,"t":"Maana mioyo yetu itamfurahia, Kwa kuwa tumelitumainia jina lake takatifu."},{"v":22,"t":"Ee Bwana, fadhili zako zikae nasi, Kama vile tulivyokungoja Wewe."}]},{"c":34,"verses":[{"v":1,"t":"Nitamhimidi Bwana kila wakati, Sifa zake zi kinywani mwangu daima."},{"v":2,"t":"Katika Bwana nafsi yangu itajisifu, Wanyenyekevu wasikie wakafurahi."},{"v":3,"t":"Mtukuzeni Bwana pamoja nami, Na tuliadhimishe jina lake pamoja."},{"v":4,"t":"Nalimtafuta Bwana akanijibu, Akaniponya na hofu zangu zote."},{"v":5,"t":"Wakamwelekea macho wakatiwa nuru, Wala nyuso zao hazitaona haya."},{"v":6,"t":"Maskini huyu aliita, Bwana akasikia, Akamwokoa na taabu zake zote."},{"v":7,"t":"Malaika wa Bwana hufanya kituo, Akiwazungukia wamchao na kuwaokoa."},{"v":8,"t":"Onjeni mwone ya kuwa Bwana yu mwema; Heri mtu yule anayemtumaini."},{"v":9,"t":"Mcheni Bwana, enyi watakatifu wake, Yaani, wamchao hawahitaji kitu."},{"v":10,"t":"Wana-simba hutindikiwa, huona njaa; Bali wamtafutao Bwana hawatahitaji kitu cho chote kilicho chema."},{"v":11,"t":"Njoni, enyi wana, mnisikilize, Nami nitawafundisha kumcha Bwana."},{"v":12,"t":"Ni nani mtu yule apendezwaye na uzima, Apendaye siku nyingi apate kuona mema?"},{"v":13,"t":"Uuzuie ulimi wako na mabaya, Na midomo yako na kusema hila."},{"v":14,"t":"Uache mabaya ukatende mema, Utafute amani ukaifuatie."},{"v":15,"t":"Macho ya Bwana huwaelekea wenye haki, Na masikio yake hukielekea kilio chao."},{"v":16,"t":"Uso wa Bwana ni juu ya watenda mabaya, Aliondoe kumbukumbu lao duniani."},{"v":17,"t":"Walilia, naye Bwana akasikia, Akawaponya na taabu zao zote."},{"v":18,"t":"Bwana yu karibu nao waliovunjika moyo, Na waliopondeka roho huwaokoa."},{"v":19,"t":"Mateso ya mwenye haki ni mengi, Lakini Bwana humponya nayo yote."},{"v":20,"t":"Huihifadhi mifupa yake yote, Haukuvunjika hata mmoja."},{"v":21,"t":"Uovu utamwua asiye haki, Nao wamchukiao mwenye haki watahukumiwa."},{"v":22,"t":"Bwana huzikomboa nafsi za watumishi wake, Wala hawatahukumiwa wote wamkimbiliao."}]},{"c":35,"verses":[{"v":1,"t":"Ee Bwana, utete nao wanaoteta nami, Upigane nao wanaopigana nami."},{"v":2,"t":"Uishike ngao na kigao, Usimame unisaidie."},{"v":3,"t":"Uutoe na mkuki uwapinge wanaonifuatia, Uiambie nafsi yangu, Mimi ni wokovu wako."},{"v":4,"t":"Waaibishwe, wafedheheshwe, Wanaoitafuta nafsi yangu. Warudishwe nyuma, wafadhaishwe, Wanaonizulia mabaya."},{"v":5,"t":"Wawe kama makapi mbele ya upepo, Malaika wa Bwana akiwaangusha chini."},{"v":6,"t":"Njia yao na iwe giza na utelezi, Malaika wa Bwana akiwafuatia."},{"v":7,"t":"Maana bila sababu wamenifichia wavu, Bila sababu wameichimbia shimo nafsi yangu."},{"v":8,"t":"Uharibifu na umpate kwa ghafula, Na wavu aliouficha umnase yeye mwenyewe; Kwa uharibifu aanguke ndani yake."},{"v":9,"t":"Na nafsi yangu itamfurahia Bwana, Na kuushangilia wokovu wake."},{"v":10,"t":"Mifupa yangu yote itasema, Bwana, ni nani aliye kama Wewe? Umponyaye maskini na mtu aliye hodari kumshinda yeye, Naam, maskini na mhitaji na mtu amtekaye."},{"v":11,"t":"Mashahidi wa udhalimu wanasimama, Wananiuliza mambo nisiyoyajua."},{"v":12,"t":"Wananilipa mabaya badala ya mema, Hata nafsi yangu ikaingia ukiwa."},{"v":13,"t":"Bali mimi, walipougua wao, Nguo yangu ilikuwa gunia. Nalijitesa nafsi yangu kwa kufunga; Maombi yangu yakarejea kifuani mwangu."},{"v":14,"t":"Nalijifanya kama kwamba ni rafiki au ndugu yangu, Naliinama nikilia kama aliyefiwa na mamaye."},{"v":15,"t":"Lakini nikijikwaa hufurahi na kukusanyana, Walinikusanyikia watu ovyo nisiowajua, Wananipapura wala hawakomi."},{"v":16,"t":"Kama wenye mzaha wakikufuru karamuni Wananisagia meno."},{"v":17,"t":"Bwana, hata lini utatazama? Uiokoe nafsi yangu na maharabu yao, Na mpenzi wangu na wana-simba."},{"v":18,"t":"Nitakushukuru katika kusanyiko kubwa; Nitakusifu kati ya watu wengi."},{"v":19,"t":"Walio adui zangu bure wasinisimange, Wanaonichukia bila sababu wasining'ong'e."},{"v":20,"t":"Maana hawasemi maneno ya amani, Na juu ya watulivu wa nchi huwaza hila."},{"v":21,"t":"Nao wananifumbulia vinywa vyao, Husema, Ewe! Ewe! Jicho letu limeona."},{"v":22,"t":"Wewe, Bwana, umeona, usinyamaze; Ee Bwana, usiwe mbali nami."},{"v":23,"t":"Uamke, uwe macho ili kunipatia hukumu Kwa ajili ya madai yangu, Mungu wangu na Bwana wangu."},{"v":24,"t":"Unihukumu kwa haki yako, Ee Bwana, Mungu wangu, Wala wasinisimangize."},{"v":25,"t":"Wasiseme moyoni, Haya! Ndivyo tutakavyo; Wasiseme, Tumemmeza."},{"v":26,"t":"Waaibishwe, wafedheheshwe pamoja, Wanaoifurahia hali yangu mbaya. Wavikwe aibu na fedheha, Wanaojikuza juu yangu."},{"v":27,"t":"Washangilie na kufurahi, Wapendezwao na haki yangu. Naam, waseme daima, Atukuzwe Bwana, Apendezwaye na amani ya mtumishi wake."},{"v":28,"t":"Na ulimi wangu utanena haki yako, Na sifa zako mchana kutwa."}]},{"c":36,"verses":[{"v":1,"t":"Kuasi kwake yule mwovu hunena moyoni mwake, Hakuna hofu ya Mungu mbele ya macho yake."},{"v":2,"t":"Kwa maana hujipendekeza machoni pake Kuwa upotovu wake hautaonekana na kuchukiwa."},{"v":3,"t":"Maneno ya kinywa chake ni uovu na hila, Ameacha kuwa na akili na kutenda mema."},{"v":4,"t":"Huwaza maovu kitandani pake, Hujiweka katika njia mbaya; ubaya hauchukii."},{"v":5,"t":"Ee Bwana, fadhili zako zafika hata mbinguni, Uaminifu wako hata mawinguni."},{"v":6,"t":"Haki yako ni kama milima ya Mungu, Hukumu zako ni vilindi vikuu, Ee Bwana, unawaokoa wanadamu na wanyama."},{"v":7,"t":"Ee Mungu, jinsi zilivyo na thamani fadhili zako! Wanadamu huukimbilia uvuli wa mbawa zako."},{"v":8,"t":"Watashibishwa kwa unono wa nyumba yako, Nawe utawanywesha mto wa furaha zako."},{"v":9,"t":"Maana kwako Wewe iko chemchemi ya uzima, Katika nuru yako tutaona nuru."},{"v":10,"t":"Uwadumishie wakujuao fadhili zako, Na wanyofu wa moyo uaminifu wako."},{"v":11,"t":"Mguu wa kiburi usinikaribie, Wala mkono wa wasio haki usinifukuze."},{"v":12,"t":"Huko ndiko walikoanguka wafanyao maovu; Wameangushwa chini wasiweze kusimama."}]},{"c":37,"verses":[{"v":1,"t":"Usikasirike kwa sababu ya watenda mabaya, Usiwahusudu wafanyao ubatili."},{"v":2,"t":"Maana kama majani watakatika mara, Kama miche mibichi watanyauka."},{"v":3,"t":"Umtumaini Bwana ukatende mema, Ukae katika nchi, upendezwe na uaminifu."},{"v":4,"t":"Nawe utajifurahisha kwa Bwana, Naye atakupa haja za moyo wako."},{"v":5,"t":"Umkabidhi Bwana njia yako, Pia umtumaini, naye atafanya."},{"v":6,"t":"Ataitokeza haki yako kama nuru, Na hukumu yako kama adhuhuri."},{"v":7,"t":"Ukae kimya mbele za Bwana, Nawe umngojee kwa saburi; Usimkasirikie yeye afanikiwaye katika njia yake, Wala mtu afanyaye hila."},{"v":8,"t":"Ukomeshe hasira, uache ghadhabu, Usikasirike, mwisho wake ni kutenda mabaya."},{"v":9,"t":"Maana watenda mabaya wataharibiwa, Bali wamngojao Bwana ndio watakaoirithi nchi."},{"v":10,"t":"Maana bado kitambo kidogo asiye haki hatakuwapo, Utapaangalia mahali pake wala hatakuwapo."},{"v":11,"t":"Bali wenye upole watairithi nchi, Watajifurahisha kwa wingi wa amani."},{"v":12,"t":"Asiye haki hunuia mabaya juu ya mwenye haki, Na kumsagia meno yake."},{"v":13,"t":"Bwana atamcheka, Maana ameona kwamba siku yake inakuja."},{"v":14,"t":"Wasio haki wamefuta upanga na kupinda uta, Wamwangushe chini maskini na mhitaji, Na kuwaua wenye mwenendo wa unyofu."},{"v":15,"t":"Upanga wao utaingia mioyoni mwao wenyewe, Na nyuta zao zitavunjika."},{"v":16,"t":"Kidogo alicho nacho mwenye haki ni bora Kuliko wingi wa mali wa wasio haki wengi."},{"v":17,"t":"Maana mikono ya wasio haki itavunjika, Bali Bwana huwategemeza wenye haki."},{"v":18,"t":"Bwana anazijua siku za wakamilifu, Na urithi wao utakuwa wa milele."},{"v":19,"t":"Hawataaibika wakati wa ubaya, Na siku za njaa watashiba."},{"v":20,"t":"Bali wasio haki watapotea, Nao wamchukiao Bwana watatoweka, Kama uzuri wa mashamba, Kama moshi watatoweka."},{"v":21,"t":"Asiye haki hukopa wala halipi, Bali mwenye haki hufadhili, hukirimu."},{"v":22,"t":"Maana waliobarikiwa na yeye watairithi nchi, Nao waliolaaniwa na yeye wataharibiwa."},{"v":23,"t":"Hatua za mtu zaimarishwa na Bwana, Naye aipenda njia yake."},{"v":24,"t":"Ajapojikwaa hataanguka chini, Bwana humshika mkono na kumtegemeza."},{"v":25,"t":"Nalikuwa kijana nami sasa ni mzee, Lakini sijamwona mwenye haki ameachwa Wala mzao wake akiomba chakula."},{"v":26,"t":"Mchana kutwa hufadhili na kukopesha, Na mzao wake hubarikiwa."},{"v":27,"t":"Jiepue na uovu, utende mema, Na kukaa hata milele."},{"v":28,"t":"Kwa kuwa Bwana hupenda haki, Wala hawaachi watauwa wake. Wao hulindwa milele, Bali mzao wa wasio haki ataharibiwa."},{"v":29,"t":"Wenye haki watairithi nchi, Nao watakaa humo milele."},{"v":30,"t":"Kinywa chake mwenye haki hunena hekima, Na ulimi wake husema hukumu."},{"v":31,"t":"Sheria ya Mungu wake imo moyoni mwake. Hatua zake hazitelezi."},{"v":32,"t":"Mtu asiye haki humvizia mwenye haki, Na kutafuta jinsi ya kumfisha."},{"v":33,"t":"Bwana hatamwacha mkononi mwake, Wala hatamlaumu atakapohukumiwa."},{"v":34,"t":"Wewe umngoje Bwana, Uishike njia yake, Naye atakutukuza uirithi nchi, Wasio haki watakapoharibiwa utawaona."},{"v":35,"t":"Nimemwona mtu asiye haki mkali sana, Akijieneza kama mwerezi wa Lebanoni."},{"v":36,"t":"Nikapita na kumbe! Hayuko, Nikamtafuta wala hakuonekana."},{"v":37,"t":"Umwangalie sana mtu mkamilifu, Umtazame mtu mnyofu, Maana mwisho wake mtu huyo ni amani."},{"v":38,"t":"Wakosaji wataangamizwa pamoja, Wasio haki mwisho wao wataharibiwa."},{"v":39,"t":"Na wokovu wa wenye haki una Bwana; Yeye ni ngome yao wakati wa taabu."},{"v":40,"t":"Naye Bwana huwasaidia na kuwaopoa; Huwaopoa na wasio haki na kuwaokoa; Kwa kuwa wamemtumaini Yeye."}]},{"c":38,"verses":[{"v":1,"t":"Ee Bwana, usinilaumu katika ghadhabu yako, Wala usiniadhibu kwa ukali wa hasira yako."},{"v":2,"t":"Kwa maana mishale yako imenichoma, Na mkono wako umenipata."},{"v":3,"t":"Hamna uzima katika mwili wangu Kwa sababu ya ghadhabu yako. Wala hamna amani mifupani mwangu Kwa sababu ya hatia zangu."},{"v":4,"t":"Maana dhambi zangu zimenifunikiza kichwa, Kama mzigo mzito zimenilemea mno."},{"v":5,"t":"Jeraha zangu zinanuka, zimeoza, Kwa sababu ya upumbavu wangu."},{"v":6,"t":"Nimepindika na kuinama sana, Mchana kutwa nimekwenda nikihuzunika."},{"v":7,"t":"Maana viuno vyangu vimejaa homa, Wala hamna uzima katika mwili wangu."},{"v":8,"t":"Nimedhoofika na kuchubuka sana, Nimeugua kwa fadhaa ya moyo wangu."},{"v":9,"t":"Bwana, haja zangu zote ziko mbele zako, Kuugua kwangu hakukusitirika kwako."},{"v":10,"t":"Moyo wangu unapwita-pwita, Nguvu zangu zimeniacha; Nuru ya macho yangu nayo imeniondoka."},{"v":11,"t":"Wanipendao na rafiki zangu wanasimama mbali na pigo langu; Naam, karibu zangu wamesimama mbali."},{"v":12,"t":"Nao wanaoutafuta uhai wangu hutega mitego; Nao wanaotaka kunidhuru hunena mabaya; Na kufikiri hila mchana kutwa."},{"v":13,"t":"Lakini kama kiziwi sisikii, Nami ni kama bubu asiyefumbua kinywa chake."},{"v":14,"t":"Naam, nimekuwa kama mtu asiyesikia, Ambaye hamna hoja kinywani mwake."},{"v":15,"t":"Kwa kuwa nakungoja Wewe, Bwana, Wewe utajibu, Ee Bwana, Mungu wangu."},{"v":16,"t":"Maana nalisema, Wasije wakanifurahia; Mguu wangu ukiteleza wajitukuza juu yangu."},{"v":17,"t":"Kwa maana mimi ni karibu na kusita, Na maumivu yangu yako mbele yangu daima."},{"v":18,"t":"Kwa maana nitaungama uovu wangu, Na kusikitika kwa dhambi zangu."},{"v":19,"t":"Lakini adui zangu ni wazima wenye nguvu, Nao wanaonichukia bure wamekuwa wengi."},{"v":20,"t":"Naam, wakilipa mabaya kwa mema, Huwa adui zangu kwa kuwa nalifuata lililo jema."},{"v":21,"t":"Wewe, Bwana, usiniache, Mungu wangu, usijitenge nami."},{"v":22,"t":"Ufanye haraka kunisaidia, Ee Bwana, wokovu wangu."}]},{"c":39,"verses":[{"v":1,"t":"Nalisema, Nitazitunza njia zangu Nisije nikakosa kwa ulimi wangu; Nitajitia lijamu kinywani, Maadamu mtu mbaya yupo mbele yangu."},{"v":2,"t":"Nalikuwa sisemi, nalinyamaa kimya, Sina faraja, maumivu yangu yakazidi."},{"v":3,"t":"Moyo wangu ukawa moto ndani yangu, Na katika kuwaza kwangu moto ukawaka; Nalisema kwa ulimi wangu,"},{"v":4,"t":"Bwana, unijulishe mwisho wangu, Na kiasi cha siku zangu ni kiasi gani; Nijue jinsi nilivyo dhaifu."},{"v":5,"t":"Tazama, umefanya siku zangu kuwa mashubiri; Maisha yangu ni kama si kitu mbele zako. Kila mwanadamu, ingawa amesitawi, ni ubatili."},{"v":6,"t":"Binadamu huenda tu huko na huko kama kivuli; Hufanya ghasia tu kwa ajili ya ubatili; Huweka akiba wala hajui ni nani atakayeichukua."},{"v":7,"t":"Na sasa ninangoja nini, Ee Bwana? Matumaini yangu ni kwako."},{"v":8,"t":"Uniokoe na maasi yangu yote, Usinifanye laumu ya mpumbavu."},{"v":9,"t":"Nimenyamaza, sitafumbua kinywa changu, Maana Wewe ndiwe uliyeyafanya."},{"v":10,"t":"Uniondolee pigo lako; Kwa uadui wa mkono wako nimeangamia."},{"v":11,"t":"Ukimrudi mtu kwa kumkemea kwa uovu wake, Watowesha uzuri wake kama nondo. Kila mwanadamu ni ubatili."},{"v":12,"t":"Ee Bwana, usikie maombi yangu, Utege sikio lako niliapo, Usiyanyamalie machozi yangu. Kwa maana mimi ni mgeni wako, Msafiri kama baba zangu wote."},{"v":13,"t":"Uniachilie nikunjuke uso, Kabla sijaondoka nisiwepo tena."}]},{"c":40,"verses":[{"v":1,"t":"Nalimngoja Bwana kwa saburi, Akaniinamia akakisikia kilio changu."},{"v":2,"t":"Akanipandisha toka shimo la uharibifu, Toka udongo wa utelezi; Akaisimamisha miguu yangu mwambani, Akaziimarisha hatua zangu."},{"v":3,"t":"Akatia wimbo mpya kinywani mwangu, Ndio sifa zake Mungu wetu. Wengi wataona na kuogopa, Nao watamtumaini Bwana"},{"v":4,"t":"Heri aliyemfanya Bwana kuwa tumaini lake, Wala hakuwaelekea wenye kiburi, Wala hao wanaogeukia uongo."},{"v":5,"t":"Ee Bwana, Mungu wangu, umefanya kwa wingi Miujiza yako na mawazo yako kwetu; Hakuna awezaye kufananishwa nawe; Kama ningependa kuyatangaza na kuyahubiri, Ni mengi sana hayahesabiki."},{"v":6,"t":"Dhabihu na matoleo hukupendezwa nazo, Masikio yangu umeyazibua, Kafara na sadaka za dhambi hukuzitaka."},{"v":7,"t":"Ndipo niliposema, Tazama nimekuja, (Katika gombo la chuo nimeandikiwa,)"},{"v":8,"t":"Kuyafanya mapenzi yako, Ee Mungu wangu, ndiyo furaha yangu; Naam, sheria yako imo moyoni mwangu."},{"v":9,"t":"Nimehubiri habari za haki katika kusanyiko kubwa. Sikuizuia midomo yangu; Ee Bwana, unajua."},{"v":10,"t":"Sikusitiri haki yako moyoni mwangu; Nimetangaza uaminifu wako na wokovu wako. Sikuficha fadhili zako wala kweli yako Katika kusanyiko kubwa."},{"v":11,"t":"Nawe, Bwana, usinizuilie rehema zako, Fadhili zako na kweli yako na zinihifadhi daima."},{"v":12,"t":"Kwa maana mabaya yasiyohesabika Yamenizunguka mimi. Maovu yangu yamenipata, Wala siwezi kuona. Yamezidi kuliko nywele za kichwa changu, Na moyo wangu umeniacha."},{"v":13,"t":"Ee Bwana, uwe radhi kuniokoa, Ee Bwana, unisaidie hima."},{"v":14,"t":"Waaibike, wafedheheke pamoja, Wanaoitafuta nafsi yangu waiangamize. Warudishwe nyuma, watahayarishwe, Wapendezwao na shari yangu."},{"v":15,"t":"Wakae hali ya ukiwa, na iwe aibu yao, Wanaoniambia, Ewe! Ewe!"},{"v":16,"t":"Washangilie, wakufurahie, Wote wakutafutao. Waupendao wokovu wako Waseme daima, Atukuzwe Bwana."},{"v":17,"t":"Nami ni maskini na mhitaji, Bwana atanitunza. Ndiwe msaada wangu na mwokozi wangu, Ee Mungu wangu, usikawie."}]},{"c":41,"verses":[{"v":1,"t":"Heri amkumbukaye mnyonge; Bwana atamwokoa siku ya taabu."},{"v":2,"t":"Bwana atamlinda na kumhifadhi hai, Naye atafanikiwa katika nchi; Wala usimtie katika hali wamtakiayo adui zake."},{"v":3,"t":"Bwana atamtegemeza alipo mgonjwa kitandani. Katika ugonjwa wake umemtandikia."},{"v":4,"t":"Nami nalisema, Bwana, unifadhili, Uniponye roho yangu maana nimekutenda dhambi."},{"v":5,"t":"Adui zangu wananitaja kwa maneno mabaya, Atakufa lini, jina lake likapotea?"},{"v":6,"t":"Na mmoja wao akija kunitazama asema uongo, Moyo wake hujikusanyia maovu, Naye atokapo nje huyanena."},{"v":7,"t":"Wote wanaonichukia wananinong'ona, Wananiwazia mabaya."},{"v":8,"t":"Neno la kisirani limemgandama, Na iwapo amelala hatasimama tena."},{"v":9,"t":"Msiri wangu tena niliyemtumaini, Aliyekula chakula changu, Ameniinulia kisigino chake."},{"v":10,"t":"Lakini Wewe, Bwana, unifadhili, Uniinue nipate kuwalipa."},{"v":11,"t":"Kwa neno hili nimejua ya kuwa wapendezwa nami, Kwa kuwa adui yangu hasimangi kwa kunishinda."},{"v":12,"t":"Nami katika ukamilifu wangu umenitegemeza, Umeniweka mbele za uso wako milele."},{"v":13,"t":"Na atukuzwe Bwana, Mungu wa Israeli, Tangu milele hata milele. Amina na Amina."}]},{"c":42,"verses":[{"v":1,"t":"Kama ayala aioneavyo shauku mito ya maji. Vivyo hivyo nafsi yangu inakuonea shauku, Ee Mungu."},{"v":2,"t":"Nafsi yangu inamwonea kiu MUNGU, Mungu aliye hai, Lini nitakapokuja nionekane mbele za Mungu?"},{"v":3,"t":"Machozi yangu yamekuwa chakula changu mchana na usiku, Pindi wanaponiambia mchana kutwa, Yuko wapi Mungu wako."},{"v":4,"t":"Nayakumbuka hayo nikiweka wazi nafsi yangu ndani yangu, Jinsi nilivyokuwa nikienda na mkutano, Na kuwaongoza nyumbani kwa Mungu, Kwa sauti ya furaha na kusifu, mkutano wa sikukuu."},{"v":5,"t":"Nafsi yangu, kwa nini kuinama, Na kufadhaika ndani yangu? Umtumaini Mungu; Kwa maana nitakuja kumsifu, Aliye afya ya uso wangu, Na Mungu wangu."},{"v":6,"t":"Nafsi yangu imeinama ndani yangu, kwa hiyo nitakukumbuka, Toka nchi ya Yordani, na Mahermoni, na toka kilima cha Mizari."},{"v":7,"t":"Kilindi chapigia kelele kilindi kwa sauti ya maboromoko ya maji yako, Gharika zako zote na mawimbi yako yote yamepita juu yangu."},{"v":8,"t":"Mchana Bwana ataagiza fadhili zake, na usiku wimbo wake utakuwa nami, Naam, maombi kwa Mungu aliye uhai wangu."},{"v":9,"t":"Nitamwambia Mungu, mwamba wangu, Kwa nini umenisahau? Kwa nini ninakwenda nikihuzunika, adui wakinionea?"},{"v":10,"t":"Watesi wangu hunitukana mithili ya kuniponda mifupa yangu, Pindi wanaponiambia mchana kutwa, Yuko wapi Mungu wako?"},{"v":11,"t":"Nafsi yangu, kwa nini kuinama, Na kufadhaika ndani yangu? Umtumaini Mungu; Kwa maana nitakuja kumsifu, Aliye afya ya uso wangu, Na Mungu wangu."}]},{"c":43,"verses":[{"v":1,"t":"Ee Bwana, unihukumu, unitetee kwa taifa lisilo haki, Uniokoe na mtu wa hila asiye haki."},{"v":2,"t":"Kwa kuwa Wewe ndiwe Mungu uliye nguvu zangu; kwa nini umenitupa? Kwa nini ninakwenda nikihuzunika, adui wakinionea?"},{"v":3,"t":"Niletewe nuru yako na kweli yako ziniongoze, Zinifikishe kwenye mlima wako mtakatifu na hata maskani yako."},{"v":4,"t":"Hivyo nitakwenda madhabahuni kwa Mungu, kwa Mungu aliye furaha yangu na shangwe yangu; Nitakusifu kwa kinubi, Ee MUNGU, Mungu wangu."},{"v":5,"t":"Nafsi yangu, kwa nini kuinama, Na kufadhaika ndani yangu? Umtumaini Mungu; Kwa maana nitakuja kumsifu, Aliye afya ya uso wangu, Na Mungu wangu."}]},{"c":44,"verses":[{"v":1,"t":"Ee Mungu, tumesikia kwa masikio yetu Baba zetu wametuambia, Matendo uliyoyatenda siku zao, siku za kale."},{"v":2,"t":"Wewe kwa mkono wako uliwafukuza mataifa, Ukawakalisha wao. Wewe uliwatesa watu wa nchi, Ukawaeneza wao."},{"v":3,"t":"Maana si kwa upanga wao walivyoimiliki nchi, Wala si mkono wao uliowaokoa; Bali mkono wako wa kuume, naam, mkono wako, Na nuru ya uso wako, kwa kuwa uliwaridhia."},{"v":4,"t":"Ee Mungu, Wewe ndiwe mfalme wangu, Uagize mambo ya wokovu kwa Yakobo."},{"v":5,"t":"Kwa nguvu zako tutawaangusha watesi wetu; Kwa jina lako tutawakanyaga watupingao."},{"v":6,"t":"Maana sitautumainia upinde wangu, Wala upanga wangu hautaniokoa."},{"v":7,"t":"Bali Wewe ndiwe uliyetuokoa na watesi wetu; Na watuchukiao umewaaibisha."},{"v":8,"t":"Tumejisifia Mungu mchana kutwa, Na jina lako tutalishukuru milele."},{"v":9,"t":"Lakini umetutupa, umetufedhehesha, Wala hutoki na majeshi yetu."},{"v":10,"t":"Waturudisha nyuma tukampa mtesi kisogo, Na watuchukiao wanajipatia mateka."},{"v":11,"t":"Umetutoa kama kondoo tuwe chakula, Na kututawanya kati ya mataifa."},{"v":12,"t":"Wawauza watu wako bila kupata mali, Wala hukupata faida kwa thamani yao."},{"v":13,"t":"Umetufanya kuwa lawama kwa jirani zetu, Mzaha na dhihaka kwao wanaotuzunguka."},{"v":14,"t":"Umetufanya kuwa mithali kwa mataifa, Sababu ya kutikisa kichwa kwa watu wa nchi."},{"v":15,"t":"Mchana kutwa fedheha yangu i mbele yangu, Na haya ya uso wangu imenifunika,"},{"v":16,"t":"Kwa sauti ya mwenye kulaumu na kukufuru, Kwa sababu ya adui na mjilipiza kisasi."},{"v":17,"t":"Haya yote yametupata, bali hatukukusahau, Wala hatukulihalifu agano lako."},{"v":18,"t":"Hatukuiacha mioyo yetu irudi nyuma, Wala hatua zetu hazikuiacha njia yako."},{"v":19,"t":"Hata utuponde katika kao la mbwa-mwitu, Na kutufunika kwa uvuli wa mauti."},{"v":20,"t":"Ikiwa tumelisahau jina la Mungu wetu, Au kumnyoshea mungu mgeni mikono yetu;"},{"v":21,"t":"Je! Mungu hatalichunguza neno hilo? Maana ndiye azijuaye siri za moyo."},{"v":22,"t":"Hasha! Kwa ajili yako tunauawa mchana kutwa; Tunafanywa kondoo waendao kuchinjwa."},{"v":23,"t":"Amka, Bwana, mbona umelala? Ondoka, usitutupe kabisa."},{"v":24,"t":"Mbona unatuficha uso wako, Na kusahau kuonewa na kudhulumiwa kwetu?"},{"v":25,"t":"Maana nafsi yetu imeinama mavumbini, Tumbo letu limegandamana na nchi."},{"v":26,"t":"Uondoke, uwe msaada wetu, Utukomboe kwa ajili ya fadhili zako."}]},{"c":45,"verses":[{"v":1,"t":"Moyo wangu umefurika kwa neno jema, Mimi nasema niliyomfanyizia mfalme; Ulimi wangu ni kalamu ya mwandishi mstadi."},{"v":2,"t":"Wewe u mzuri sana kuliko wanadamu; Neema imemiminiwa midomoni mwako, Kwa hiyo Mungu amekubariki hata milele."},{"v":3,"t":"Jifungie upanga wako pajani, wewe uliye hodari, Utukufu ni wako na fahari ni yako."},{"v":4,"t":"Katika fahari yako usitawi uendelee Kwa ajili ya kweli na upole na haki Na mkono wako wa kuume Utakufundisha mambo ya kutisha."},{"v":5,"t":"Mishale yako ni mikali, watu huanguka chini yako; Imo mioyoni mwa adui za mfalme."},{"v":6,"t":"Kiti chako cha enzi, Mungu, ni cha milele na milele, Fimbo ya ufalme wako ni fimbo ya adili."},{"v":7,"t":"Umeipenda haki; Umeichukia dhuluma. Kwa hiyo MUNGU, Mungu wako, amekupaka mafuta, Mafuta ya furaha kuliko wenzako."},{"v":8,"t":"Mavazi yako yote hunukia manemane Na udi na mdalasini. Katika majumba ya pembe Vinubi vimekufurahisha."},{"v":9,"t":"Binti za wafalme wamo Miongoni mwa akina bibi wako wastahiki. Mkono wako wa kuume amesimama malkia Amevaa dhahabu ya Ofiri."},{"v":10,"t":"Sikia, binti, utazame, utege sikio lako, Uwasahau watu wako na nyumba ya baba yako."},{"v":11,"t":"Naye mfalme atautamani uzuri wako, Maana ndiye bwana wako, nawe umsujudie."},{"v":12,"t":"Na binti Tiro analeta kipawa chake, Nao matajiri wa watu watajipendekeza kwako."},{"v":13,"t":"Binti mfalme yumo ndani ana fahari tupu, Mavazi yake ni ya nyuzi za dhahabu."},{"v":14,"t":"Atapelekwa kwa mfalme Na mavazi yaliyofumwa kwa uzuri. Wanawali wenzake wanaomfuata, Watapelekwa kwako."},{"v":15,"t":"Watapelekwa kwa furaha na shangwe, Na kuingia katika nyumba ya mfalme."},{"v":16,"t":"Badala ya baba zako watakuwapo watoto wako, Utawafanya kuwa wakuu katika nchi zote."},{"v":17,"t":"Jina lako nitalifanya kuwa kumbukumbu Katika vizazi vyote. Kwa hiyo mataifa watakushukuru Milele na milele."}]},{"c":46,"verses":[{"v":1,"t":"Mungu kwetu sisi ni kimbilio na nguvu, Msaada utakaoonekana tele wakati wa mateso."},{"v":2,"t":"Kwa hiyo hatutaogopa ijapobadilika nchi, Ijapotetemeka milima moyoni mwa bahari."},{"v":3,"t":"Maji yake yajapovuma na kuumuka, Ijapopepesuka milima kwa kiburi chake."},{"v":4,"t":"Kuna mto, vijito vyake vyaufurahisha mji wa Mungu, Patakatifu pa maskani zake Aliye juu."},{"v":5,"t":"Mungu yu katikati yake hautatetemeshwa; Mungu atausaidia asubuhi na mapema."},{"v":6,"t":"Mataifa yalighadhibika, falme zikataharuki; Alitoa sauti yake, nchi ikayeyuka."},{"v":7,"t":"Bwana wa majeshi yu pamoja nasi, Mungu wa Yakobo ni ngome yetu."},{"v":8,"t":"Njoni myatazame matendo ya Bwana, Jinsi alivyofanya ukiwa katika nchi."},{"v":9,"t":"Avikomesha vita hata mwisho wa dunia; Avunja uta, akata mkuki, achoma moto magari."},{"v":10,"t":"Acheni, mjue ya kuwa Mimi ni Mungu, Nitakuzwa katika mataifa, nitakuzwa katika nchi."},{"v":11,"t":"Bwana wa majeshi yu pamoja nasi, Mungu wa Yakobo ni ngome yetu."}]},{"c":47,"verses":[{"v":1,"t":"Enyi watu wote, pigeni makofi, Mpigieni Mungu kelele kwa Sauti ya shangwe."},{"v":2,"t":"Kwa kuwa Bwana Aliye juu, mwenye kuogofya, Ndiye mfalme mkuu juu ya dunia yote."},{"v":3,"t":"Atawatiisha watu wa nchi chini yetu, Na mataifa chini ya miguu yetu."},{"v":4,"t":"Atatuchagulia urithi wetu, Fahari ya Yakobo ambaye alimpenda."},{"v":5,"t":"Mungu amepaa kwa kelele za shangwe, Bwana kwa sauti ya baragumu."},{"v":6,"t":"Mwimbieni Mungu, naam, imbeni; Mwimbieni mfalme wetu, naam, imbeni."},{"v":7,"t":"Maana Mungu ndiye mfalme wa dunia yote, Imbeni kwa akili."},{"v":8,"t":"Mungu awamiliki mataifa, Mungu ameketi katika kiti chake kitakatifu."},{"v":9,"t":"Wakuu wa watu wamekusanyika, Wawe watu wa Mungu wa Ibrahimu. Maana ngao za dunia zina Mungu, Ametukuka sana."}]},{"c":48,"verses":[{"v":1,"t":"Bwana ndiye aliye mkuu, Na mwenye kusifiwa sana. Katika mji wa Mungu wetu, Katika mlima wake mtakatifu."},{"v":2,"t":"Kuinuka kwake ni mzuri sana, Ni furaha ya dunia yote. Mlima Sayuni pande za kaskazini, Mji wa Mfalme mkuu."},{"v":3,"t":"Mungu katika majumba yake Amejijulisha kuwa ngome."},{"v":4,"t":"Maana, tazama, wafalme walikusanyika; Walipita wote pamoja."},{"v":5,"t":"Waliona, mara wakashangaa; Wakafadhaika na kukimbia."},{"v":6,"t":"Papo hapo tetemeko liliwashika, Utungu kama wa mwanamke azaaye."},{"v":7,"t":"Kwa upepo wa mashariki Wavunja jahazi za Tarshishi."},{"v":8,"t":"Kama tulivyosikia, ndivyo tulivyoona, Katika mji wa Bwana wa majeshi. Mji wa Mungu wetu; Mungu ataufanya imara hata milele."},{"v":9,"t":"Tumezitafakari fadhili zako, Ee Mungu, Katikati ya hekalu lako."},{"v":10,"t":"Kama lilivyo jina lako, Ee Mungu, Ndivyo na sifa yako hata miisho ya dunia. Mkono wako wa kuume umejaa haki;"},{"v":11,"t":"Na ufurahi mlima Sayuni. Binti za Yuda na washangilie Kwa sababu ya hukumu zako."},{"v":12,"t":"Tembeeni katika Sayuni, Uzungukeni mji, Ihesabuni minara yake,"},{"v":13,"t":"Tieni moyoni boma zake, Yafikirini majumba yake, Mpate kuwaambia kizazi kitakachokuja."},{"v":14,"t":"Kwa maana ndivyo alivyo MUNGU, Mungu wetu. Milele na milele Yeye ndiye atakayetuongoza."}]},{"c":49,"verses":[{"v":1,"t":"Sikieni haya, enyi mataifa yote; Sikilizeni, ninyi nyote mnaokaa duniani."},{"v":2,"t":"Watu wakuu na watu wadogo wote pia, Tajiri na maskini wote pamoja."},{"v":3,"t":"Kinywa changu kitanena hekima, Na fikira za moyo wangu zitakuwa za busara."},{"v":4,"t":"Nitatega sikio langu nisikie mithali, Na kufumbua fumbo langu kwa kinubi"},{"v":5,"t":"Kwa nini niogope siku za uovu, Ubaya ukinizunguka miguuni pangu?"},{"v":6,"t":"Wa hao wanaozitumainia mali zao, Na kujisifia wingi wa utajiri wao;"},{"v":7,"t":"Hakuna mtu awezaye kumkomboa ndugu yake, Wala kumpa Mungu fidia kwa ajili yake,"},{"v":8,"t":"(Maana fidia ya nafsi zao ina gharama, Wala hana budi kuiacha hata milele;)"},{"v":9,"t":"ili aishi sikuzote asilione kaburi."},{"v":10,"t":"Naam, ataliona, hata wenye hekima hufa; Mpumbavu na mjinga hupotea pamoja, Na kuwaachia wengine mali zao."},{"v":11,"t":"Makaburi ni nyumba zao hata milele, Maskani zao vizazi hata vizazi. Hao waliotaja mashamba yao Kwa majina yao wenyewe."},{"v":12,"t":"Lakini mwanadamu hadumu katika heshima, Bali amefanana na wanyama wapoteao."},{"v":13,"t":"Hiyo ndiyo njia yao, ujinga wao, Nao walioko baada yao huyaridhia maneno yao."},{"v":14,"t":"Kama kondoo wamewekwa kwenda kuzimu, Na mauti itawachunga; Watu wanyofu watawamiliki asubuhi; Umbo lao litachakaa, kao lao ni kuzimu."},{"v":15,"t":"Bali Mungu atanikomboa nafsi yangu, Atanitoa mkononi mwa kuzimu, maana atanikaribisha."},{"v":16,"t":"Usiogope mtu atakapopata utajiri, Na fahari ya nyumba yake itakapozidi."},{"v":17,"t":"Maana atakapokufa hatachukua cho chote; Utukufu wake hautashuka ukimfuata."},{"v":18,"t":"Ajapojibariki nafsi yake alipokuwa hai, Na watu watakusifu ukijitendea mema,"},{"v":19,"t":"Atakwenda kwenye kizazi cha baba zake Hawataona nuru hata milele."},{"v":20,"t":"Mwanadamu mwenye heshima, iwapo hana akili, Amefanana na wanyama wapoteao."}]},{"c":50,"verses":[{"v":1,"t":"Mungu, Mungu Bwana, amenena, ameiita nchi, Toka maawio ya jua hata machweo yake."},{"v":2,"t":"Tokea Sayuni, ukamilifu wa uzuri, Mungu amemulika."},{"v":3,"t":"Mungu wetu atakuja wala hatanyamaza, Moto utakula mbele zake, na tufani yavuma sana ikimzunguka pande zote."},{"v":4,"t":"Ataziita mbingu zilizo juu, Na nchi pia awahukumu watu wake."},{"v":5,"t":"Nikusanyieni wacha Mungu wangu Waliofanya agano nami kwa dhabihu."},{"v":6,"t":"Na mbingu zitatangaza haki yake, Kwa maana Mungu ndiye aliye hakimu."},{"v":7,"t":"Sikieni, enyi watu wangu, nami nitanena, Mimi nitakushuhudia, Israeli; Mimi ndimi niliye MUNGU, Mungu wako."},{"v":8,"t":"Sitakukemea kwa ajili ya dhabihu zako, Na kafara zako ziko mbele zangu daima."},{"v":9,"t":"Sitatwaa ng'ombe katika nyumba yako, Wala beberu katika mazizi yako."},{"v":10,"t":"Maana kila hayawani ni wangu, Na makundi juu ya milima elfu."},{"v":11,"t":"Nawajua ndege wote wa milima, Na wanyama wote wa mashamba ni wangu"},{"v":12,"t":"Kama ningekuwa na njaa singekuambia, Maana ulimwengu ni wangu, navyo viujazavyo."},{"v":13,"t":"Je! Nile nyama ya mafahali! Au ninywe damu ya mbuzi!"},{"v":14,"t":"Mtolee Mungu dhabihu za kushukuru; Mtimizie Aliye juu nadhiri zako."},{"v":15,"t":"Ukaniite siku ya mateso; Nitakuokoa, na wewe utanitukuza."},{"v":16,"t":"Bali mtu asiye haki, Mungu amwambia, Una nini wewe kuitangaza sheria yangu, Na kuliweka agano langu kinywani mwako?"},{"v":17,"t":"Maana wewe umechukia maonyo, Na kuyatupa maneno yangu nyuma yako."},{"v":18,"t":"Ulipomwona mwivi ulikuwa radhi naye, Ukashirikiana na wazinzi."},{"v":19,"t":"Umekiachia kinywa chako kinene mabaya, Na ulimi wako watunga hila."},{"v":20,"t":"Umekaa na kumsengenya ndugu yako, Na mwana wa mama yako umemsingizia."},{"v":21,"t":"Ndivyo ulivyofanya, nami nikanyamaza; Ukadhani ya kuwa Mimi ni kama wewe. Walakini nitakukemea; Nitayapanga hayo mbele ya macho yako."},{"v":22,"t":"Yafahamuni hayo, Ninyi mnaomsahau Mungu, Nisije nikawararueni, Asipatikane mwenye kuwaponya."},{"v":23,"t":"Atoaye dhabihu za kushukuru, Ndiye anayenitukuza. Naye autengenezaye mwenendo wake, Nitamwonyesha wokovu wa Mungu."}]},{"c":51,"verses":[{"v":1,"t":"Ee Mungu, unirehemu, Sawasawa na fadhili zako. Kiasi cha wingi wa rehema zako, Uyafute makosa yangu."},{"v":2,"t":"Unioshe kabisa na uovu wangu, Unitakase dhambi zangu."},{"v":3,"t":"Maana nimejua mimi makosa yangu Na dhambi yangu i mbele yangu daima."},{"v":4,"t":"Nimekutenda dhambi Wewe peke yako, Na kufanya maovu mbele za macho yako. Wewe ujulikane kuwa una haki unenapo, Na kuwa safi utoapo hukumu."},{"v":5,"t":"Tazama, mimi naliumbwa katika hali ya uovu; Mama yangu alinichukua mimba hatiani."},{"v":6,"t":"Tazama, wapendezwa na kweli iliyo moyoni; Nawe utanijulisha hekima kwa siri,"},{"v":7,"t":"Unisafishe kwa hisopo nami nitakuwa safi, Unioshe, nami nitakuwa mweupe kuliko theluji"},{"v":8,"t":"Unifanye kusikia furaha na shangwe, Mifupa uliyoiponda ifurahi."},{"v":9,"t":"Usitiri uso wako usitazame dhambi zangu; Uzifute hatia zangu zote."},{"v":10,"t":"Ee Mungu, uniumbie moyo safi, Uifanye upya roho iliyotulia ndani yangu"},{"v":11,"t":"Usinitenge na uso wako, Wala roho yako mtakatifu usiniondolee."},{"v":12,"t":"Unirudishie furaha ya wokovu wako; Unitegemeze kwa roho ya wepesi."},{"v":13,"t":"Nitawafundisha wakosaji njia zako, Na wenye dhambi watarejea kwako."},{"v":14,"t":"Ee MUNGU, Mungu wa wokovu wangu, Uniponye na damu za watu, Na ulimi wangu utaiimba haki yako."},{"v":15,"t":"Ee Bwana, uifumbue midomo yangu, Na kinywa changu kitazinena sifa zako."},{"v":16,"t":"Maana hupendezwi na dhabihu, au ningeitoa, Wewe huridhii sadaka ya kuteketezwa."},{"v":17,"t":"Dhabihu za Mungu ni roho iliyovunjika; Moyo uliovunjika na kupondeka, Ee Mungu, hutaudharau."},{"v":18,"t":"Uitendee mema Sayuni kwa radhi yako, Uzijenge kuta za Yerusalemu."},{"v":19,"t":"Ndipo utakapopendezwa na dhabihu za haki, Na sadaka za kuteketezwa, na kafara. Ndipo watakapotoa ng'ombe Juu ya madhabahu yako."}]},{"c":52,"verses":[{"v":1,"t":"Kwa nini kujisifia uovu, Ewe jabari? Wema wa Mungu upo sikuzote."},{"v":2,"t":"Ulimi wako watunga madhara, Kama wembe mkali, Ewe mwenye hila"},{"v":3,"t":"Umependa mabaya kuliko mema, Na uongo kuliko kusema kweli."},{"v":4,"t":"Umependa maneno yote ya kupoteza watu, Ewe ulimi wenye hila."},{"v":5,"t":"Lakini Mungu atakuharibu hata milele; Atakuondolea mbali; Atakunyakua hemani mwako; Atakung'oa katika nchi ya walio hai."},{"v":6,"t":"Nao wenye haki wataona; Wataingiwa na hofu na kumcheka;"},{"v":7,"t":"Kumbe! Huyu ndiye mtu yule, Asiyemfanya Mungu kuwa nguvu zake. Aliutumainia wingi wa mali zake, Na kujifanya hodari kwa madhara yake."},{"v":8,"t":"Bali mimi ni kama mzeituni Umeao katika nyumba ya Mungu. Nazitumainia fadhili za Mungu milele na milele."},{"v":9,"t":"Nitakushukuru milele kwa maana umetenda; Nitalingojea jina lako kwa kuwa ni jema; Mbele ya wacha Mungu wako."}]},{"c":53,"verses":[{"v":1,"t":"Mpumbavu amesema moyoni, Hakuna Mungu; Wametenda uovu wa ufisadi na kuchukiza, Hakuna atendaye mema."},{"v":2,"t":"Toka mbinguni MUNGU aliwachungulia wanadamu, Aone kama yuko mtu mwenye akili, Amtafutaye Mungu."},{"v":3,"t":"Kila mtu amepotoka, wameoza wote pamoja, Hakuna atendaye mema, La! Hata mmoja."},{"v":4,"t":"Je! Wafanyao maovu hawajui? Walao watu wangu kama walavyo mkate, Hawakumwita MUNGU."},{"v":5,"t":"Hapo waliingiwa na hofu pasipokuwapo hofu, Maana Mungu ameitawanya mifupa yake aliyekuhusuru. Umewatia aibu, Kwa sababu MUNGU amewadharau."},{"v":6,"t":"Laiti wokovu wa Israeli utoke katika Sayuni! MUNGU awarudishapo wafungwa wa watu wake; Yakobo atashangilia, Israeli atafurahi."}]},{"c":54,"verses":[{"v":1,"t":"Ee Mungu, kwa jina lako uniokoe, Na kwa uweza wako unifanyie hukumu."},{"v":2,"t":"Ee Mungu, uyasikie maombi yangu, Uyasikilize maneno ya kinywa changu."},{"v":3,"t":"Kwa maana wageni wamenishambulia; Watu watishao wananitafuta nafsi yangu; Hawakumweka Mungu mbele yao."},{"v":4,"t":"Tazama, Mungu ndiye anayenisaidia; Bwana ndiye anayenitegemeza nafsi yangu."},{"v":5,"t":"Atawarudishia adui zangu ubaya wao; Uwaangamize kwa uaminifu wako."},{"v":6,"t":"Kwa ukunjufu wa moyo nitakutolea dhabihu; Ee Bwana, nitalishukuru jina lako, maana ni jema."},{"v":7,"t":"Kwa kuwa limeniokoa na kila taabu; Na jicho langu limeridhika Kwa kuwatazama adui zangu."}]},{"c":55,"verses":[{"v":1,"t":"Ee Mungu, uisikilize sala yangu, Wala usijifiche nikuombapo rehema."},{"v":2,"t":"Unisikilize na kunijibu, Nimetanga-tanga nikilalama na kuugua."},{"v":3,"t":"Kwa sababu ya sauti ya adui, Kwa sababu ya dhuluma yake yule mwovu. Kwa maana wananitupia uovu, Na kwa ghadhabu wananiudhi."},{"v":4,"t":"Moyo wangu unaumia ndani yangu, Na hofu za mauti zimeniangukia."},{"v":5,"t":"Hofu na tetemeko limenijia, Na hofu kubwa imenifunikiza."},{"v":6,"t":"Nikasema, Ningekuwa na mbawa kama njiwa, Ningerukia mbali na kustarehe."},{"v":7,"t":"Ningekwenda zangu mbali, Ningetua jangwani."},{"v":8,"t":"Ningefanya haraka kuzikimbia Dhoruba na tufani."},{"v":9,"t":"Ee Bwana, uwaangamize, uzichafue ndimi zao, Maana nimeona dhuluma na fitina katika mji."},{"v":10,"t":"Mchana na usiku huzunguka kutani mwake; Uovu na taabu zimo ndani yake;"},{"v":11,"t":"Tamaa mbaya zimo ndani yake; Dhuluma na hila haziondoki mitaani mwake."},{"v":12,"t":"Kwa maana aliyetukana si adui; Kama ndivyo, ningevumilia. Aliyejitukuza juu yangu siye anichukiaye; Kama ndivyo, ningejificha asinione."},{"v":13,"t":"Bali ni wewe, mtu mwenzangu, Rafiki yangu, niliyejuana nawe sana."},{"v":14,"t":"Tulipeana shauri tamu; na kutembea Nyumbani mwa Mungu pamoja na mkutano."},{"v":15,"t":"Mauti na iwapate kwa ghafula, Na washuke kuzimu wangali hai, Maana uovu u makaoni mwao na katikati yao."},{"v":16,"t":"Nami nitamwita Mungu, Na Bwana ataniokoa;"},{"v":17,"t":"Jioni, asubuhi, na adhuhuri nitalalama na kuugua, Naye ataisikia sauti yangu."},{"v":18,"t":"Ameiokoa nafsi yangu iwe salama, asinikaribie mtu, Maana walioshindana nami walikuwa wengi."},{"v":19,"t":"Mungu atasikia na kuwajibu; Ndiye Yeye akaaye tangu milele. Mageuzi ya mambo hayawapati hao, Kwa hiyo hawamchi Mungu."},{"v":20,"t":"Amenyosha mkono awadhuru waliopatana naye, Amelihalifu agano lake."},{"v":21,"t":"Kinywa chake ni laini kuliko siagi, Bali moyo wake ni vita. Maneno yake ni mororo kuliko mafuta, Bali hayo ni panga wazi."},{"v":22,"t":"Umtwike Bwana mzigo wako naye atakutegemeza, Hatamwacha mwenye haki aondoshwe milele."},{"v":23,"t":"Nawe, Ee Mungu, utawatelemsha, Walifikilie shimo la uharibifu; Watu wa damu na hila hawataishi nusu ya siku zao, Bali mimi nitakutumaini Wewe."}]},{"c":56,"verses":[{"v":1,"t":"Mungu, unirehemu, maana yuko atakaye kunimeza, Mchana kutwa ananionea akileta vita."},{"v":2,"t":"Adui zangu wanataka kunimeza mchana kutwa, Maana waletao vita juu yangu kwa kiburi ni wengi."},{"v":3,"t":"Siku ya hofu yangu nitakutumaini Wewe;"},{"v":4,"t":"Kwa msaada wa MUNGU nitalisifu neno lake. Nimemtumaini Mungu, sitaogopa; Mwenye mwili atanitenda nini?"},{"v":5,"t":"Mchana kutwa wanapotosha maneno yangu, Mawazo yao yote ni juu yangu kunitakia mabaya."},{"v":6,"t":"Hukutanika, hujificha, huziangalia nyayo zangu, Kwa kuwa wameniotea nafsi yangu."},{"v":7,"t":"Je! Wataokoka kwa uovu wao? Ee Mungu, uwaangamize kwa hasira yako."},{"v":8,"t":"Umehesabu kutanga-tanga kwangu; Uyatie machozi yangu katika chupa yako; (Je! Hayamo katika kitabu chako?)"},{"v":9,"t":"Ndipo adui zangu watarudi nyuma siku ile niitapo. Neno hili najua kuwa MUNGU yu upande wangu;"},{"v":10,"t":"Kwa msaada wa MUNGU nitalisifu neno lake. Kwa msaada wa Bwana nitalisifu neno lake."},{"v":11,"t":"Nimemtumaini Mungu, sitaogopa; Mwanadamu atanitenda nini?"},{"v":12,"t":"Ee Mungu, nadhiri zako zi juu yangu; Nitakutolea dhabihu za kushukuru."},{"v":13,"t":"Maana umeniponya nafsi yangu na mauti; Je! Hukuizuia miguu yangu isianguke? Ili nienende mbele za Mungu Katika nuru ya walio hai."}]},{"c":57,"verses":[{"v":1,"t":"Unirehemu, Ee Mungu, unirehemu mimi, Maana nafsi yangu imekukimbilia Wewe. Nitaukimbilia uvuli wa mbawa zako, Hata misiba hii itakapopita."},{"v":2,"t":"Nitamwita MUNGU Aliye juu, Mungu anitimiziaye mambo yangu."},{"v":3,"t":"Atapeleka toka mbinguni na kuniokoa, Atukanapo yule atakaye kunimeza. Mungu atazipeleka Fadhili zake na kweli yake"},{"v":4,"t":"Nafsi yangu i kati ya simba, Nitastarehe kati yao waliowaka moto. Wanadamu meno yao ni mikuki na mishale, Na ndimi zao ni upanga mkali."},{"v":5,"t":"Ee Mungu, utukuzwe juu ya mbingu, Na juu ya nchi yote uwe utukufu wako."},{"v":6,"t":"Wameweka wavu ili kuninasa miguu; Nafsi yangu imeinama; Wamechimba shimo mbele yangu; Wametumbukia ndani yake!"},{"v":7,"t":"Ee Mungu, moyo wangu u thabiti, Moyo wangu u thabiti. Nitaimba, nitaimba zaburi,"},{"v":8,"t":"Amka, utukufu wangu. Amka, kinanda na kinubi, Nitaamka alfajiri."},{"v":9,"t":"Ee Bwana, nitakushukuru kati ya watu, Nitakuimbia zaburi kati ya mataifa."},{"v":10,"t":"Maana fadhili zako ni kubwa hata mbinguni, Na uaminifu wako hata mawinguni."},{"v":11,"t":"Ee Mungu, utukuzwe juu ya mbingu, Na juu ya nchi yote uwe utukufu wako."}]},{"c":58,"verses":[{"v":1,"t":"Ni kweli, enyi wakuu, mnanena haki? Enyi wanadamu, mnahukumu kwa adili?"},{"v":2,"t":"Sivyo! Mioyoni mwenu mnatenda maovu; Katika nchi mnapima udhalimu wa mikono yenu."},{"v":3,"t":"Wasio haki wamejitenga tangu kuzaliwa kwao; Tangu tumboni wamepotea, wakisema uongo."},{"v":4,"t":"Sumu yao, mfano wake ni sumu ya nyoka; Mfano wao ni fira kiziwi azibaye sikio lake."},{"v":5,"t":"Asiyeisikiliza sauti ya waganga, Ijapo wanafanya uganga kwa ustadi."},{"v":6,"t":"Ee Mungu, uyavunje meno yao vinywani mwao; Ee Bwana, uyavunje magego ya wana-simba."},{"v":7,"t":"Na watoweke kama maji yapitayo kwa kasi; Akiielekeza mishale yake, iwe imetiwa ubutu."},{"v":8,"t":"Kama konokono ayeyukaye na kutoweka, Kama mimba iliyoharibika, isiyoliona jua,"},{"v":9,"t":"Kabla ya masufuria yenu kupata moto wa miiba, Ataipeperusha kama chamchela, Iliyo mibichi na iliyo moto."},{"v":10,"t":"Mwenye haki atafurahi akionapo kisasi; Ataiosha miguu yake katika damu ya wasio haki."},{"v":11,"t":"Na mwanadamu atasema, Hakika iko thawabu yake mwenye haki. Hakika yuko Mungu Anayehukumu katika dunia."}]},{"c":59,"verses":[{"v":1,"t":"Ee Mungu wangu, uniponye na adui zangu, Uniinue juu yao wanaoshindana nami."},{"v":2,"t":"Uniponye nao wafanyao maovu, Uniokoe na watu wa damu."},{"v":3,"t":"Kwa maana wanaiotea nafsi yangu; Wenye nguvu wamenikusanyikia; Ee Bwana, si kwa kosa langu, Wala si kwa hatia yangu."},{"v":4,"t":"Bila kosa langu huenda mbio, hujiweka tayari; Uamke uonane nami, na kutazama."},{"v":5,"t":"Na Wewe, Bwana, Mungu wa majeshi, Mungu wa Israeli, uamke. Uwapatilize mataifa yote; Usiwarehemu waovu wafanyao uovu hata mmoja."},{"v":6,"t":"Wakati wa jioni hurudi, hulia kama mbwa, Na kuzunguka-zunguka mjini."},{"v":7,"t":"Tazama, kwa vinywa vyao huteuka, Midomoni mwao mna panga, Kwa maana ni nani asikiaye?"},{"v":8,"t":"Na Wewe, Bwana, utawacheka, Utawadhihaki mataifa yote."},{"v":9,"t":"Ee nguvu zangu, nitakungoja Wewe, Maana Mungu ndiye aliye ngome yangu"},{"v":10,"t":"Mungu wa fadhili zangu atanitangulia, Mungu atanijalia kuwatazama adui zangu."},{"v":11,"t":"Usiwaue, watu wangu wasije wakasahau; Uwatawanye kwa uweza wako, Na kuwaangamiza, Ee Bwana, ngao yetu."},{"v":12,"t":"Kwa dhambi ya kinywa chao, Na kwa neno la midomo yao, Wanaswe kwa kiburi chao, Kwa ajili ya kulaani na uongo wasemao."},{"v":13,"t":"Uwakomeshe kwa hasira, Uwakomeshe watoweke, Wajue ya kuwa Mungu atawala katika Yakobo, Na hata miisho ya dunia."},{"v":14,"t":"Wakati wa jioni hurudi, hulia kama mbwa, Na kuzunguka-zunguka mjini."},{"v":15,"t":"Watatanga-tanga hao wakitafuta chakula; Wasiposhiba watakesha usiku kucha."},{"v":16,"t":"Nami nitaziimba nguvu zako asubuhi, Nitaziimba fadhili zako kwa furaha. Kwa kuwa ndiwe uliyekuwa ngome yangu, Na makimbilio siku ya shida yangu."},{"v":17,"t":"Ee nguvu zangu, nitakuimbia kwa furaha, Maana Mungu ndiye aliye ngome yangu, Mungu wa fadhili zangu."}]},{"c":60,"verses":[{"v":1,"t":"Ee Mungu, umetutupa na kututawanya, Umekuwa na hasira, uturudishe tena."},{"v":2,"t":"Umeitetemesha nchi na kuipasua, Upaponye palipobomoka, maana inatikisika."},{"v":3,"t":"Umewaonyesha watu wako mazito, Na kutunywesha mvinyo ya kutuyumbisha."},{"v":4,"t":"Umewapa wakuogopao bendera, Ili itwekwe kwa ajili ya kweli."},{"v":5,"t":"Ili wapenzi wako waopolewe, Uokoe kwa mkono wako wa kuume, utuitikie."},{"v":6,"t":"Mungu amenena kwa utakatifu wake, Nami nitashangilia. Nitaigawanya Shekemu, Nitalipima bonde la Sukothi."},{"v":7,"t":"Gileadi ni yangu, na Manase ni yangu, Na Efraimu ni nguvu ya kichwa changu. Yuda ni fimbo yangu ya kifalme,"},{"v":8,"t":"Moabu ni bakuli langu la kunawia. Nitamtupia Edomu kiatu changu, Na kumpigia Filisti kelele za vita."},{"v":9,"t":"Ni nani atakayenipeleka hata mji wenye boma? Ni nani atakayeniongoza hata Edomu?"},{"v":10,"t":"Ee Mungu, si Wewe uliyetutupa? Wala, Ee Mungu, hutoki na majeshi yetu?"},{"v":11,"t":"Utuletee msaada juu ya mtesi, Maana wokovu wa binadamu haufai."},{"v":12,"t":"Kwa msaada wa Mungu tutatenda makuu, Maana Yeye atawakanyaga watesi wetu."}]},{"c":61,"verses":[{"v":1,"t":"Ee Mungu, ukisikie kilio changu, Uyasikilize maombi yangu."},{"v":2,"t":"Toka mwisho wa nchi nitakulilia nikizimia moyo, Uniongoze juu ya mwamba nisioweza kuupanda."},{"v":3,"t":"Kwa maana ulikuwa kimbilio langu, Ngome yenye nguvu adui asinipate."},{"v":4,"t":"Nitakaa katika hema yako milele, Nitaikimbilia sitara ya mbawa zako"},{"v":5,"t":"Maana Wewe, Mungu, umezisikia nadhiri zangu. Umewapa urithi wao waliogopao jina lako."},{"v":6,"t":"Utaziongeza siku za mfalme, Miaka yake itakuwa kama vizazi vingi."},{"v":7,"t":"Atakaa mbele za Mungu milele, Ziagize fadhili na kweli zimhifadhi."},{"v":8,"t":"Ndivyo nitakavyoliimbia jina lako daima, Ili niondoe nadhiri zangu kila siku."}]},{"c":62,"verses":[{"v":1,"t":"Nafsi yangu yamngoja Mungu peke yake kwa kimya, Wokovu wangu hutoka kwake."},{"v":2,"t":"Yeye tu ndiye mwamba wangu na wokovu wangu, Ngome yangu, sitatikisika sana."},{"v":3,"t":"Hata lini mtamshambulia mtu, Mpate kumwua ninyi nyote pamoja? Kama ukuta unaoinama, Kama kitalu kilicho tayari kuanguka,"},{"v":4,"t":"Hufanya shauri kumwangusha tu katika cheo chake; Huufurahia uongo. Kwa kinywa chao hubariki; Kwa moyo wao hulaani."},{"v":5,"t":"Nafsi yangu, umngoje Mungu peke yake kwa kimya. Tumaini langu hutoka kwake."},{"v":6,"t":"Yeye tu ndiye mwamba wangu na wokovu wangu, Ngome yangu, sitatikisika sana."},{"v":7,"t":"Kwa Mungu wokovu wangu, Na utukufu wangu; Mwamba wa nguvu zangu, Na kimbilio langu ni kwa Mungu."},{"v":8,"t":"Enyi watu, mtumainini sikuzote, Ifunueni mioyo yenu mbele zake; Mungu ndiye kimbilio letu."},{"v":9,"t":"Hakika binadamu ni ubatili, Na wenye cheo ni uongo, Katika mizani huinuka; Wote pamoja ni hafifu kuliko ubatili."},{"v":10,"t":"Msiitumainie dhuluma, Wala msijivune kwa unyang'anyi; Mali izidipo msiiangalie sana moyoni."},{"v":11,"t":"Mara moja amenena Mungu; Mara mbili nimeyasikia haya, Ya kuwa nguvu zina Mungu,"},{"v":12,"t":"Na fadhili ziko kwako, Ee Bwana; Maana ndiwe umlipaye kila mtu Sawasawa na haki yake."}]},{"c":63,"verses":[{"v":1,"t":"Ee MUNGU, Mungu wangu, nitakutafuta mapema, Nafsi yangu inakuonea kiu, Mwili wangu wakuonea shauku, Katika nchi kame na uchovu, isiyo na maji."},{"v":2,"t":"Ndivyo nilivyokutazama katika patakatifu, Nizione nguvu zako na utukufu wako."},{"v":3,"t":"Maana fadhili zako ni njema kuliko uhai; Midomo yangu itakusifu."},{"v":4,"t":"Ndivyo nitakavyokubariki maadamu ni hai; Kwa jina lako nitaiinua mikono yangu."},{"v":5,"t":"Nafsi yangu itakinai kama kushiba mafuta na vinono; Kinywa changu kitakusifu kwa midomo ya furaha."},{"v":6,"t":"Ninapokukumbuka kitandani mwangu, Nakutafakari Wewe makesha yote ya usiku."},{"v":7,"t":"Maana Wewe umekuwa msaada wangu, Na uvulini mwa mbawa zako nitashangilia."},{"v":8,"t":"Nafsi yangu inakuandama sana; Mkono wako wa kuume unanitegemeza."},{"v":9,"t":"Bali waitafutao nafsi yangu, ili kuiharibu, Wataingia pande za nchi zilizo chini."},{"v":10,"t":"Watatolewa wafe kwa nguvu za upanga, Watakuwa riziki za mbwa-mwitu."},{"v":11,"t":"Bali mfalme atamfurahia Mungu, Kila aapaye kwa Yeye atashangilia, Kwa maana vinywa vya waongo vitafumbwa."}]},{"c":64,"verses":[{"v":1,"t":"Mungu, uisikie sauti yangu katika malalamiko yangu; Unilinde uhai wangu na hofu ya adui."},{"v":2,"t":"Utanificha mbali na shauri la siri la watenda mabaya, Mbali na ghasia ya watu wafanyao maovu;"},{"v":3,"t":"Waliounoa ulimi wao kama upanga, Wameielekeza mishale yao, maneno ya uchungu,"},{"v":4,"t":"Wapate kumpiga mkamilifu faraghani, Kwa ghafula humpiga wala hawaogopi."},{"v":5,"t":"Walijifanya hodari katika jambo baya; Hushauriana juu ya kutega mitego; Husema, Ni nani atakayeiona?"},{"v":6,"t":"Hutunga maovu; husema, Tumefanya shauri kamili; Na mawazo ya ndani ya kila mmoja wao, Na moyo wake, huwa siri kabisa."},{"v":7,"t":"Kwa hiyo Mungu atawapiga shabaha, Kwa mshale mara watapigwa."},{"v":8,"t":"Ndivyo watakavyokwazwa, Ulimi wao wenyewe ukishindana nao. Wote wawaonao watatikisa kichwa."},{"v":9,"t":"Na watu wote wataogopa, Wataitangaza kazi ya Mungu, Na kuyafahamu matendo yake."},{"v":10,"t":"Mwenye haki atamfurahia Bwana na kumkimbilia, Na wote wenye moyo wa adili watajisifu."}]},{"c":65,"verses":[{"v":1,"t":"Ee Mungu, sifa zakulaiki katika Sayuni, Na kwako Wewe itaondolewa nadhiri."},{"v":2,"t":"Wewe usikiaye kuomba, Wote wenye mwili watakujia."},{"v":3,"t":"Ingawa maovu mengi yanamshinda, Wewe utayafunika maasi yetu."},{"v":4,"t":"Heri mtu yule umchaguaye, Na kumkaribisha akae nyuani mwako. Na tushibe wema wa nyumba yako, Patakatifu pa hekalu lako."},{"v":5,"t":"Kwa mambo ya kutisha utatujibu, Katika haki, Ee Mungu wa wokovu wetu. Wewe uliye tumaini la miisho yote ya dunia, Na la bahari iliyo mbali sana,"},{"v":6,"t":"Milima waiweka imara kwa nguvu zako, Huku ukijifunga uweza kama mshipi."},{"v":7,"t":"Wautuliza uvumi wa bahari, Uvumi wa mawimbi yake, Na ghasia ya mataifa;"},{"v":8,"t":"Kwa hiyo wakaao mbali kabisa huogopa ishara zako; Milango ya asubuhi na jioni waifurahisha."},{"v":9,"t":"Umeijilia nchi na kuisitawisha, Umeitajirisha sana; Mto wa Mungu umejaa maji; Wawaruzuku watu nafaka Maana ndiwe uitengenezaye ardhi."},{"v":10,"t":"Matuta yake wayajaza maji; Wapasawazisha palipoinuka, Wailainisha nchi kwa manyunyu; Waibariki mimea yake."},{"v":11,"t":"Umeuvika mwaka taji ya wema wako; Mapito yako yadondoza unono."},{"v":12,"t":"Huyadondokea malisho ya nyikani, Na vilima vyajifunga furaha."},{"v":13,"t":"Na malisho yamevikwa kondoo, Na mabonde yamepambwa nafaka, Yanashangilia, naam, yanaimba."}]},{"c":66,"verses":[{"v":1,"t":"Mpigie Mungu kelele za shangwe, nchi yote,"},{"v":2,"t":"Imbeni utukufu wa jina lake, Tukuzeni sifa zake."},{"v":3,"t":"Mwambieni Mungu, Matendo yako yatisha kama nini! Kwa ajili ya wingi wa nguvu zako, Adui zako watakuja kunyenyekea mbele zako."},{"v":4,"t":"Nchi yote itakusujudia na kukuimbia, Naam, italiimbia jina lako."},{"v":5,"t":"Njoni yatazameni matendo ya Mungu; Hutisha kwa mambo awatendayo wanadamu;"},{"v":6,"t":"Aligeuza bahari ikawa nchi kavu; Katika mto walivuka kwa miguu; Huko ndiko mlikomfurahia."},{"v":7,"t":"Atawala kwa uweza wake milele; Macho yake yanaangalia mataifa; Waasio wasijitukuze nafsi zao."},{"v":8,"t":"Enyi mataifa, mtukuzeni Mungu wetu, Itangazeni sauti ya sifa zake;"},{"v":9,"t":"Aliyeiweka nafsi yetu katika uhai, Wala hakuuacha mguu wetu usogezwe."},{"v":10,"t":"Kwa maana umetupima, Ee Mungu, Umetujaribu inavyojaribiwa fedha."},{"v":11,"t":"Ulituingiza ndani ya wavu, Na kuweka viunoni mwetu mzigo uliotulemea."},{"v":12,"t":"Uliwapandisha watu Juu ya vichwa vyetu. Tulipita motoni na majini; Ukatutoa na kutuleta kunako wingi."},{"v":13,"t":"Nitaingia nyumbani mwako na kafara; Nitaondoa kwako nadhiri zangu;"},{"v":14,"t":"Ambazo midomo yangu ilizinena; Kinywa changu kikazisema nilipokuwa taabuni."},{"v":15,"t":"Kafara za vinono nitakutolea, Pamoja na fukizo la kondoo waume, Nitatoa ng'ombe pamoja na mbuzi."},{"v":16,"t":"Njoni, sikieni, ninyi nyote mnaomcha Mungu, Nami nitayatangaza aliyonitendea roho yangu."},{"v":17,"t":"Nalimwita kwa kinywa changu, Na sifa kuu zilikuwa chini ya ulimi wangu."},{"v":18,"t":"Kama ningaliwaza maovu moyoni mwangu, Bwana asingesikia."},{"v":19,"t":"Hakika Mungu amesikia; Ameisikiliza sauti ya maombi yangu."},{"v":20,"t":"Na ahimidiwe Mungu asiyeyakataa maombi yangu, Wala kuniondolea fadhili zake."}]},{"c":67,"verses":[{"v":1,"t":"Mungu na atufadhili na kutubariki, Na kutuangazia uso wake."},{"v":2,"t":"Njia yake ijulike duniani, Wokovu wake katikati ya mataifa yote."},{"v":3,"t":"Watu na wakushukuru, Ee Mungu, Watu wote na wakushukuru."},{"v":4,"t":"Mataifa na washangilie, Naam, waimbe kwa furaha, Maana kwa haki utawahukumu watu, Na kuwaongoza mataifa walioko duniani."},{"v":5,"t":"Watu na wakushukuru, Ee Mungu, Watu wote na wakushukuru."},{"v":6,"t":"Nchi imetoa mazao yake MUNGU, Mungu wetu, ametubariki."},{"v":7,"t":"Mungu atatubariki sisi; Miisho yote ya dunia itamcha Yeye."}]},{"c":68,"verses":[{"v":1,"t":"Mungu huondoka, adui zake wakatawanyika, Nao wamchukiao huukimbia uso wake."},{"v":2,"t":"Kama moshi upeperushwavyo, Ndivyo uwapeperushavyo wao; Kama nta iyeyukavyo mbele ya moto, Ndivyo waovu wapoteavyo usoni pa Mungu."},{"v":3,"t":"Bali wenye haki hufurahi, Na kuushangilia uso wa Mungu, Naam, hupiga kelele kwa furaha."},{"v":4,"t":"Mwimbieni Mungu, lisifuni jina lake, Mtengenezeeni njia ya barabara, Apitaye majangwani kama mpanda farasi; Jina lake ni YAHU; shangilieni mbele zake."},{"v":5,"t":"Baba wa yatima na mwamuzi wa wajane, Mungu katika kao lake takatifu."},{"v":6,"t":"Mungu huwakalisha wapweke nyumbani; Huwatoa wafungwa wakae hali ya kufanikiwa; Bali wakaidi hukaa katika nchi kavu."},{"v":7,"t":"Ee Mungu, ulipotoka mbele ya watu wako, Ulipopita nyikani,"},{"v":8,"t":"Nchi ilitetemeka Naam, mbingu zilidondoka usoni pa Mungu; Hata Sinai usoni pa Mungu; Mungu wa Israeli."},{"v":9,"t":"Ee Mungu, ulinyesha mvua ya neema; Urithi wako ulipochoka uliutia nguvu."},{"v":10,"t":"Kabila yako ilifanya kao lake huko; Ee Mungu, kwa wema wako uliwaruzuku walioonewa."},{"v":11,"t":"Bwana analitoa neno lake; Wanawake watangazao habari ni jeshi kubwa;"},{"v":12,"t":"Wafalme wa majeshi wanakimbia, wanakimbia; Na mwanamke akaaye nyumbani agawa nyara."},{"v":13,"t":"Kwa nini kulala mazizini arukapo hua, Mbawa zake ziking'aa kama fedha Na manyoya yake kama dhahabu?"},{"v":14,"t":"Mwenyezi Mungu alipotawanya wafalme huko, Kulinyesha theluji katika Salmoni."},{"v":15,"t":"Ni mlima wa Mungu mlima Bashani, Ni mlima mrefu mlima Bashani."},{"v":16,"t":"Enyi milima mirefu, kwani kuutazama kwa wivu Mlima alioutamani Mungu akae juu yake? Naam, Bwana atakaa juu yake milele."},{"v":17,"t":"Magari ya Mungu ni ishirini elfu, maelfu maelfu; Bwana yumo kati yao kama katika Sinai, Katika patakatifu."},{"v":18,"t":"Wewe umepaa juu, umeteka mateka, Umepewa vipawa katikati ya wanadamu; Naam, hata na wakaidi, Bwana Mungu akae nao."},{"v":19,"t":"Na ahimidiwe Bwana, Siku kwa siku hutuchukulia mzigo wetu; Mungu ndiye wokovu wetu."},{"v":20,"t":"Mungu kwetu sisi ni Mungu wa kuokoa; Na njia za kutoka mautini zina YEHOVA Bwana."},{"v":21,"t":"Naam, Mungu atakipasua kichwa cha adui zake, Utosi wenye nywele wa mtu afulizaye kukosa."},{"v":22,"t":"Bwana alisema, Kutoka Bashani nitawarudisha, Nitawarudisha kutoka vilindi vya bahari;"},{"v":23,"t":"Uuchovye mguu wako katika damu ya adui zako, Na ulimi wa mbwa zako upate sehemu yake."},{"v":24,"t":"Ee Mungu, wameiona miendo yako; Miendo ya Mungu wangu, Mfalme wangu, katika patakatifu"},{"v":25,"t":"Waimbaji hutangulia, nyuma yao wapigao vinanda, Kati ya wanawali wapiga matari."},{"v":26,"t":"Mhimidini Mungu katika mikutano, Bwana katika makusanyiko ya Israeli."},{"v":27,"t":"Yuko Benyamini mdogo, mtawala wao; Wakuu wa Yuda, kundi lao; Wakuu wa Zabuloni; Wakuu wa Naftali."},{"v":28,"t":"Ee Mungu, uziamuru nguvu zako; Ee Mungu, uwe hodari uliyetufanyia makuu."},{"v":29,"t":"Kwa ajili ya hekalu lako Yerusalemu Wafalme watakuletea hedaya."},{"v":30,"t":"Mkemee mnyama wa manyasini; Kundi la mafahali, na ndama za watu; Hata wanyenyekee na kuleta vipande vya fedha, Uwatawanye watu wapendao vita."},{"v":31,"t":"Masheki watakuja kutoka Misri, Kushi itamnyoshea Mungu mikono yake mara."},{"v":32,"t":"Enyi falme za dunia, mwimbieni Mungu, Msifuni Bwana kwa nyimbo."},{"v":33,"t":"Apandaye mbingu za mbingu za tangu milele; Aitoa sauti yake, sauti ya nguvu."},{"v":34,"t":"Mhesabieni Mungu nguvu; Enzi yake i juu ya Israeli; Na nguvu zake zi mawinguni."},{"v":35,"t":"Mungu ni mwenye kutisha Kutoka patakatifu pako. Ndiye Mungu wa Israeli; Yeye huwapa watu wake nguvu na uwezo. Na ahimidiwe Mungu."}]},{"c":69,"verses":[{"v":1,"t":"Ee Mungu, uniokoe, Maana maji yamefika mpaka nafsini mwangu."},{"v":2,"t":"Ninazama katika matope mengi, Pasipowezekana kusimama. Nimefika penye maji ya vilindi, Mkondo wa maji unanigharikisha."},{"v":3,"t":"Nimechoka kwa kulia kwangu, Koo yangu imekauka. Macho yangu yamedhoofu Kwa kumngoja Mungu wangu."},{"v":4,"t":"Wanaonichukia bure ni wengi Kuliko nywele za kichwa changu. Watakao kunikatilia mbali wamekuwa hodari, Adui zangu kwa sababu isiyo kweli. Hata mimi nalilipishwa kwa nguvu Vitu nisivyovichukua."},{"v":5,"t":"Ee Mungu, unajua upumbavu wangu, Wala hukufichwa dhambi yangu."},{"v":6,"t":"Wanaokungoja Wewe wasiaibishwe, Kwa ajili yangu, Bwana, MUNGU wa majeshi. Wanaokutafuta Wewe wasifedheheshwe, Kwa ajili yangu, Ee Mungu wa Israeli."},{"v":7,"t":"Maana kwa ajili yako nimestahimili laumu, Fedheha imenifunika uso wangu."},{"v":8,"t":"Nimekuwa mgeni kwa ndugu zangu, Na msikwao kwa wana wa mama yangu."},{"v":9,"t":"Maana wivu wa nyumba yako umenila, Na laumu zao wanaokulaumu zimenipata."},{"v":10,"t":"Nilipolia na kuiadhibu roho yangu kwa kufunga, Ikawa laumu juu yangu."},{"v":11,"t":"Nilipofanya gunia kuwa nguo zangu, Nikawa mithali kwao."},{"v":12,"t":"Waketio langoni hunisema, Na nyimbo za walevi hunidhihaki."},{"v":13,"t":"Nami maombi yangu nakuomba Wewe, Bwana, Wakati ukupendezao; Ee Mungu, Kwa wingi wa fadhili zako unijibu, Katika kweli ya wokovu wako."},{"v":14,"t":"Uniponye kwa kunitoa matopeni, Wala usiniache nikazama. Na niponywe nao wanaonichukia, Na katika vilindi vya maji."},{"v":15,"t":"Mkondo usinigharikishe, wala vilindi visinimeze, Wala shimo lisifumbe kinywa chake juu yangu."},{"v":16,"t":"Ee Bwana, unijibu, maana fadhili zako ni njema, Kwa kadiri ya rehema zako unielekee."},{"v":17,"t":"Wala usinifiche uso wako, mimi mtumishi wako, Maana mimi nimo taabuni, unijibu upesi."},{"v":18,"t":"Uikaribie nafsi yangu, uikomboe, Kwa sababu ya adui zangu unifidie."},{"v":19,"t":"Wewe umejua kulaumiwa kwangu, Na kuaibika na kufedheheka kwangu, Mbele zako Wewe wako watesi wangu wote."},{"v":20,"t":"Laumu imenivunja moyo, Nami ninaugua sana. Nikangoja aje wa kunihurumia, wala hakuna; Na wa kunifariji, wala sikumwona mtu."},{"v":21,"t":"Wakanipa uchungu kuwa chakula changu; Nami nilipokuwa na kiu wakaninywesha siki."},{"v":22,"t":"Meza yao mbele yao na iwe mtego; Naam, wakiwa salama na iwe tanzi."},{"v":23,"t":"Macho yao yatiwe giza wasione, Na viuno vyao uvitetemeshe daima."},{"v":24,"t":"Uimwage ghadhabu yako juu yao, Na ukali wa hasira yako uwapate."},{"v":25,"t":"Matuo yao na yawe ukiwa, Pasiwe na mtu wa kukaa hemani mwao."},{"v":26,"t":"Maana wanamwudhi mtu uliyempiga Wewe, Wanasimulia maumivu ya hao uliowatia jeraha."},{"v":27,"t":"Uwaongezee uovu juu ya uovu, Wala wasiingie katika haki yako."},{"v":28,"t":"Na wafutwe katika chuo cha uhai, Wala pamoja na wenye haki wasiandikwe."},{"v":29,"t":"Nami niliye maskini na mtu wa huzuni, Mungu, wokovu wako utaniinua."},{"v":30,"t":"Nitalisifu jina la Mungu kwa wimbo, Nami nitamtukuza kwa shukrani."},{"v":31,"t":"Nayo yatampendeza Bwana kuliko ng'ombe, Au ndama mwenye pembe na kwato."},{"v":32,"t":"Walioonewa watakapoona watafurahi; Enyi mmtafutao Mungu, mioyo yenu ihuishwe."},{"v":33,"t":"Kwa kuwa Bwana huwasikia wahitaji, Wala hawadharau wafungwa wake."},{"v":34,"t":"Mbingu na nchi zimsifu, Bahari na vyote viendavyo ndani yake."},{"v":35,"t":"Maana Mungu ataiokoa Sayuni, na kuijenga miji ya Yuda, Na watu watakaa ndani yake na kuimiliki."},{"v":36,"t":"Wazao wa watumishi wake watairithi, Nao walipendao jina lake watakaa humo."}]},{"c":70,"verses":[{"v":1,"t":"Ee Mungu, uniokoe, Ee Bwana, unisaidie hima."},{"v":2,"t":"Waaibike, wafedheheke, Wanaoitafuta nafsi yangu. Warudishwe nyuma, watahayarishwe, Wapendezwao na shari yangu."},{"v":3,"t":"Warudi nyuma, na iwe aibu yao, Wanaosema, Ewe! Ewe!"},{"v":4,"t":"Washangilie, wakufurahie, Wote wakutafutao. Waupendao wokovu wako Waseme daima, Atukuzwe Mungu."},{"v":5,"t":"Nami ni maskini na mhitaji, Ee Mungu, unijilie kwa haraka. Ndiwe msaada wangu na mwokozi wangu, Ee Bwana, usikawie."}]},{"c":71,"verses":[{"v":1,"t":"Nimekukimbilia Wewe, Bwana, Nisiaibike milele."},{"v":2,"t":"Kwa haki yako uniponye, uniopoe, Unitegee sikio lako, uniokoe."},{"v":3,"t":"Uwe kwangu mwamba wa makazi yangu, Nitakakokwenda sikuzote. Umeamuru niokolewe, Ndiwe genge langu na ngome yangu."},{"v":4,"t":"Ee Mungu wangu, uniopoe mkononi mwa mkorofi, Katika mkono wake mwovu, mdhalimu,"},{"v":5,"t":"Maana ndiwe taraja langu, Ee Bwana MUNGU, Tumaini langu tokea ujana wangu."},{"v":6,"t":"Nimekutegemea Wewe tangu kuzaliwa, Ndiwe uliyenitoa tumboni mwa mama yangu, Ninakusifu Wewe daima."},{"v":7,"t":"Nimekuwa kitu cha ajabu kwa watu wengi, Na Wewe ndiwe kimbilio langu la nguvu."},{"v":8,"t":"Kinywa changu kitajazwa sifa zako, Na heshima yako mchana kutwa."},{"v":9,"t":"Usinitupe wakati wa uzee, Nguvu zangu zipungukapo usiniache."},{"v":10,"t":"Kwa maana adui zangu wananiamba, Nao wanaoniotea roho yangu hushauriana."},{"v":11,"t":"Wakisema, Mungu amemwacha, Mfuatieni, mkamateni, hakuna wa kumponya."},{"v":12,"t":"Ee Mungu, usiwe mbali nami; Ee Mungu wangu, fanya haraka kunisaidia."},{"v":13,"t":"Waaibishwe, watoweshwe, adui za nafsi yangu. Wavikwe laumu na aibu wanaonitakia mabaya."},{"v":14,"t":"Nami nitatumaini daima, Nitazidi kuongeza sifa zake zote."},{"v":15,"t":"Kinywa changu kitasimulia haki na wokovu wako Mchana kutwa; maana sijui hesabu yake."},{"v":16,"t":"Nitakuja na mambo ya ajabu ya Bwana MUNGU; Nitawakumbusha watu haki yako Wewe peke yako."},{"v":17,"t":"Ee Mungu, umenifundisha tokea ujana wangu; Nimekuwa nikitangaza miujiza yako hata leo."},{"v":18,"t":"Na hata nikiwa ni mzee mwenye mvi, Ee Mungu, usiniache. Hata niwaeleze watu wa kizazi hiki nguvu zako, Na kila atakayekuja uweza wako."},{"v":19,"t":"Na haki yako, Ee Mungu, Imefika juu sana. Wewe uliyefanya mambo makuu; Ee Mungu, ni nani aliye kama Wewe?"},{"v":20,"t":"Wewe, uliyetuonyesha mateso mengi, mabaya, Utatuhuisha tena. Utatupandisha juu tena Tokea pande za chini ya nchi."},{"v":21,"t":"Laiti ungeniongezea ukuu! Urejee tena na kunifariji moyo."},{"v":22,"t":"Nami nitakushukuru kwa kinanda, Na kweli yako, Ee Mungu wangu. Nitakuimbia Wewe kwa kinubi, Ee Mtakatifu wa Israeli."},{"v":23,"t":"Midomo yangu itafurahi sana nikuimbiapo, Na nafsi yangu uliyoikomboa."},{"v":24,"t":"Ulimi wangu nao utasimulia Haki yako mchana kutwa. Kwa maana wameaibishwa, Wametahayarika, wanaonitakia mabaya."}]},{"c":72,"verses":[{"v":1,"t":"Ee Mungu, mpe mfalme hukumu zako, Na mwana wa mfalme haki yako."},{"v":2,"t":"Atawaamua watu wako kwa haki, Na watu wako walioonewa kwa hukumu."},{"v":3,"t":"Milima itawazalia watu amani, Na vilima navyo kwa haki."},{"v":4,"t":"Atawahukumu walioonewa wa watu, Atawaokoa wahitaji, atamseta mwenye kuonea."},{"v":5,"t":"Watakuogopa wakati wote wa kudumu jua, Na wakati wa kung'aa mwezi kizazi hata kizazi."},{"v":6,"t":"Atashuka kama mvua juu ya majani yaliyokatwa, Kama manyunyu yainyweshayo nchi."},{"v":7,"t":"Siku zake yeye, mtu mwenye haki atasitawi, Na wingi wa amani hata mwezi utakapokoma."},{"v":8,"t":"Na awe na enzi toka bahari hata bahari, Toka Mto hata miisho ya dunia."},{"v":9,"t":"Wakaao jangwani na wainame mbele zake; Adui zake na warambe mavumbi."},{"v":10,"t":"Wafalme wa Tarshishi na visiwa na walete kodi; Wafalme wa Sheba na Seba na watoe vipawa."},{"v":11,"t":"Naam, wafalme wote na wamsujudie; Na mataifa yote wamtumikie."},{"v":12,"t":"Kwa maana atamkomboa mhitaji aliapo, Na mtu aliyeonewa iwapo hana msaidizi."},{"v":13,"t":"Atamhurumia aliye dhaifu na maskini, Na nafsi za wahitaji ataziokoa."},{"v":14,"t":"Atawakomboa nafsi zao na kuonewa na udhalimu, Na damu yao ina thamani machoni pake."},{"v":15,"t":"Basi na aishi; Na wampe dhahabu ya Sheba; Na wamwombee daima; Na kumbariki mchana kutwa."},{"v":16,"t":"Na uwepo wingi wa nafaka Katika ardhi juu ya milima; Matunda yake na yawaye-waye kama Lebanoni, Na watu wa mjini wasitawi kama majani ya nchi."},{"v":17,"t":"Jina lake na lidumu milele, Pindi ling'aapo jua jina lake liwe na wazao; Mataifa yote na wajibariki katika yeye, Na kumwita heri."},{"v":18,"t":"Na ahimidiwe Bwana, Mungu, Mungu wa Israeli, Atendaye miujiza Yeye peke yake;"},{"v":19,"t":"Jina lake tukufu na lihimidiwe milele; Dunia yote na ijae utukufu wake. Amina na Amina."},{"v":20,"t":"Maombi ya Daudi mwana wa Yese yamekwisha."}]},{"c":73,"verses":[{"v":1,"t":"Hakika Mungu ni mwema kwa Israeli, Kwa hao walio safi mioyo yao."},{"v":2,"t":"Nami miguu yangu ilikuwa karibu na kupotoka, Hatua zangu zilikuwa karibu na kuteleza."},{"v":3,"t":"Maana naliwaonea wivu wenye kujivuna, Nilipoiona hali ya amani ya wasio haki."},{"v":4,"t":"Maana hawana maumivu katika kufa kwao, Na mwili wao una nguvu."},{"v":5,"t":"Katika taabu ya watu hawamo, Wala hawapati mapigo pamoja na wanadamu."},{"v":6,"t":"Hivyo kiburi kimekuwa mkufu shingoni mwao, Jeuri huwavika kama nguo."},{"v":7,"t":"Macho yao hutokeza kwa kunenepa, Wameipita kadiri ya mawazo ya mioyo yao."},{"v":8,"t":"Hudhihaki, husimulia mabaya, Husimulia udhalimu kana kwamba wako juu."},{"v":9,"t":"Wameweka kinywa chao mbinguni, Na ulimi wao hutanga-tanga duniani."},{"v":10,"t":"Kwa hiyo watu wake hugeuka huko, Na maji yaliyojaa humezwa nao."},{"v":11,"t":"Nao husema, Mungu ajuaje? Yako maarifa kwake aliye juu?"},{"v":12,"t":"Fahamu, ndivyo walivyo wasio haki, Na kwa kustarehe sikuzote wamepata mali nyingi."},{"v":13,"t":"Hakika nimejisafisha moyo wangu bure, Nimenawa mikono yangu kwa kutokukosa."},{"v":14,"t":"Maana mchana kutwa nimepigwa, Na kuadhibiwa kila asubuhi."},{"v":15,"t":"Kama ningalisema, Nitasimulia kama hayo; Kumbe! Ningaliwadanganya kizazi cha wana wako."},{"v":16,"t":"Nami nalifikiri jinsi ya kufahamu hayo; Ikawa taabu machoni pangu;"},{"v":17,"t":"Hata nilipoingia katika patakatifu pa Mungu, Nikautafakari mwisho wao."},{"v":18,"t":"Hakika Wewe huwaweka penye utelezi, Huwaangusha mpaka palipoharibika."},{"v":19,"t":"Namna gani wamekuwa ukiwa mara! Wametokomea na kutoweshwa kwa utisho."},{"v":20,"t":"Ee Bwana, kama ndoto wakati wa kuamka, Uondokapo utaidharau sanamu yao."},{"v":21,"t":"Moyo wangu ulipoona uchungu, Viuno vyangu viliponichoma,"},{"v":22,"t":"Nalikuwa kama mjinga, sijui neno; Nalikuwa kama mnyama tu mbele zako."},{"v":23,"t":"Walakini mimi ni pamoja nawe daima, Umenishika mkono wa kuume."},{"v":24,"t":"Utaniongoza kwa shauri lako, Na baadaye utanikaribisha kwa utukufu."},{"v":25,"t":"Ni nani niliye naye mbinguni, Wala duniani sina cha kupendeza ila Wewe."},{"v":26,"t":"Mwili wangu na moyo wangu hupunguka, Bali Mungu ni mwamba wa moyo wangu Na sehemu yangu milele."},{"v":27,"t":"Maana wajitengao nawe watapotea; Umewaangamiza wote waliokuacha Wewe."},{"v":28,"t":"Nami kumkaribia Mungu ni kwema kwangu; Nimefanya kimbilio kwa Bwana MUNGU, Niyahubiri matendo yako yote."}]},{"c":74,"verses":[{"v":1,"t":"Ee Mungu, mbona umetutupa milele? Kwa nini hasira yako inatoka moshi Juu ya kondoo wa malisho yako?"},{"v":2,"t":"Ulikumbuke kusanyiko lako, Ulilolinunua zamani. Ulilolikomboa liwe kabila ya urithi wako, Mlima Sayuni ulioufanya maskani yako."},{"v":3,"t":"Upainulie miguu yako palipoharibika milele; Adui ameufanya kila ubaya katika patakatifu."},{"v":4,"t":"Watesi wako wamenguruma kati ya kusanyiko lako; Wameweka bendera zao ziwe alama."},{"v":5,"t":"Wanaonekana kama watu wainuao mashoka, Waikate miti ya msituni."},{"v":6,"t":"Na sasa nakishi yake yote pia Wanaivunja-vunja kwa mashoka na nyundo."},{"v":7,"t":"Wamepatia moto patakatifu pako; Wamelinajisi kao la jina lako hata chini."},{"v":8,"t":"Walisema mioyoni mwao, Na tuwaangamize kabisa; Mahali penye mikutano ya Mungu Wamepachoma moto katika nchi pia."},{"v":9,"t":"Hatuzioni ishara zetu, wala sasa hakuna nabii, Wala kwetu hakuna ajuaye, hata lini?"},{"v":10,"t":"Ee Mungu, mtesi atalaumu hata lini? Adui alidharau jina lako hata milele?"},{"v":11,"t":"Mbona unaurudisha mkono wako, Naam, mkono wako wa kuume, Uutoe kifuani mwako, Ukawaangamize kabisa."},{"v":12,"t":"Lakini Mungu ni mfalme wangu tokea zamani, Afanyaye mambo ya wokovu katikati ya nchi."},{"v":13,"t":"Wewe umeipasua bahari kwa nguvu zako, Umevivunja vichwa vya nyangumi juu ya maji."},{"v":14,"t":"Wewe uliviseta vichwa vya lewiathani, Awe chakula cha watu wa jangwani."},{"v":15,"t":"Wewe ulitokeza chemchemi na kijito; Wewe ulikausha mito yenye maji sikuzote."},{"v":16,"t":"Mchana ni wako, usiku nao ni wako, Ndiwe uliyeufanya mwanga na jua."},{"v":17,"t":"Wewe uliiweka mipaka yote ya dunia, Kaskazi na kusi Wewe ulizitengeneza."},{"v":18,"t":"Ee Bwana, uyakumbuke hayo, adui amelaumu, Na watu wapumbavu wamelidharau jina lako."},{"v":19,"t":"Usimpe mnyama mkali nafsi ya hua wako; Usiusahau milele uhai wa watu wako walioonewa."},{"v":20,"t":"Ulitafakari agano; Maana mahali penye giza katika nchi Pamejaa makao ya ukatili."},{"v":21,"t":"Aliyeonewa asirejee ametiwa haya, Mnyonge na mhitaji na walisifu jina lako."},{"v":22,"t":"Ee Mungu, usimame, ujitetee mwenyewe, Ukumbuke unavyotukanwa na mpumbavu mchana kutwa."},{"v":23,"t":"Usiisahau sauti ya watesi wako, Ghasia yao wanaokuondokea inapaa daima."}]},{"c":75,"verses":[{"v":1,"t":"Ee Mungu, twakushukuru. Twakushukuru kwa kuwa Jina lako li karibu; Watu huyasimulia matendo yako ya ajabu."},{"v":2,"t":"Nitakapoufikia wakati ulioamriwa, Mimi nitahukumu hukumu za haki."},{"v":3,"t":"Ingawa dunia na wote wakaao humo wataharuki, Mimi mwenyewe nimezisimamisha nguzo zake."},{"v":4,"t":"Naliwaambia waliojivuna, Msijivune; Na wasio haki, Msiiinue pembe."},{"v":5,"t":"Msiiinue pembe yenu juu, Wala msinene kwa shingo ya kiburi."},{"v":6,"t":"Maana siko mashariki wala magharibi, Wala nyikani itokako heshima."},{"v":7,"t":"Bali Mungu ndiye ahukumuye; Humdhili huyu na kumwinua huyu."},{"v":8,"t":"Maana mkononi mwa Bwana mna kikombe, Na mvinyo yake inatoka povu; Kumejaa machanganyiko; Naye huyamimina. Na sira zake wasio haki wa dunia Watazifyonza na kuzinywa."},{"v":9,"t":"Bali mimi nitatangaza matendo yako milele, Nitamwimbia Mungu wa Yakobo."},{"v":10,"t":"Pembe zote za wasio haki nitazikata, Na pembe za mwenye haki zitainuka."}]},{"c":76,"verses":[{"v":1,"t":"Katika Yuda Mungu amejulikana, Katika Israeli jina lake ni kuu."},{"v":2,"t":"Kibanda chake pia kiko Salemu, Na maskani yake iko Sayuni."},{"v":3,"t":"Huko ndiko alikoivunja mishale ya uta, Ngao, na upanga, na zana za vita."},{"v":4,"t":"Wewe U mwenye fahari na adhama, Toka milima ya mateka."},{"v":5,"t":"Wametekwa wenye moyo thabiti; Wamelala usingizi; Wala hawakuiona mikono yao Watu wote walio hodari."},{"v":6,"t":"Kwa kukemea kwako, Ee Mungu wa Yakobo, Gari na farasi wameshikwa na usingizi mzito."},{"v":7,"t":"Wewe ndiwe utishaye, naam, Wewe; Naye ni nani awezaye kusimama ufanyapo hasira?"},{"v":8,"t":"Toka mbinguni ulitangaza hukumu; Nchi iliogopa, ikakaa kimya."},{"v":9,"t":"Mungu aliposimama ili kuhukumu Na kuwaokoa wapole wa dunia wote pia."},{"v":10,"t":"Maana hasira ya binadamu itakusifu, Masalio ya hasira utajifunga kama mshipi."},{"v":11,"t":"Wekeni nadhiri, mkaziondoe Kwa Bwana, Mungu wenu. Wote wanaomzunguka wamletee hedaya, Yeye astahiliye kuogopwa."},{"v":12,"t":"Yeye huzikata roho za wakuu; Na kuwatisha wafalme wa dunia."}]},{"c":77,"verses":[{"v":1,"t":"Nimpazie Mungu sauti yangu, Naam, nimpazie Mungu, naye atanisikia."},{"v":2,"t":"Siku ya taabu yangu nalimtafuta Bwana; Mkono wangu ulinyoshwa usiku, haukulegea; Nafsi yangu ilikataa kufarijika."},{"v":3,"t":"Nilipotaka kumkumbuka Mungu nalifadhaika; Nilipotaka kutafakari roho yangu ilizimia."},{"v":4,"t":"Ulizishika kope za macho yangu zisifumbike; Naliona mashaka nisiweze kunena."},{"v":5,"t":"Nalifikiri habari za siku za kale, Miaka ya zamani zilizopita."},{"v":6,"t":"Nakumbuka wimbo wangu usiku, Nawaza moyoni mwangu, Roho yangu ikatafuta."},{"v":7,"t":"Je! Bwana atatupa milele na milele? Hatatenda fadhili tena kabisa?"},{"v":8,"t":"Rehema zake zimekoma hata milele? Ahadi yake imekwisha hata vizazi vyote?"},{"v":9,"t":"Mungu amesahau fadhili zake? Amezuia kwa hasira rehema zake?"},{"v":10,"t":"Nikasema, Ndio udhaifu wangu huo; Lakini nitaikumbuka miaka ya mkono wa kuume wake Aliye juu."},{"v":11,"t":"Nitayakumbuka matendo ya Bwana; Naam, nitayakumbuka maajabu yako ya kale."},{"v":12,"t":"Pia nitaitafakari kazi yako yote; Nitaziwaza habari za matendo yako."},{"v":13,"t":"Ee Mungu, njia yako i katika utakatifu; Ni nani aliye mungu mkuu kama Mungu?"},{"v":14,"t":"Wewe ndiwe Mungu ufanyaye maajabu; Uliudhihirisha uweza wako kati ya mataifa."},{"v":15,"t":"Kwa mkono wako umewakomboa watu wako, Wana wa Yakobo na Yusufu."},{"v":16,"t":"Ee Mungu, yale maji yalikuona, Yale maji yalikuona, yakaogopa. Vilindi vya maji navyo vikatetemeka,"},{"v":17,"t":"Mawingu yakamwaga maji. Mbingu nazo zikatoa sauti, Mishale yako nayo ikatapakaa."},{"v":18,"t":"Sauti ya radi yako ikawa katika kisulisuli; Umeme uliuangaza ulimwengu. Nchi ilitetemeka na kutikisika;"},{"v":19,"t":"Njia yako ilikuwa katika bahari. Na mapito yako yalikuwa katika maji makuu; Hatua zako hazikujulikana."},{"v":20,"t":"Uliwaongoza watu wako kama kundi, Kwa mkono wa Musa na Haruni."}]},{"c":78,"verses":[{"v":1,"t":"Enyi watu wangu, sikilizeni sheria yangu, Tegeni masikio kwa maneno ya kinywa changu."},{"v":2,"t":"Na nifunue kinywa changu kwa mithali, Niyatamke mafumbo ya kale."},{"v":3,"t":"Mambo tuliyoyasikia na kuyafahamu, Ambayo baba zetu walituambia."},{"v":4,"t":"Hayo hatutawaficha wana wao, Huku tukiwaambia kizazi kingine, Sifa za Bwana, na nguvu zake, Na mambo yake ya ajabu aliyoyafanya."},{"v":5,"t":"Maana alikaza ushuhuda katika Yakobo, Na sheria aliiweka katika Israeli. Aliyowaamuru baba zetu Wawajulishe wana wao,"},{"v":6,"t":"Ili kizazi kingine wawe na habari, Ndio hao wana watakaozaliwa. Wasimame na kuwaambia wana wao"},{"v":7,"t":"Wamwekee Mungu tumaini lao. Wala wasiyasahau matendo ya Mungu, Bali wazishike amri zake."},{"v":8,"t":"Naam, wasiwe kama baba zao, Kizazi cha ukaidi na uasi. Kizazi kisichojitengeneza moyo, Wala roho yake haikuwa amini kwa Mungu."},{"v":9,"t":"Wale Waefraimu, wenye silaha, wapiga upinde, Walirudi nyuma siku ya vita."},{"v":10,"t":"Hawakulishika agano la Mungu; Wakakataa kuenenda katika sheria yake;"},{"v":11,"t":"Wakayasahau matendo yake, Na mambo yake ya ajabu aliyowaonyesha."},{"v":12,"t":"Mbele ya baba zao alifanya mambo ya ajabu, Katika nchi ya Misri, konde la Soani."},{"v":13,"t":"Aliipasua bahari akawavusha; Aliyasimamisha maji mfano wa chungu."},{"v":14,"t":"Akawaongoza kwa wingu mchana, Na usiku kucha kwa nuru ya moto."},{"v":15,"t":"Akapasua miamba jangwani; Akawanywesha maji mengi kama maji ya vilindi."},{"v":16,"t":"Akatokeza na vijito gengeni, Akatelemsha maji kama mito."},{"v":17,"t":"Lakini wakazidi kumtenda dhambi, Walipomwasi Aliye juu katika nchi ya kiu."},{"v":18,"t":"Wakamjaribu Mungu mioyoni mwao Kwa kutaka chakula kwa tamaa zao."},{"v":19,"t":"Naam, walimwamba Mungu, wakasema, Je! Mungu aweza kuandika meza jangwani?"},{"v":20,"t":"Tazama, aliupiga mwamba; Maji yakabubujika, ikafurika mito. Pia aweza kutupa chakula? Atawaandalia watu wake nyama?"},{"v":21,"t":"Hivyo Bwana aliposikia akaghadhibika; Moto ukawashwa juu ya Yakobo, Hasira nayo ikapanda juu ya Israeli."},{"v":22,"t":"Kwa kuwa hawakumwamini Mungu, Wala hawakuutumainia wokovu wake."},{"v":23,"t":"Lakini aliyaamuru mawingu juu; Akaifungua milango ya mbinguni;"},{"v":24,"t":"Akawanyeshea mana ili wale; Akawapa nafaka ya mbinguni."},{"v":25,"t":"Mwanadamu akala chakula cha mashujaa; Aliwapelekea chakula cha kuwashibisha."},{"v":26,"t":"Aliuelekeza upepo wa mashariki mbinguni; Akaiongoza kusi kwa uweza wake."},{"v":27,"t":"Akawanyeshea nyama kama mavumbi, Na ndege wenye mbawa, Kama mchanga wa bahari."},{"v":28,"t":"Akawaangusha kati ya matuo yao, Pande zote za maskani zao."},{"v":29,"t":"Wakala wakashiba sana; Maana aliwaletea walivyovitamani;"},{"v":30,"t":"Hawakuachana na matakwa yao. Ila chakula chao kikali ki vinywani mwao"},{"v":31,"t":"Hasira ya Mungu ikapanda juu yao, Akawaua waliokuwa wanono; Akawaangusha chini vijana wa Israeli."},{"v":32,"t":"Pamoja na hayo wakazidi kutenda dhambi, Wala hawakuyaamini matendo yake ya ajabu."},{"v":33,"t":"Kwa hiyo akazikomesha siku zao kama pumzi, Na miaka yao kwa hofu ya kuwasitusha."},{"v":34,"t":"Alipowaua ndipo walipokuwa wakimtafuta; Wakarudi wakamtaka Mungu kwa bidii."},{"v":35,"t":"Wakakumbuka kuwa Mungu ni mwamba wao, Na Mungu Aliye juu ni mkombozi wao."},{"v":36,"t":"Lakini walimdanganya kwa vinywa vyao, Wakamwambia uongo kwa ndimi zao."},{"v":37,"t":"Kwa maana mioyo yao haikuwa thabiti kwake, Wala hawakuwa waaminifu katika agano lake."},{"v":38,"t":"Lakini Yeye, kwa kuwa anayo rehema, Husamehe uovu wala haangamizi. Mara nyingi huipishia mbali ghadhabu yake, Wala haiwashi hasira yake yote."},{"v":39,"t":"Akakumbuka ya kuwa wao ni kiwiliwili, Upepo upitao wala haurudi."},{"v":40,"t":"Walimwasi jangwani mara ngapi? Na kumhuzunisha nyikani!"},{"v":41,"t":"Wakarudi nyuma wakamjaribu Mungu; Wakampa mpaka Mtakatifu wa Israeli."},{"v":42,"t":"Hawakuukumbuka mkono wake, Wala siku ile alipowakomboa na mtesi."},{"v":43,"t":"Alivyoziweka ishara zake katika Misri, Na miujiza yake katika konde la Soani."},{"v":44,"t":"Aligeuza damu mito yao, Na vijito wasipate kunywa."},{"v":45,"t":"Aliwapelekea mainzi wakawala, Na vyura wakawaharibu."},{"v":46,"t":"Akawapa tunutu mazao yao, Na nzige kazi yao."},{"v":47,"t":"Aliiharibu mizabibu yao kwa mvua ya mawe, Na mikuyu yao kwa mawe ya barafu."},{"v":48,"t":"Akaacha ng'ombe zao wapigwe kwa mvua ya mawe, Na makundi yao kwa umeme."},{"v":49,"t":"Akawapelekea ukali wa hasira yake, Ghadhabu, na uchungu, na taabu, Kundi la malaika waletao mabaya."},{"v":50,"t":"Akiifanyizia njia hasira yake; Wala hakuziepusha roho zao na mauti, Bali aliiachia tauni uhai wao;"},{"v":51,"t":"Akampiga kila mzaliwa wa kwanza wa Misri, Malimbuko ya nguvu katika hema za Hamu."},{"v":52,"t":"Bali aliwaongoza watu wake kama kondoo, Akawachunga kama kundi jangwani."},{"v":53,"t":"Hao akawachukua salama wala hawakuogopa, Bali bahari iliwafunikiza adui zao."},{"v":54,"t":"Akawapeleka hadi mpaka wake mtakatifu, Mlima alioununua kwa mkono wake wa kuume."},{"v":55,"t":"Akawafukuza mataifa mbele yao, Akawapimia urithi kwa kamba, Na kuwakalisha kabila za Israeli katika hema zao."},{"v":56,"t":"Lakini walimjaribu Mungu Aliye juu, wakamwasi, Wala hawakuzishika shuhuda zake."},{"v":57,"t":"Bali walirudi nyuma, wakahaini kama baba zao; Wakaepea kama upinde usiofaa."},{"v":58,"t":"Wakamkasirisha kwa mahali pao pa juu, Wakamtia wivu kwa sanamu zao."},{"v":59,"t":"Mungu akasikia, akaghadhibika, Akamkataa Israeli kabisa."},{"v":60,"t":"Akaiacha maskani ya Shilo, Hema aliyoiweka katikati ya wanadamu;"},{"v":61,"t":"Akaziacha nguvu zake kutekwa, Na fahari yake mkononi mwa mtesi."},{"v":62,"t":"Akawatoa watu wake wapigwe kwa upanga; Akaughadhibikia urithi wake."},{"v":63,"t":"Moto ukawala vijana wao, Wanawali wao hawakuimbiwa nyimbo za arusi,"},{"v":64,"t":"Makuhani wao walianguka kwa upanga, Wala wajane wao hawakuomboleza."},{"v":65,"t":"Ndipo Bwana alipoamka kama aliyelala usingizi, Kama shujaa apigaye kelele sababu ya mvinyo;"},{"v":66,"t":"Akawapiga watesi wake akawarudisha nyuma, Akawatia aibu ya milele."},{"v":67,"t":"Ila akaikataa hema ya Yusufu; Wala hakuichagua kabila ya Efraimu."},{"v":68,"t":"Bali aliichagua kabila ya Yuda, Mlima Sayuni alioupenda."},{"v":69,"t":"Akajenga patakatifu pake kama vilele, Kama dunia aliyoiweka imara milele."},{"v":70,"t":"Akamchagua Daudi, mtumishi wake, Akamwondoa katika mazizi ya kondoo."},{"v":71,"t":"Nyuma ya kondoo wanyonyeshao alimwondoa, Awachunge Yakobo watu wake, na Israeli urithi wake."},{"v":72,"t":"Akawalisha kwa ukamilifu wa moyo wake, Na kuwaongoza kwa busara ya mikono yake."}]},{"c":79,"verses":[{"v":1,"t":"Ee Mungu, mataifa wameingia katika urithi wako, Wamelinajisi hekalu lako takatifu. Wamefanya Yerusalemu chungu chungu."},{"v":2,"t":"Wameziacha maiti za watumishi wako Ziwe chakula cha ndege wa angani. Na miili ya watauwa wako Iwe chakula cha wanyama wa nchi."},{"v":3,"t":"Wamemwaga damu yao kama maji Pande zote za Yerusalemu, Wala hapakuwa na mzishi."},{"v":4,"t":"Tumekuwa lawama kwa jirani zetu, Mzaha na dhihaka kwao wanaotuzunguka."},{"v":5,"t":"Ee Bwana, hata lini? Utaona hasira milele? Wivu wako utawaka kama moto?"},{"v":6,"t":"Ukali wako uwamwagie mataifa wasiokujua, Na falme za hao wasioliitia jina lako."},{"v":7,"t":"Kwa maana wamemla Yakobo, Na matuo yake wameyaharibu."},{"v":8,"t":"Usikumbuke juu yetu maovu ya baba zetu, Rehema zako zije kutulaki hima, Kwa maana tumedhilika sana."},{"v":9,"t":"Ee Mungu wa wokovu wetu, utusaidie, Kwa ajili ya utukufu wa jina lako. Utuokoe, utughofiri dhambi zetu, Kwa ajili ya jina lako."},{"v":10,"t":"Kwa nini mataifa kusema, Yuko wapi Mungu wao? Kisasi cha damu ya watumishi wako iliyomwagika Kijulike kati ya mataifa machoni petu."},{"v":11,"t":"Kuugua kwake aliyefungwa Na kuingie mbele zako. Kwa kadiri ya uweza wa mkono wako Uwahifadhi wana wa mauti."},{"v":12,"t":"Uwalipe jirani zetu mara saba vifuani mwao Laumu zao walizokulaumu, Ee Bwana."},{"v":13,"t":"Na sisi tulio watu wako, Na kondoo za malisho yako, Tutakushukuru milele; Tutazisimulia sifa zako kizazi kwa kizazi."}]},{"c":80,"verses":[{"v":1,"t":"Wewe uchungaye Israeli, usikie, Wewe umwongozaye Yusufu kama kundi; Wewe uketiye juu ya makerubi, utoe nuru."},{"v":2,"t":"Mbele ya Efraimu, na Benyamini, na Manase, Uziamshe nguvu zako, Uje, utuokoe."},{"v":3,"t":"Ee Mungu, uturudishe, Uangazishe uso wako nasi tutaokoka."},{"v":4,"t":"Ee Bwana, Mungu wa majeshi, hata lini Utayaghadhibikia maombi ya watu wako?"},{"v":5,"t":"Umewalisha mkate wa machozi, Umewanywesha machozi kwa kipimo kikuu."},{"v":6,"t":"Unatufanya sababu ya ugomvi kwa jirani zetu, Na adui zetu wanacheka wao kwa wao."},{"v":7,"t":"Ee Mungu wa majeshi, uturudishe, Uangazishe uso wako nasi tutaokoka."},{"v":8,"t":"Ulileta mzabibu kutoka Misri, Ukawafukuza mataifa ukaupanda."},{"v":9,"t":"Ulitengeneza nafasi mbele yake, Nao ukatia mizizi sana ukaijaza nchi."},{"v":10,"t":"Milima ilifunikwa kwa uvuli wake, Matawi yake ni kama mierezi ya Mungu."},{"v":11,"t":"Nao uliyaeneza matawi yake hata baharini, Na vichipukizi vyake hata kunako Mto."},{"v":12,"t":"Kwa nini umezibomoa kuta zake, Wakauchuma wote wapitao njiani?"},{"v":13,"t":"Nguruwe wa msituni wanauharibu, Na hayawani wa kondeni wanautafuna."},{"v":14,"t":"Ee Mungu wa majeshi, tunakusihi, urudi, Utazame toka juu uone, uujilie mzabibu huu."},{"v":15,"t":"Na mche ule ulioupanda Kwa mkono wako wa kuume; Na tawi lile ulilolifanya Kuwa imara kwa nafsi yako."},{"v":16,"t":"Umechomwa moto; umekatwa; Kwa lawama ya uso wako wanapotea."},{"v":17,"t":"Mkono wako na uwe juu yake Mtu wa mkono wako wa kuume; Juu ya mwanadamu uliyemfanya Kuwa imara kwa nafsi yako;"},{"v":18,"t":"Basi hatutakuacha kwa kurudi nyuma; Utuhuishe nasi tutaliitia jina lako."},{"v":19,"t":"Ee Bwana, Mungu wa majeshi, uturudishe, Uangazishe uso wako nasi tutaokoka."}]},{"c":81,"verses":[{"v":1,"t":"Mwimbieni Mungu, nguvu zetu, nyimbo za furaha, Mshangilieni Mungu wa Yakobo."},{"v":2,"t":"Pazeni zaburi, pigeni matari, Kinubi chenye sauti nzuri, na kinanda."},{"v":3,"t":"Pigeni panda mwandamo wa mwezi, Wakati wa mbalamwezi, sikukuu yetu."},{"v":4,"t":"Kwa maana ni sheria kwa Israeli, Ni hukumu ya Mungu wa Yakobo."},{"v":5,"t":"Aliamuru iwe ushuhuda katika Yusufu, Alipoondoka juu ya nchi ya Misri; Maneno yake nisiyemjua naliyasikia."},{"v":6,"t":"Nimelitenga bega lake na mzigo, Mikono yake ikaachana na kikapu."},{"v":7,"t":"Katika shida uliniita nikakuokoa; Nalikuitikia katika sitara ya radi; Nalikujaribu penye maji ya Meriba."},{"v":8,"t":"Enyi watu wangu, sikieni, nami nitawaonya, Ee Israeli, kama ukitaka kunisikiliza;"},{"v":9,"t":"Usiwe na mungu mgeni ndani yako; Wala usimsujudie mungu mwingine."},{"v":10,"t":"Mimi ndimi Bwana, Mungu wako, Niliyekupandisha toka nchi ya Misri; Fumbua sana kinywa chako nami nitakijaza."},{"v":11,"t":"Lakini watu wangu hawakuisikiliza sauti yangu, Wala Israeli hawakunitaka."},{"v":12,"t":"Nikawaacha wakaenda kwa ukaidi wa mioyo yao, Waenende katika mashauri yao."},{"v":13,"t":"Laiti watu wangu wangenisikiliza, Na Israeli angeenenda katika njia zangu;"},{"v":14,"t":"Ningewadhili adui zao kwa upesi, Na juu ya watesi wao ningegeuza mkono wangu;"},{"v":15,"t":"Wamchukiao Bwana wangenyenyekea mbele zake, Bali wakati wao ungedumu milele."},{"v":16,"t":"Naam, ningewalisha kwa unono wa ngano, Ningewashibisha kwa asali itokayo mwambani."}]},{"c":82,"verses":[{"v":1,"t":"Mungu asimama katika kusanyiko la Mungu; Katikati ya miungu anahukumu."},{"v":2,"t":"Hata lini mtahukumu kwa dhuluma, Na kuzikubali nyuso za wabaya?"},{"v":3,"t":"Mfanyieni hukumu maskini na yatima; Mtendeeni haki aliyeonewa na fukara;"},{"v":4,"t":"Mwokoeni maskini na mhitaji; Mwopoeni mikononi mwa wadhalimu."},{"v":5,"t":"Hawajui wala hawafahamu, hutembea gizani; Misingi yote ya nchi imetikisika."},{"v":6,"t":"Mimi nimesema, Ndinyi miungu, Na wana wa Aliye juu, nyote pia."},{"v":7,"t":"Lakini mtakufa kama wanadamu, Mtaanguka kama mmoja wa wakuu."},{"v":8,"t":"Ee Mungu, usimame, uihukumu nchi, Maana Wewe utawarithi mataifa yote."}]},{"c":83,"verses":[{"v":1,"t":"Ee Mungu, usistarehe, Ee Mungu, usinyamae, wala usitulie."},{"v":2,"t":"Maana adui zako wanafanya ghasia, Nao wakuchukiao wameviinua vichwa vyao."},{"v":3,"t":"Juu ya watu wako wanafanya hila, Na kushauriana juu yao uliowaficha."},{"v":4,"t":"Wamesema, Njoni, tuwakatilie mbali wasiwe taifa, Na jina la Israeli halitakumbukwa tena."},{"v":5,"t":"Maana wanashauriana kwa moyo mmoja, Juu yako wanafanyana agano."},{"v":6,"t":"Hema za Edomu, na Waishmaeli, Na Moabu, na Wahagari,"},{"v":7,"t":"Gebali, na Amoni, na Amaleki, Na Filisti, nao wanaokaa Tiro,"},{"v":8,"t":"Ashuri naye amepatana nao, Wamewasaidia wana wa Lutu."},{"v":9,"t":"Uwatende kama Midiani, kama Sisera, Kama Yabini, penye kijito Kishoni."},{"v":10,"t":"Ambao waliangamizwa Endori; Wakawa samadi juu ya nchi."},{"v":11,"t":"Uwafanye wakuu wao kama Orebu na Zeebu, Na masheki yao wote kama Zeba na Zalmuna."},{"v":12,"t":"Ambao Walisema, Na tutamalaki makao ya Mungu."},{"v":13,"t":"Ee Mungu, uwafanye kama mavumbi ya kisulisuli, Mithili ya makapi mbele ya upepo,"},{"v":14,"t":"Kama moto uteketezao msitu, Kama miali ya moto iiwashayo milima,"},{"v":15,"t":"Ndivyo utakavyowafuatia kwa tufani yako, Na kuwafadhaisha kwa dhoruba yako."},{"v":16,"t":"Uwajaze nyuso zao fedheha; Wakalitafute jina lako, Bwana."},{"v":17,"t":"Waaibike, wafadhaike milele, Naam, watahayarike na kupotea."},{"v":18,"t":"Wajue ya kuwa Wewe, uitwaye jina lako YEHOVA, Ndiwe peke yako Uliye juu, juu ya nchi yote."}]},{"c":84,"verses":[{"v":1,"t":"Maskani zako zapendeza kama nini, Ee Bwana wa majeshi!"},{"v":2,"t":"Nafsi yangu imezionea shauku nyua za Bwana, Naam, na kuzikondea. Moyo wangu na mwili wangu Vinamlilia Mungu aliye hai."},{"v":3,"t":"Shomoro naye ameona nyumba, Na mbayuwayu amejipatia kioto, Alipoweka makinda yake, Kwenye madhabahu zako, Ee Bwana wa majeshi, Mfalme wangu na Mungu wangu."},{"v":4,"t":"Heri wakaao nyumbani mwako, Wanakuhimidi daima."},{"v":5,"t":"Heri ambaye nguvu zake zatoka kwako, Na njia ziendazo Sayuni zimo moyoni mwake."},{"v":6,"t":"Wakipita kati ya bonde la Vilio, Hulifanya kuwa chemchemi, Naam, mvua ya vuli hulivika baraka"},{"v":7,"t":"Huendelea toka nguvu hata nguvu, Huonekana Sayuni kila mmoja mbele za Mungu."},{"v":8,"t":"Bwana, Mungu wa majeshi, uyasikie maombi yangu, Ee Mungu wa Yakobo, usikilize,"},{"v":9,"t":"Ee Mungu, ngao yetu, uangalie, Umtazame uso masihi wako."},{"v":10,"t":"Hakika siku moja katika nyua zako Ni bora kuliko siku elfu. Ningependa kuwa bawabu nyumbani mwa Mungu wangu, Kuliko kukaa katika hema za uovu."},{"v":11,"t":"Kwa kuwa Bwana, Mungu, ni jua na ngao, Bwana atatoa neema na utukufu. Hatawanyima kitu chema Hao waendao kwa ukamilifu."},{"v":12,"t":"Ee Bwana wa majeshi, Heri mwanadamu anayekutumaini Wewe."}]},{"c":85,"verses":[{"v":1,"t":"Bwana, umeiridhia nchi yako, Umewarejeza mateka wa Yakobo."},{"v":2,"t":"Umeusamehe uovu wa watu wako, Umezisitiri hatia zao zote."},{"v":3,"t":"Umeiondoa ghadhabu yako yote, Umerudi na kuuacha ukali wa hasira yako."},{"v":4,"t":"Mungu wa wokovu wetu, uturudishe, Uikomeshe hasira uliyo nayo juu yetu."},{"v":5,"t":"Je! Utatufanyia hasira hata milele? Utadumisha ghadhabu kizazi hata kizazi?"},{"v":6,"t":"Je! Hutaki kurudi na kutuhuisha, Watu wako wakufurahie?"},{"v":7,"t":"Ee Bwana, utuonyeshe rehema zako, Utupe wokovu wako."},{"v":8,"t":"Na nisikie atakavyosema Mungu Bwana, Maana atawaambia watu wake amani, Naam, na watauwa wake pia, Bali wasiurudie upumbavu tena."},{"v":9,"t":"Hakika wokovu wake u karibu na wamchao, Utukufu ukae katika nchi yetu."},{"v":10,"t":"Fadhili na kweli zimekutana, Haki na amani zimehusiana."},{"v":11,"t":"Kweli imechipuka katika nchi, Haki imechungulia kutoka mbinguni."},{"v":12,"t":"Naam, Bwana atatoa kilicho chema, Na nchi yetu itatoa mazao yake."},{"v":13,"t":"Haki itakwenda mbele zake, Nayo itazifanya hatua zake kuwa njia."}]},{"c":86,"verses":[{"v":1,"t":"Ee Bwana, utege sikio lako unijibu, Maana mimi ni maskini na mhitaji"},{"v":2,"t":"Unihifadhi nafsi yangu, Maana mimi ni mcha Mungu. Wewe uliye Mungu wangu, Umwokoe mtumishi wako anayekutumaini."},{"v":3,"t":"Wewe, Bwana, unifadhili, Maana nakulilia Wewe mchana kutwa."},{"v":4,"t":"Uifurahishe nafsi ya mtumishi wako, Maana nafsi yangu nakuinulia Wewe, Bwana."},{"v":5,"t":"Kwa maana Wewe, Bwana, U mwema, Umekuwa tayari kusamehe, Na mwingi wa fadhili, Kwa watu wote wakuitao."},{"v":6,"t":"Ee Bwana, uyasikie maombi yangu; Uisikilize sauti ya dua zangu."},{"v":7,"t":"Siku ya mateso yangu nitakuita, Kwa maana utaniitikia."},{"v":8,"t":"Katikati ya miungu hakuna kama Wewe, Bwana, Wala matendo mfano wa matendo yako."},{"v":9,"t":"Mataifa yote uliowafanya watakuja; Watakusujudia Wewe, Bwana, Watalitukuza jina lako;"},{"v":10,"t":"Kwa kuwa ndiwe uliye mkuu, Wewe ndiwe mfanya miujiza, Ndiwe Mungu peke yako."},{"v":11,"t":"Ee Bwana, unifundishe njia yako; Nitakwenda katika kweli yako; Moyo wangu na ufurahi kulicha jina lako;"},{"v":12,"t":"Nitakusifu Wewe, Bwana, Mungu wangu, Kwa moyo wangu wote, Nitalitukuza jina lako milele."},{"v":13,"t":"Maana fadhili zako kwangu ni nyingi sana; Umeiopoa nafsi yangu na kuzimu."},{"v":14,"t":"Ee Mungu, wenye kiburi wamenishambulia; Mkutano wa wakatili wamenitafuta roho. Wala hawakukuweka Wewe Mbele ya macho yao."},{"v":15,"t":"Lakini Wewe, Bwana, U Mungu wa rehema na neema, Mvumilivu, mwingi wa fadhili na kweli."},{"v":16,"t":"Unielekee na kunifadhili mimi; Mpe mtumishi wako nguvu zako, Umwokoe mwana wa mjakazi wako."},{"v":17,"t":"Unifanyie ishara ya wema, Wanichukiao waione na kuaibishwa. Kwa kuwa Wewe, Bwana, Umenisaidia na kunifariji."}]},{"c":87,"verses":[{"v":1,"t":"Msingi wake upo Juu ya milima mitakatifu."},{"v":2,"t":"Bwana ayapenda malango ya Sayuni Kuliko maskani zote za Yakobo."},{"v":3,"t":"Umetajwa kwa mambo matukufu, Ee Mji wa Mungu."},{"v":4,"t":"Nitataja Rahabu na Babeli Miongoni mwao wanaonijua. Tazama Filisti, na Tiro, na Kushi; Huyu alizaliwa humo."},{"v":5,"t":"Naam, mintarafu Sayuni itasemwa, Huyu na huyu alizaliwa humo. Na Yeye Aliye juu Ataufanya imara."},{"v":6,"t":"Bwana atahesabu, awaandikapo mataifa, Huyu alizaliwa humo."},{"v":7,"t":"Waimbao na wachezao na waseme, Visima vyangu vyote vimo mwako."}]},{"c":88,"verses":[{"v":1,"t":"Ee Bwana, Mungu wa wokovu wangu Mchana na usiku nimelia mbele zako."},{"v":2,"t":"Maombi yangu yafike mbele zako, Uutegee ukelele wangu sikio lako."},{"v":3,"t":"Maana nafsi yangu imeshiba taabu, Na uhai wangu umekaribia kuzimu."},{"v":4,"t":"Nimehesabiwa pamoja nao washukao shimoni; Nimekuwa kama mtu asiye na msaada."},{"v":5,"t":"Miongoni mwao waliokufa nimetupwa, Kama waliouawa walalao makaburini. Hao ambao Wewe huwakumbuki tena, Wametengwa mbali na mkono wako."},{"v":6,"t":"Mimi umenilaza katika shimo la chini, Katika mahali penye giza vilindini."},{"v":7,"t":"Ghadhabu yako imenilemea, Umenitesa kwa mawimbi yako yote."},{"v":8,"t":"Wanijuao umewatenga nami; Umenifanya kuwa chukizo kwao; Nimefungwa wala siwezi kutoka."},{"v":9,"t":"Jicho langu limefifia kwa ajili ya mateso Bwana, nimekuita kila siku; Nimekunyoshea Wewe mikono yangu."},{"v":10,"t":"Wafu je! Utawafanyia miujiza? Au waliofariki watasimama na kukuhimidi?"},{"v":11,"t":"Fadhili zako zitasimuliwa kaburini? Au uaminifu wako katika uharibifu?"},{"v":12,"t":"Miujiza yako itajulikana gizani? Au haki yako katika nchi ya usahaulifu?"},{"v":13,"t":"Lakini mimi nimekulilia Wewe, Bwana, Na asubuhi maombi yangu yatakuwasilia."},{"v":14,"t":"Bwana, kwa nini kuitupa nafsi yangu, Na kunificha uso wako?"},{"v":15,"t":"Nateswa mimi hali ya kufa tangu ujana, Nimevumilia vitisho vyako na kufadhaika."},{"v":16,"t":"Hasira zako kali zimepita juu yangu, Maogofyo yako yameniangamiza."},{"v":17,"t":"Yamenizunguka kama maji mchana kutwa, Yamenisonga yote pamoja."},{"v":18,"t":"Mpenzi na rafiki umewatenga nami, Nao wanijuao wamo gizani."}]},{"c":89,"verses":[{"v":1,"t":"Fadhili za Bwana nitaziimba milele; Kwa kinywa changu nitavijulisha vizazi vyote uaminifu wako."},{"v":2,"t":"Maana nimesema, Fadhili zitajengwa milele; Katika mbingu utauthibitisha uaminifu wako."},{"v":3,"t":"Nimefanya agano na mteule wangu, Nimemuapia Daudi, mtumishi wangu."},{"v":4,"t":"Wazao wako nitawafanya imara milele, Nitakijenga kiti chako cha enzi hata milele."},{"v":5,"t":"Ee Bwana, mbingu zitayasifu maajabu yako, Uaminifu wako katika kusanyiko la watakatifu."},{"v":6,"t":"Maana ni nani katika mbingu awezaye kulinganishwa na Bwana? Ni nani afananaye na Bwana miongoni mwa malaika?"},{"v":7,"t":"Mungu huogopwa sana barazani pa watakatifu, Ni wa kuhofiwa kuliko wote wanaomzunguka."},{"v":8,"t":"Bwana, Mungu wa majeshi, Ni nani aliye hodari kama Wewe, Ee YAHU? Na uaminifu wako unakuzunguka."},{"v":9,"t":"Wewe ndiwe ukitawalaye kiburi cha bahari. Mawimbi yake yainukapo wayatuliza Wewe."},{"v":10,"t":"Ndiwe uliyemseta Rahabu akawa kama aliyeuawa, Kwa mkono hodari umewatawanya wakuchukiao."},{"v":11,"t":"Mbingu ni mali yako, nchi nayo ni mali yako, Ulimwengu na vyote viujazavyo Ndiwe uliyeupiga msingi wake."},{"v":12,"t":"Kaskazini na kusini ndiwe uliyeziumba, Tabori na Hermoni hulifurahia jina lako."},{"v":13,"t":"Mkono wako ni mkono wenye uweza, Mkono wako una nguvu, Mkono wako wa kuume umetukuka."},{"v":14,"t":"Haki na hukumu ndio msingi wa kiti chako, Fadhili na kweli zahudhuria mbele za uso wako."},{"v":15,"t":"Heri watu wale waijuao sauti ya shangwe, Ee Bwana, huenenda katika nuru ya uso wako."},{"v":16,"t":"Kwa jina lako hufurahi mchana kutwa, Na kwa haki yako hutukuzwa."},{"v":17,"t":"Maana fahari ya nguvu zao ni Wewe, Na kwa radhi yako pembe yetu itatukuka."},{"v":18,"t":"Maana ngao yetu ina Bwana, Na mfalme wetu ni wake Mtakatifu wa Israeli."},{"v":19,"t":"Ndipo ulipowaambia watakatifu wako kwa njozi, Ukasema, nimempa aliye hodari msaada; Nimemtukuza aliyechaguliwa miongoni mwa watu."},{"v":20,"t":"Nimemwona Daudi, mtumishi wangu, Nimempaka mafuta yangu matakatifu."},{"v":21,"t":"Ambaye mkono wangu utakuwa thabiti kwake, Na mkono wangu utamtia nguvu."},{"v":22,"t":"Adui hatamwonea, Wala mwana wa uovu hatamtesa."},{"v":23,"t":"Bali nitawaponda watesi wake mbele yake, Nitawapiga wanaomchukia."},{"v":24,"t":"Uaminifu wangu na fadhili zangu atakuwa nazo, Na kwa jina langu pembe yake itatukuka."},{"v":25,"t":"Nitaweka mkono wake juu ya bahari, Na mkono wake wa kuume juu ya mito."},{"v":26,"t":"Yeye ataniita, Wewe baba yangu, Mungu wangu na mwamba wa wokovu wangu."},{"v":27,"t":"Nami nitamjalia kuwa mzaliwa wangu wa kwanza, Kuwa juu sana kuliko wafalme wa dunia."},{"v":28,"t":"Hata milele nitamwekea fadhili zangu, Na agano langu litafanyika amini kwake."},{"v":29,"t":"Wazao wake nao nitawadumisha milele, Na kiti chake cha enzi kama siku za mbingu."},{"v":30,"t":"Wanawe wakiiacha sheria yangu, Wasiende katika hukumu zangu,"},{"v":31,"t":"Wakizihalifu amri zangu, Wasiyashike maagizo yangu,"},{"v":32,"t":"Basi, nitawarudi makosa yao kwa fimbo, Na uovu wao kwa mapigo."},{"v":33,"t":"Lakini fadhili zangu sitamwondolea yeye, Wala sitafanya uaminifu wangu kuwa uongo."},{"v":34,"t":"Mimi sitalihalifu agano langu, Sitalibadili neno lililotoka midomoni mwangu."},{"v":35,"t":"Neno moja nimeliapa kwa utakatifu wangu, Hakika sitamwambia Daudi uongo,"},{"v":36,"t":"Wazao wake watadumu milele, Na kiti chake kitakuwa kama jua mbele zangu."},{"v":37,"t":"Kitathibitika milele kama mwezi; Shahidi aliye mbinguni mwaminifu."},{"v":38,"t":"Walakini Wewe umemtupa na kumkataa, Umemghadhibikia masihi wako."},{"v":39,"t":"Umechukizwa na agano la mtumishi wako, Umeinajisi taji yake na kuitupa chini."},{"v":40,"t":"Umeyabomoa maboma yake yote, Umezifanya ngome zake kuwa magofu."},{"v":41,"t":"Wote wapitao njiani wanateka mali zake; Amekuwa laumu kwa jirani zake;"},{"v":42,"t":"Umeutukuza mkono wa kuume wa watesi wake; Umewafurahisha wote wanaomchukia."},{"v":43,"t":"Pia umeurudisha nyuma ukali wa upanga wake; Wala hukumsimamisha vitani."},{"v":44,"t":"Umeikomesha fahari yake; Kiti chake cha enzi umekitupa chini."},{"v":45,"t":"Umezipunguza siku za ujana wake; Umemvika aibu."},{"v":46,"t":"Ee Bwana, hata lini? Utajificha hata milele? Ghadhabu yako itawaka kama moto?"},{"v":47,"t":"Ukumbuke jinsi mimi nisivyo wa kudumu; Kwa ubatili gani umeiumba jamii ya wanadamu!"},{"v":48,"t":"Ni mwanamume gani atakayeishi asione mauti, Atakayejiokoa nafsi yake na mkono wa kuzimu?"},{"v":49,"t":"Bwana, zi wapi fadhili zako za kwanza, Ulizomwapia Daudi kwa uaminifu wako?"},{"v":50,"t":"Ee Bwana, ukumbuke, Wanavyosimangwa watumishi wako; Jinsi ninavyostahimili kifuani mwangu Masimango ya watu wengi."},{"v":51,"t":"Ambayo adui zako wamesimanga, Ee Bwana, Naam, wamezisimanga hatua za masihi wako."},{"v":52,"t":"Na ahimidiwe Bwana milele. Amina na Amina."}]},{"c":90,"verses":[{"v":1,"t":"Wewe, Bwana, umekuwa makao yetu, Kizazi baada ya kizazi."},{"v":2,"t":"Kabla haijazaliwa milima, wala hujaiumba dunia, Na tangu milele hata milele ndiwe Mungu."},{"v":3,"t":"Wamrudisha mtu mavumbini, usemapo, Rudini, enyi wanadamu."},{"v":4,"t":"Maana miaka elfu machoni pako Ni kama siku ya jana ikiisha kupita, Na kama kesha la usiku."},{"v":5,"t":"Wawagharikisha, huwa kama usingizi, Asubuhi huwa kama majani yameayo."},{"v":6,"t":"Asubuhi yachipuka na kumea, Jioni yakatika na kukauka."},{"v":7,"t":"Maana tumetoweshwa kwa hasira yako, Na kwa ghadhabu yako tumefadhaishwa."},{"v":8,"t":"Umeyaweka maovu yetu mbele zako, Siri zetu katika mwanga wa uso wako."},{"v":9,"t":"Maana siku zetu zote zimepita katika hasira yako, Tumetowesha miaka yetu kama kite."},{"v":10,"t":"Siku za miaka yetu ni miaka sabini, Na ikiwa tuna nguvu miaka themanini; Na kiburi chake ni taabu na ubatili, Maana chapita upesi tukatokomea mara."},{"v":11,"t":"Ni nani aujuaye uweza wa hasira yako? Na ghadhabu yako kama ipasavyo kicho chako?"},{"v":12,"t":"Basi, utujulishe kuzihesabu siku zetu, Tujipatie moyo wa hekima."},{"v":13,"t":"Ee Bwana urudi, hata lini? Uwahurumie watumishi wako."},{"v":14,"t":"Utushibishe asubuhi kwa fadhili zako, Nasi tutashangilia na kufurahi siku zetu zote."},{"v":15,"t":"Utufurahishe kwa kadiri ya siku ulizotutesa, Kama miaka ile tuliyoona mabaya."},{"v":16,"t":"Matendo yako na yaonekane kwa watumishi wako, Na adhama yako kwa watoto wao."},{"v":17,"t":"Na uzuri wa Bwana, Mungu wetu, uwe juu yetu, Na kazi ya mikono yetu utufanyie thabiti, Naam, kazi ya mikono yetu uithibitishe."}]},{"c":91,"verses":[{"v":1,"t":"Aketiye mahali pa siri pake Aliye juu Atakaa katika uvuli wake Mwenyezi."},{"v":2,"t":"Nitasema, Bwana ndiye kimbilio langu na ngome yangu, Mungu wangu nitakayemtumaini."},{"v":3,"t":"Maana Yeye atakuokoa na mtego wa mwindaji, Na katika tauni iharibuyo."},{"v":4,"t":"Kwa manyoya yake atakufunika, Chini ya mbawa zake utapata kimbilio; Uaminifu wake ni ngao na kigao."},{"v":5,"t":"Hutaogopa hofu ya usiku, Wala mshale urukao mchana,"},{"v":6,"t":"Wala tauni ipitayo gizani, Wala uele uharibuo adhuhuri,"},{"v":7,"t":"Ijapo watu elfu waanguka ubavuni pako. Naam, kumi elfu mkono wako wa kuume! Hata hivyo hautakukaribia wewe."},{"v":8,"t":"Ila kwa macho yako utatazama, Na kuyaona malipo ya wasio haki."},{"v":9,"t":"Kwa kuwa Wewe Bwana ndiwe kimbilio langu; Umemfanya Aliye juu kuwa makao yako."},{"v":10,"t":"Mabaya hayatakupata wewe, Wala tauni haitaikaribia hema yako."},{"v":11,"t":"Kwa kuwa atakuagizia malaika zake Wakulinde katika njia zako zote."},{"v":12,"t":"Mikononi mwao watakuchukua, Usije ukajikwaa mguu wako katika jiwe."},{"v":13,"t":"Utawakanyaga simba na nyoka, Mwana-simba na joka utawaseta kwa miguu."},{"v":14,"t":"Kwa kuwa amekaza kunipenda Nitamwokoa; na kumweka palipo juu, Kwa kuwa amenijua Jina langu."},{"v":15,"t":"Ataniita nami nitamwitikia; Nitakuwa pamoja naye taabuni, Nitamwokoa na kumtukuza;"},{"v":16,"t":"Kwa siku nyingi nitamshibisha, Nami nitamwonyesha wokovu wangu."}]},{"c":92,"verses":[{"v":1,"t":"Ni neno jema kumshukuru Bwana, Na kuliimbia jina lako, Ee Uliye juu."},{"v":2,"t":"Kuzitangaza rehema zako asubuhi, Na uaminifu wako wakati wa usiku."},{"v":3,"t":"Kwa chombo chenye nyuzi kumi, Na kwa kinanda, Na kwa mlio wa kinubi."},{"v":4,"t":"Kwa kuwa umenifurahisha, Bwana, Kwa kazi yako; nitashangilia Kwa ajili ya matendo ya mikono yako."},{"v":5,"t":"Ee Bwana, jinsi yalivyo makuu matendo yako! Mawazo yako ni mafumbo makubwa."},{"v":6,"t":"Mtu mjinga hayatambui hayo, Wala mpumbavu hayafahamu."},{"v":7,"t":"Wasio haki wakichipuka kama majani Na wote watendao maovu wakistawi. Ni kwa kusudi waangamizwe milele;"},{"v":8,"t":"Bali Wewe, Bwana, U Mtukufu hata milele."},{"v":9,"t":"Maana hao adui zako, Ee Bwana, Hao adui zako watapotea, Na watendao maovu watatawanyika wote pia."},{"v":10,"t":"Bali pembe yangu umeiinua kama pembe ya nyati, Nimepakwa mafuta mabichi."},{"v":11,"t":"Na jicho langu limewatazama walioniotea, Sikio langu limesikia habari za waovu walionishambulia."},{"v":12,"t":"Mwenye haki atasitawi kama mtende, Atakua kama mwerezi wa Lebanoni."},{"v":13,"t":"Waliopandwa katika nyumba ya Bwana Watasitawi katika nyua za Mungu wetu."},{"v":14,"t":"Watazaa matunda hadi wakati wa uzee, Watajaa utomvu, watakuwa na ubichi."},{"v":15,"t":"Watangaze ya kuwa Bwana ni mwenye adili, Mwamba wangu, ndani yake hamna udhalimu."}]},{"c":93,"verses":[{"v":1,"t":"Bwana ametamalaki, amejivika adhama, Bwana amejivika, na kujikaza nguvu. Naam, ulimwengu umethibitika usitikisike;"},{"v":2,"t":"Kiti chako kimekuwa thabiti tokea zamani; Wewe ndiwe uliye tangu milele."},{"v":3,"t":"Ee Bwana, mito imepaza, Mito imepaza sauti zake, Mito imepaza uvumi wake."},{"v":4,"t":"Kupita sauti ya maji mengi, maji makuu, Kupita mawimbi ya bahari yaumkayo, Bwana Aliye juu ndiye mwenye ukuu."},{"v":5,"t":"Shuhuda zako ni amini sana; Utakatifu ndio uifaao nyumba yako, Ee Bwana, milele na milele."}]},{"c":94,"verses":[{"v":1,"t":"Ee Bwana, Mungu wa kisasi, Mungu wa kisasi, uangaze,"},{"v":2,"t":"Mwenye kuihukumu nchi, ujitukuze, Uwape wenye kiburi stahili zao."},{"v":3,"t":"Bwana, hata lini wasio haki, Hata lini wasio haki watashangilia?"},{"v":4,"t":"Je! Wote watendao uovu watatoa maneno, Na kusema majivuno, na kufanya kiburi?"},{"v":5,"t":"Ee Bwana, wanawaseta watu wako; Wanautesa urithi wako;"},{"v":6,"t":"Wanamwua mjane na mgeni; Wanawafisha yatima."},{"v":7,"t":"Nao husema, Bwana haoni; Mungu wa Yakobo hafikiri."},{"v":8,"t":"Enyi wajinga miongoni mwa watu, fikirini; Enyi wapumbavu, lini mtakapopata akili?"},{"v":9,"t":"Aliyelitia sikio mahali pake asisikie? Aliyelifanya jicho asione?"},{"v":10,"t":"Awaadibuye mataifa asikemee? Amfundishaye mwanadamu asijue?"},{"v":11,"t":"Bwana anajua mawazo ya mwanadamu, Ya kuwa ni ubatili."},{"v":12,"t":"Ee Bwana, heri mtu yule umwadibuye, Na kumfundisha kwa sheria yako;"},{"v":13,"t":"Upate kumstarehesha siku za mabaya, Hata asiye haki atakapochimbiwa shimo."},{"v":14,"t":"Kwa kuwa Bwana hatawatupa watu wake, Wala hutauacha urithi wake,"},{"v":15,"t":"Maana hukumu itairejea haki, Na wote walio wanyofu wa moyo wataifuata."},{"v":16,"t":"Ni nani atakayesimama Kwa ajili yangu juu ya wabaya? Ni nani atakayenisaidia Juu yao wafanyao maovu?"},{"v":17,"t":"Kama Bwana asingalikuwa msaada wangu, Nafsi yangu kwa upesi ingalikaa penye kimya."},{"v":18,"t":"Niliposema, Mguu wangu unateleza; Ee Bwana, fadhili zako zilinitegemeza."},{"v":19,"t":"Katika wingi wa mawazo ya moyoni mwangu, Faraja zako zaifurahisha roho yangu."},{"v":20,"t":"Je! Kiti cha udhalimu kishirikiane nawe, Kitungacho madhara kwa njia ya sheria?"},{"v":21,"t":"Huishambulia nafsi yake mwenye haki, Na kuihukumu damu isiyo na hatia."},{"v":22,"t":"Lakini Bwana amekuwa ngome kwangu, Na Mungu wangu mwamba wangu wa kukimbilia."},{"v":23,"t":"Naye atawarudishia uovu wao, Atawaangamiza katika ubaya wao, Naam, Bwana, Mungu wetu, atawaangamiza."}]},{"c":95,"verses":[{"v":1,"t":"Njoni, tumwimbie Bwana, Tumfanyie shangwe mwamba wa wokovu wetu."},{"v":2,"t":"Tuje mbele zake kwa shukrani, Tumfanyie shangwe kwa zaburi."},{"v":3,"t":"Kwa kuwa Bwana ni Mungu mkuu, Na Mfalme mkuu juu ya miungu yote."},{"v":4,"t":"Mkononi mwake zimo bonde za dunia, Hata vilele vya milima ni vyake."},{"v":5,"t":"Bahari ni yake, ndiye aliyeifanya, Na mikono yake iliumba nchi kavu."},{"v":6,"t":"Njoni, tuabudu, tusujudu, Tupige magoti mbele za Bwana aliyetuumba."},{"v":7,"t":"Kwa maana ndiye Mungu wetu, Na sisi tu watu wa malisho yake, Na kondoo za mkono wake. Ingekuwa heri leo msikie sauti yake!"},{"v":8,"t":"Msifanye migumu mioyo yenu; Kama vile huko Meriba Kama siku ya Masa jangwani."},{"v":9,"t":"Hapo waliponijaribu baba zenu, Wakanipima, wakayaona matendo yangu."},{"v":10,"t":"Miaka arobaini nalihuzunika na kizazi kile, Nikasema, Hao ni watu waliopotoka mioyo, Hawakuzijua njia zangu."},{"v":11,"t":"Nikaapa kwa hasira yangu Wasiingie rahani mwangu."}]},{"c":96,"verses":[{"v":1,"t":"Mwimbieni Bwana wimbo mpya, Mwimbieni Bwana, nchi yote."},{"v":2,"t":"Mwimbieni Bwana, libarikini jina lake, Tangazeni wokovu wake siku kwa siku."},{"v":3,"t":"Wahubirini mataifa habari za utukufu wake, Na watu wote habari za maajabu yake."},{"v":4,"t":"Kwa kuwa Bwana ni mkuu mwenye kusifiwa sana. Na wa kuhofiwa kuliko miungu yote."},{"v":5,"t":"Maana miungu yote ya watu si kitu, Lakini Bwana ndiye aliyezifanya mbingu."},{"v":6,"t":"Heshima na adhama ziko mbele zake, Nguvu na uzuri zimo katika patakatifu pake."},{"v":7,"t":"Mpeni Bwana, enyi jamaa za watu, Mpeni Bwana utukufu na nguvu."},{"v":8,"t":"Mpeni Bwana utukufu wa jina lake, Leteni sadaka mkaziingie nyua zake."},{"v":9,"t":"Mwabuduni Bwana kwa uzuri wa utakatifu, Tetemekeni mbele zake, nchi yote."},{"v":10,"t":"Semeni katika mataifa, Bwana ametamalaki; Naam, ulimwengu umethibitika usitikisike, Atawahukumu watu kwa adili."},{"v":11,"t":"Mbingu na zifurahi, nchi na ishangilie, Bahari na ivume na vyote viijazavyo,"},{"v":12,"t":"Mashamba na yashangilie, na vyote vilivyomo, Ndipo miti yote ya mwituni iimbe kwa furaha;"},{"v":13,"t":"Mbele za Bwana, kwa maana anakuja, Kwa maana anakuja aihukumu nchi. Atauhukumu ulimwengu kwa haki, Na mataifa kwa uaminifu wake."}]},{"c":97,"verses":[{"v":1,"t":"Bwana ametamalaki, nchi na ishangilie, Visiwa vingi na vifurahi."},{"v":2,"t":"Mawingu na giza vyamzunguka, Haki na hukumu ndio msingi wa kiti chake."},{"v":3,"t":"Moto hutangulia mbele zake, Nao huwateketeza watesi wake pande zote."},{"v":4,"t":"Umeme wake uliuangaza ulimwengu, Nchi ikaona ikatetemeka."},{"v":5,"t":"Milima iliyeyuka kama nta mbele za Bwana, Mbele za Bwana wa dunia yote."},{"v":6,"t":"Mbingu zimetangaza haki yake, Na watu wote wameuona utukufu wake."},{"v":7,"t":"Na waaibishwe wote waabuduo sanamu, Wajivunao kwa vitu visivyofaa; Enyi miungu yote, msujuduni Yeye."},{"v":8,"t":"Sayuni imesikia na kufurahi, Binti za Yuda walishangilia, Kwa sababu ya hukumu zako, Ee Bwana."},{"v":9,"t":"Maana Wewe, Bwana, ndiwe Uliye juu, Juu sana kuliko nchi yote; Umetukuka sana juu ya miungu yote."},{"v":10,"t":"Enyi mmpendao Bwana, uchukieni uovu; Huwalinda nafsi zao watauwa wake, Na kuwaokoa na mkono wa wasio haki."},{"v":11,"t":"Nuru imemzukia mwenye haki, Na furaha wanyofu wa moyo."},{"v":12,"t":"Enyi wenye haki, mmfurahieni Bwana, Na kulishukuru jina lake takatifu."}]},{"c":98,"verses":[{"v":1,"t":"Mwimbieni Bwana wimbo mpya, Kwa maana ametenda mambo ya ajabu. Mkono wa kuume wake mwenyewe, Mkono wake mtakatifu umemtendea wokovu."},{"v":2,"t":"Bwana ameufunua wokovu wake, Machoni pa mataifa ameidhihirisha haki yake."},{"v":3,"t":"Amezikumbuka rehema zake, Na uaminifu wake kwa nyumba ya Israeli. Miisho yote ya dunia imeuona Wokovu wa Mungu wetu."},{"v":4,"t":"Mshangilieni Bwana, nchi yote, Inueni sauti, imbeni kwa furaha, imbeni zaburi."},{"v":5,"t":"Mwimbieni Bwana zaburi kwa kinubi, Kwa kinubi na sauti ya zaburi."},{"v":6,"t":"Kwa panda na sauti ya baragumu. Shangilieni mbele za Mfalme, Bwana."},{"v":7,"t":"Bahari na ivume na vyote viijazavyo, Ulimwengu nao wanaokaa ndani yake."},{"v":8,"t":"Mito na ipige makofi, Milima na iimbe pamoja kwa furaha."},{"v":9,"t":"Mbele za Bwana; Kwa maana anakuja aihukumu nchi. Atauhukumu ulimwengu kwa haki, Na mataifa kwa adili."}]},{"c":99,"verses":[{"v":1,"t":"Bwana ametamalaki, mataifa wanatetemeka; Ameketi juu ya makerubi, nchi inatikisika."},{"v":2,"t":"Bwana katika Sayuni ni mkuu, Naye ametukuka juu ya mataifa yote."},{"v":3,"t":"Na walishukuru jina lake kuu la kuhofiwa; Ndiye mtakatifu."},{"v":4,"t":"Nguvu za mfalme nazo zapenda hukumu; Wewe ndiwe uliyeithibitisha adili; Ulifanya hukumu na haki katika Yakobo."},{"v":5,"t":"Mtukuzeni Bwana, Mungu wetu; Sujuduni penye kiti cha miguu yake; Ndiye mtakatifu."},{"v":6,"t":"Musa na Haruni miongoni mwa makuhani wake, Na Samweli miongoni mwao waliitiao jina lake, Walipomwita Bwana aliwaitikia;"},{"v":7,"t":"Katika nguzo ya wingu alikuwa akisema nao. Walishika shuhuda zake na amri aliyowapa."},{"v":8,"t":"Ee Bwana, Mungu wetu, ndiwe uliyewajibu; Ulikuwa kwao Mungu mwenye kusamehe Ingawa uliwapatiliza matendo yao."},{"v":9,"t":"Mtukuzeni Bwana, Mungu wetu; Sujuduni mkiukabili mlima wake mtakatifu; Maana Bwana, Mungu wetu, ndiye mtakatifu."}]},{"c":100,"verses":[{"v":1,"t":"Mfanyieni Bwana shangwe, dunia yote;"},{"v":2,"t":"Mtumikieni Bwana kwa furaha; Njoni mbele zake kwa kuimba;"},{"v":3,"t":"Jueni kwamba Bwana ndiye Mungu; Ndiye aliyetuumba na sisi tu watu wake; Tu watu wake, na kondoo wa malisho yake."},{"v":4,"t":"Ingieni malangoni mwake kwa kushukuru; Nyuani mwake kwa kusifu; Mshukuruni, lihimidini jina lake;"},{"v":5,"t":"Kwa kuwa Bwana ndiye mwema; Rehema zake ni za milele; Na uaminifu wake vizazi na vizazi."}]},{"c":101,"verses":[{"v":1,"t":"Rehema na hukumu nitaziimba, Ee Bwana, nitakuimbia zaburi."},{"v":2,"t":"Nitaiangalia njia ya unyofu; Utakuja kwangu lini? Nitakwenda kwa unyofu wa moyo Ndani ya nyumba yangu."},{"v":3,"t":"Sitaweka mbele ya macho yangu Neno la uovu. Kazi yao waliopotoka naichukia, Haitaambatana nami."},{"v":4,"t":"Moyo wa ukaidi utaondoka kwangu, Lililo ovu sitalijua."},{"v":5,"t":"Amsingiziaye jirani yake kwa siri, Huyo nitamharibu. Mwenye macho ya kiburi na moyo wa majivuno, Huyo sitavumilia naye."},{"v":6,"t":"Macho yangu yatawaelekea waaminifu katika nchi, Hao wakae nami. Yeye aendaye katika njia kamilifu, Ndiye atakayenitumikia."},{"v":7,"t":"Hatakaa ndani ya nyumba yangu Mtu atendaye hila. Asemaye uongo hatathibitika Mbele ya macho yangu."},{"v":8,"t":"Asubuhi hata asubuhi nitawaharibu Wabaya wote wa nchi. Niwatenge wote watendao uovu Na mji wa Bwana."}]},{"c":102,"verses":[{"v":1,"t":"Ee Bwana, usikie kuomba kwangu, Kilio changu kikufikie."},{"v":2,"t":"Usinifiche uso wako siku ya shida yangu, Unitegee sikio lako, siku niitapo unijibu upesi."},{"v":3,"t":"Maana siku zangu zinatoweka kama moshi, Na mifupa yangu inateketea kama kinga."},{"v":4,"t":"Moyo wangu umepigwa kama majani na kukauka, Naam, ninasahau kula chakula changu."},{"v":5,"t":"Kwa ajili ya sauti ya kuugua kwangu Mifupa yangu imegandamana na nyama yangu."},{"v":6,"t":"Nimekuwa kama mwari nyuni wa jangwani, Na kufanana na bundi wa mahameni."},{"v":7,"t":"Nakesha, tena nimekuwa kama shomoro Aliye peke yake juu ya nyumba."},{"v":8,"t":"Adui zangu wananilaumu mchana kutwa; Wanaonichukia kana kwamba wana wazimu Huapa kwa kunitaja mimi."},{"v":9,"t":"Maana nimekula majivu kama chakula, Na kukichanganya kinywaji changu na machozi."},{"v":10,"t":"Kwa sababu ya ghadhabu yako na hasira yako; Maana umeniinua na kunitupilia mbali."},{"v":11,"t":"Siku zangu zi kama kivuli kilichotandaa, Nami ninanyauka kama majani."},{"v":12,"t":"Bali Wewe, Bwana utaketi ukimiliki milele, Na kumbukumbu lako kizazi hata kizazi."},{"v":13,"t":"Wewe mwenyewe utasimama, Na kuirehemu Sayuni, Kwa maana ndio wakati wa kuihurumia, Naam, majira yaliyoamriwa yamewadia."},{"v":14,"t":"Maana watumishi wako wameyaridhia mawe yake, Na kuyaonea huruma mavumbi yake."},{"v":15,"t":"Kisha mataifa wataliogopa jina la Bwana, Na wafalme wote wa dunia utukufu wako;"},{"v":16,"t":"Bwana atakapokuwa ameijenga Sayuni, Atakapoonekana katika utukufu wake,"},{"v":17,"t":"Atakapoyaelekea maombi yake aliye mkiwa, Asiyadharau maombi yao."},{"v":18,"t":"Kizazi kitakachokuja kitaandikiwa hayo, Na watu watakaoumbwa watamsifu Bwana."},{"v":19,"t":"Maana ametazama toka patakatifu pake pa juu, Toka mbinguni Bwana ameiangalia nchi,"},{"v":20,"t":"Ili akusikie kuugua kwake aliyefungwa, Na kuwafungua walioandikiwa kufa."},{"v":21,"t":"Watu walitangaze jina la Bwana katika Sayuni, Na sifa zake katika Yerusalemu,"},{"v":22,"t":"Pindi mataifa watapokusanyika pamoja, Falme nazo ili kumtumikia Bwana."},{"v":23,"t":"Amezipunguza nguvu zangu njiani; Amezifupisha siku zangu."},{"v":24,"t":"Nitasema, Ee Mungu wangu, usiniondoe katikati ya siku zangu; Miaka yako ni tangu kizazi hata kizazi."},{"v":25,"t":"Hapo mwanzo uliutia msingi wa nchi, Na mbingu ni kazi ya mikono yako."},{"v":26,"t":"Hizi zitaharibika, bali Wewe utadumu Naam, hizi zitachakaa kama nguo; Na kama mavazi utazibadilisha, Nazo zitabadilika."},{"v":27,"t":"Lakini Wewe U Yeye yule; Na miaka yako haitakoma."},{"v":28,"t":"Wana wa watumishi wako watakaa, Na wazao wao wataimarishwa mbele zako."}]},{"c":103,"verses":[{"v":1,"t":"Ee nafsi yangu, umhimidi Bwana. Naam, vyote vilivyo ndani yangu Vilihimidi jina lake takatifu."},{"v":2,"t":"Ee nafsi yangu, umhimidi Bwana, Wala usizisahau fadhili zake zote."},{"v":3,"t":"Akusamehe maovu yako yote, Akuponya magonjwa yako yote,"},{"v":4,"t":"Aukomboa uhai wako na kaburi, Akutia taji ya fadhili na rehema,"},{"v":5,"t":"Aushibisha mema uzee wako, Ujana wako ukarejezwa kama tai;"},{"v":6,"t":"Bwana ndiye afanyaye mambo ya haki, Na hukumu kwa wote wanaoonewa."},{"v":7,"t":"Alimjulisha Musa njia zake, Wana wa Israeli matendo yake."},{"v":8,"t":"Bwana amejaa huruma na neema, Haoni hasira upesi, ni mwingi wa fadhili."},{"v":9,"t":"Yeye hatateta sikuzote, Wala hatashika hasira yake milele."},{"v":10,"t":"Hakututenda sawasawa na hatia zetu, Wala hakutulipa kwa kadiri ya maovu yetu."},{"v":11,"t":"Maana mbingu zilivyoinuka juu ya nchi, Kadiri ile ile rehema zake ni kuu kwa wamchao."},{"v":12,"t":"Kama mashariki ilivyo mbali na magharibi, Ndivyo alivyoweka dhambi zetu mbali nasi."},{"v":13,"t":"Kama vile baba awahurumiavyo watoto wake, Ndivyo Bwana anavyowahurumia wamchao."},{"v":14,"t":"Kwa maana Yeye anatujua umbo letu, Na kukumbuka ya kuwa sisi tu mavumbi."},{"v":15,"t":"Mwanadamu siku zake zi kama majani; Kama ua la kondeni ndivyo asitawivyo."},{"v":16,"t":"Maana upepo hupita juu yake, kumbe haliko! Na mahali pake hapatalijua tena."},{"v":17,"t":"Bali fadhili za Bwana zina wamchao Tangu milele hata milele, Na haki yake ina wana wa wana;"},{"v":18,"t":"Maana, wale walishikao agano lake, Na kuyakumbuka maagizo yake ili wayafanye."},{"v":19,"t":"Bwana ameweka kiti chake cha enzi mbinguni, Na ufalme wake unavitawala vitu vyote."},{"v":20,"t":"Mhimidini Bwana, enyi malaika zake, Ninyi mlio hodari, mtendao neno lake, Mkiisikiliza sauti ya neno lake."},{"v":21,"t":"Mhimidini Bwana, enyi majeshi yake yote, Ninyi watumishi wake mfanyao mapenzi yake."},{"v":22,"t":"Mhimidini Bwana, enyi matendo yake yote, Mahali pote pa milki yake. Ee nafsi yangu, umhimidi Bwana."}]},{"c":104,"verses":[{"v":1,"t":"Ee nafsi yangu, umhimidi Bwana. Wewe, Bwana, Mungu wangu, Umejifanya mkuu sana; Umejivika heshima na adhama."},{"v":2,"t":"Umejivika nuru kama vazi; Umezitandika mbingu kama pazia;"},{"v":3,"t":"Na kuziweka nguzo za orofa zake majini. Huyafanya mawingu kuwa gari lake, Na kwenda juu ya mabawa ya upepo,"},{"v":4,"t":"Huwafanya malaika zake kuwa pepo, Na watumishi wake kuwa moto wa miali."},{"v":5,"t":"Uliiweka nchi juu ya misingi yake, Isitikisike milele."},{"v":6,"t":"Uliifunika kwa vilindi kama kwa vazi, Maji yalikuwa yakisimama juu ya milima."},{"v":7,"t":"Kwa kukemea kwako yakakimbia, Kwa sauti ya radi yako yakaenda zake kasi,"},{"v":8,"t":"Yakapanda milima, yakatelemka mabondeni, Mpaka mahali ulipoyatengenezea."},{"v":9,"t":"Umeweka mpaka yasiupite, Wala yasirudi kuifunikiza nchi."},{"v":10,"t":"Hupeleka chemchemi katika mabonde; Zapita kati ya milima;"},{"v":11,"t":"Zamnywesha kila mnyama wa kondeni; Punda mwitu huzima kiu yao."},{"v":12,"t":"Kandokando hukaa ndege wa angani; Kati ya matawi hutoa sauti zao."},{"v":13,"t":"Huinywesha milima toka orofa zake; Nchi imeshiba mazao ya kazi zako."},{"v":14,"t":"Huyameesha majani kwa makundi, Na maboga kwa matumizi ya mwanadamu; Ili atoe chakula katika nchi,"},{"v":15,"t":"Na divai imfurahishe mtu moyo wake. Aung'aze uso wake kwa mafuta, Na mkate umburudishe mtu moyo wake."},{"v":16,"t":"Miti ya Bwana nayo imeshiba, Mierezi ya Lebanoni aliyoipanda."},{"v":17,"t":"Ndimo ndege wafanyamo vitundu vyao, Na korongo, misunobari ni nyumba yake."},{"v":18,"t":"Milima mirefu ndiko waliko mbuzi wa mwitu, Na magenge ni kimbilio la wibari."},{"v":19,"t":"Aliufanya mwezi kwa ajili ya nyakati, Jua latambua kuchwa kwake."},{"v":20,"t":"Wewe hufanya giza, kukawa usiku, Ndipo atambaapo kila mnyama wa mwitu."},{"v":21,"t":"Wana-simba hunguruma wakitaka mawindo, Ili kutafuta chakula chao kwa Mungu."},{"v":22,"t":"Jua lachomoza, wanakwenda zao, Na kujilaza mapangoni mwao."},{"v":23,"t":"Mwanadamu atoka kwenda zake kazini, Na kwenye utumishi wake mpaka jioni."},{"v":24,"t":"Ee Bwana, jinsi yalivyo mengi matendo yako! Kwa hekima umevifanya vyote pia. Dunia imejaa mali zako."},{"v":25,"t":"Bahari iko kule, kubwa na upana, Ndimo mlimo viendavyo visivyohesabika, Viumbe hai vidogo kwa vikubwa."},{"v":26,"t":"Ndimo zipitamo merikebu, Ndimo alimo lewiathani uliyemwumba acheze humo."},{"v":27,"t":"Hao wote wanakungoja Wewe, Uwape chakula chao kwa wakati wake."},{"v":28,"t":"Wewe huwapa, Wao wanakiokota; Wewe waukunjua mkono wako, Wao wanashiba mema;"},{"v":29,"t":"Wewe wauficha uso wako, Wao wanafadhaika; Waiondoa pumzi yao, wanakufa, Na kuyarudia mavumbi yao,"},{"v":30,"t":"Waipeleka roho yako, wanaumbwa, Nawe waufanya upya uso wa nchi."},{"v":31,"t":"Utukufu wa Bwana na udumu milele; Bwana na ayafurahie matendo yake."},{"v":32,"t":"Aitazama nchi, inatetemeka; Aigusa milima, inatoka moshi."},{"v":33,"t":"Nitamwimbia Bwana maadamu ninaishi; Nitamshangilia Mungu wangu nikiwa hai;"},{"v":34,"t":"Kutafakari kwangu na kuwe kutamu kwake; Mimi nitamfurahia Bwana."},{"v":35,"t":"Wenye dhambi waangamizwe katika nchi, Watendao ubaya wasiwepo tena. Ee nafsi yangu, umhimidi Bwana."}]},{"c":105,"verses":[{"v":1,"t":"Haleluya. Mshukuruni Bwana,liitieni jina ,Wajulisheni watu matendo yake."},{"v":2,"t":"Mwimbieni, mwimbieni kwa zaburi, Zitafakarini ajabu zake zote."},{"v":3,"t":"Jisifuni kwa jina lake takatifu, Na ufurahi moyo wao wamtafutao Bwana."},{"v":4,"t":"Mtakeni Bwana na nguvu zake, Utafuteni uso wake sikuzote."},{"v":5,"t":"Zikumbukeni ajabu zake alizozifanya, Miujiza yake na hukumu za kinywa chake."},{"v":6,"t":"Enyi wazao wa Ibrahimu, mtumishi wake; Enyi wana wa Yakobo, wateule wake."},{"v":7,"t":"Yeye, Bwana, ndiye Mungu wetu; Duniani mwote mna hukumu zake."},{"v":8,"t":"Analikumbuka agano lake milele; Neno lile aliloviamuru vizazi elfu."},{"v":9,"t":"Agano alilofanya na Ibrahimu, Na uapo wake kwa Isaka."},{"v":10,"t":"Alilomthibitishia Yakobo liwe amri, Na Israeli liwe agano la milele."},{"v":11,"t":"Akisema, Nitakupa wewe nchi ya Kanaani, Iwe urithi wenu mliopimiwa."},{"v":12,"t":"Walipokuwa watu wawezao kuhesabiwa, Naam, watu wachache na wageni ndani yake,"},{"v":13,"t":"Wakatanga-tanga toka taifa hata taifa, Toka ufalme mmoja hata kwa watu wengine."},{"v":14,"t":"Hakumwacha mtu awaonee, Hata wafalme aliwakemea kwa ajili yao."},{"v":15,"t":"Akisema, Msiwaguse masihi wangu, Wala msiwadhuru nabii zangu."},{"v":16,"t":"Akaiita njaa iijilie nchi, Akakiharibu chakula chote walichokitegemea."},{"v":17,"t":"Alimpeleka mtu mbele yao, Yusufu aliuzwa utumwani."},{"v":18,"t":"Walimwumiza miguu yake kwa pingu, Akatiwa katika minyororo ya chuma."},{"v":19,"t":"Hata wakati wa kuwadia neno lake, Ahadi ya Bwana ilimjaribu."},{"v":20,"t":"Mfalme alituma watu akamfungua, Mkuu wa watu akamwachia."},{"v":21,"t":"Akamweka kuwa bwana wa nyumba yake, Na mwenye amri juu ya mali zake zote."},{"v":22,"t":"Awafunge masheki wake kama apendavyo, Na kuwafundisha wazee wake hekima."},{"v":23,"t":"Israeli naye akaingia Misri, Yakobo akawa mgeni katika nchi ya Hamu."},{"v":24,"t":"Akawajalia watu wake wazae sana, Akawafanya kuwa hodari kuliko watesi wao."},{"v":25,"t":"Akawageuza moyo wawachukie watu wake, Wakawatendea hila watumishi wake."},{"v":26,"t":"Akamtuma Musa, mtumishi wake, Na Haruni ambaye amemchagua."},{"v":27,"t":"Akaweka mambo ya ishara zake kati yao, Na miujiza katika nchi ya Hamu."},{"v":28,"t":"Alituma giza, kukafunga giza, Wala hawakuyaasi maneno yake."},{"v":29,"t":"Aliyageuza maji yao yakawa damu, Akawafisha samaki wao."},{"v":30,"t":"Nchi yao ilijaa vyura, Vyumbani mwa wafalme wao."},{"v":31,"t":"Alisema, kukaja makundi ya mainzi, Na chawa mipakani mwao mwote."},{"v":32,"t":"Badala ya mvua aliwapa mvua ya mawe, Na moto wa miali katika nchi yao."},{"v":33,"t":"Akaipiga mizabibu yao na mitini yao, Akaivunja miti ya mipaka yao."},{"v":34,"t":"Alisema, kukaja nzige, Na tunutu wasiohesabika;"},{"v":35,"t":"Wakaila miche yote ya nchi yao, Wakayala matunda ya ardhi yao."},{"v":36,"t":"Akawapiga wazaliwa wa kwanza katika nchi, Malimbuko ya nguvu zao."},{"v":37,"t":"Akawatoa hali wana fedha na dhahabu, Katika kabila zao asiwepo mwenye kukwaa."},{"v":38,"t":"Misri ilifurahi walipoondoka, Maana kwa ajili yao hofu imewaangukia."},{"v":39,"t":"Alitandaza wingu liwe funiko, Na moto utoe nuru usiku."},{"v":40,"t":"Walipotaka akaleta kware, Akawashibisha chakula cha mbinguni."},{"v":41,"t":"Akaufunua mwamba, kukabubujika maji, Yakapita pakavuni kama mto."},{"v":42,"t":"Maana alilikumbuka neno lake takatifu, Na Ibrahimu, mtumishi wake."},{"v":43,"t":"Akawatoa watu wake kwa shangwe, Na wateule wake kwa nyimbo za furaha."},{"v":44,"t":"Akawapa nchi za mataifa, wakairithi kazi ya watu;"},{"v":45,"t":"Ili wazishike amri zake, na kuzitii sheria zake. Haleluya."}]},{"c":106,"verses":[{"v":1,"t":"Haleluya. Mshukuruni Bwana kwa kuwa ni mwema, Kwa maana fadhili zake ni za milele."},{"v":2,"t":"Nani awezaye kuyanena matendo makuu ya Bwana, Kuzihubiri sifa zake zote?"},{"v":3,"t":"Heri washikao hukumu, Na kutenda haki sikuzote."},{"v":4,"t":"Ee Bwana, unikumbuke mimi, Kwa kibali uliyo nayo kwa watu wako. Unijilie kwa wokovu wako,"},{"v":5,"t":"Ili niuone wema wa wateule wako. Nipate kuifurahia furaha ya taifa lako, Na kujisifu pamoja na watu wako."},{"v":6,"t":"Tumetenda dhambi pamoja na baba zetu, Tumetenda maovu, tumefanya ubaya."},{"v":7,"t":"Baba zetu katika Misri Hawakufikiri matendo yako ya ajabu; Hawakukumbuka wingi wa fadhili zako; Wakaasi penye bahari, bahari ya Shamu."},{"v":8,"t":"Lakini akawaokoa kwa ajili ya jina lake, Ayadhihirishe matendo yake makuu."},{"v":9,"t":"Akaikemea bahari ya Shamu ikakauka, Akawaongoza vilindini kana kwamba ni uwanda."},{"v":10,"t":"Akawaokoa na mkono wa mtu aliyewachukia, Na kuwakomboa na mkono wa adui zao."},{"v":11,"t":"Maji yakawafunika watesi wao, Hakusalia hata mmoja wao."},{"v":12,"t":"Ndipo walipoyaamini maneno yake, Waliziimba sifa zake."},{"v":13,"t":"Wakayasahau matendo yake kwa haraka, Hawakulingojea shauri lake."},{"v":14,"t":"Bali walitamani sana jangwani, Wakamjaribu Mungu nyikani."},{"v":15,"t":"Akawapa walichomtaka, Akawakondesha roho zao."},{"v":16,"t":"Wakamhusudu Musa matuoni, Na Haruni, mtakatifu wa Bwana."},{"v":17,"t":"Nchi ikapasuka ikammeza Dathani, Ikaufunika mkutano wa Abiramu."},{"v":18,"t":"Moto ukawaka katika mkutano wao, Miali yake ikawateketeza wabaya."},{"v":19,"t":"Walifanya ndama huko Horebu, Wakaisujudia sanamu ya kuyeyuka."},{"v":20,"t":"Wakaubadili utukufu wao Kuwa mfano wa ng'ombe mla majani."},{"v":21,"t":"Wakamsahau Mungu, mwokozi wao, Aliyetenda makuu katika Misri."},{"v":22,"t":"Matendo ya ajabu katika nchi ya Hamu, Mambo ya kutisha penye bahari ya Shamu."},{"v":23,"t":"Akasema ya kuwa atawaangamiza Kama Musa, mteule wake, asingalisimama, Mbele zake kama mahali palipobomoka, Ili aigeuze hasira yake asije akawaharibu."},{"v":24,"t":"Wakaidharau nchi ile ya kupendeza, Wala hawakuliamini neno lake."},{"v":25,"t":"Bali wakanung'unika hemani mwao, Wala hawakuisikiliza sauti ya Bwana."},{"v":26,"t":"Ndipo alipowainulia mkono wake, Ya kuwa atawaangamiza jangwani,"},{"v":27,"t":"Na kuwatawanya wazao wao kati ya mataifa, Na kuwatapanya katika nchi mbali."},{"v":28,"t":"Wakajiambatiza na Baal-Peori, Wakazila dhabihu za wafu."},{"v":29,"t":"Wakamkasirisha kwa matendo yao; Tauni ikawashambulia."},{"v":30,"t":"Ndipo Finehasi akasimama akafanya hukumu; Tauni ikazuiliwa."},{"v":31,"t":"Akahesabiwa kuwa ana haki Kizazi baada ya kizazi hata milele."},{"v":32,"t":"Wakamghadhibisha penye maji ya Meriba, Hasara ikampata Musa kwa ajili yao,"},{"v":33,"t":"Kwa sababu waliiasi roho yake, Akasema yasiyofaa kwa midomo yake."},{"v":34,"t":"Hawakuwaharibu watu wa nchi Kama Bwana alivyowaambia;"},{"v":35,"t":"Bali walijichanganya na mataifa, Wakajifunza matendo yao."},{"v":36,"t":"Wakazitumikia sanamu zao, Nazo zikawa mtego kwao."},{"v":37,"t":"Naam, walitoa wana wao na binti zao Kuwa dhabihu kwa mashetani."},{"v":38,"t":"Wakamwaga damu isiyo na hatia, Damu ya wana wao na binti zao, Waliowatoa dhabihu kwa sanamu za Kanaani; Nchi ikatiwa unajisi kwa damu."},{"v":39,"t":"Ndivyo walivyotiwa uchafu kwa kazi zao, Wakafanya uasherati kwa matendo yao."},{"v":40,"t":"Hasira ya Bwana ikawaka juu ya watu wake, Akauchukia urithi wake."},{"v":41,"t":"Akawatia mikononi mwa mataifa, Nao waliowachukia wakawatawala."},{"v":42,"t":"Adui zao wakawaonea, Wakatiishwa chini ya mkono wao."},{"v":43,"t":"Mara nyingi aliwaponya, Bali walikuwa wakimwasi kwa mashauri yao, Wakadhilika katika uovu wao."},{"v":44,"t":"Lakini aliyaangalia mateso yao, Aliposikia kilio chao."},{"v":45,"t":"Akawakumbukia agano lake; Akawahurumia kwa wingi wa fadhili zake;"},{"v":46,"t":"Akawajalia kuhurumiwa Na watu wote waliowateka."},{"v":47,"t":"Ee Bwana, Mungu wetu, utuokoe, Utukusanye kwa kututoa katika mataifa, Tulishukuru jina lako takatifu, Tuzifanyie shangwe sifa zako."},{"v":48,"t":"Na ahimidiwe Bwana, Mungu wa Israeli, Tangu milele hata milele. Watu wote na waseme, Amina. Haleluya."}]},{"c":107,"verses":[{"v":1,"t":"Mshukuruni Bwana kwa kuwa ni mwema, Kwa maana fadhili zake ni za milele."},{"v":2,"t":"Na waseme hivi waliokombolewa na Bwana, Wale aliowakomboa na mkono wa mtesi."},{"v":3,"t":"Akawakusanya kutoka nchi zote, Mashariki na magharibi, kaskazini na kusini."},{"v":4,"t":"Walitanga-tanga jangwani katika njia ya nyika; Hawakuona mji wa kukaa."},{"v":5,"t":"Waliona njaa, waliona na kiu, Nafsi yao ilikuwa ikizimia ndani yao."},{"v":6,"t":"Wakamlilia Bwana katika dhiki zao, Akawaponya na shida zao."},{"v":7,"t":"Akawaongoza kwa njia ya kunyoka, Wapate kwenda mpaka mji wa kukaa."},{"v":8,"t":"Na wamshukuru Bwana, kwa fadhili zake, Na maajabu yake kwa wanadamu."},{"v":9,"t":"Maana hushibisha nafsi yenye shauku, Na nafsi yenye njaa huijaza mema."},{"v":10,"t":"Waliokaa katika giza na uvuli wa mauti, Wamefungwa katika taabu na chuma,"},{"v":11,"t":"Kwa sababu waliyaasi maneno ya Mungu, Wakalidharau shauri lake Aliye juu."},{"v":12,"t":"Hata akawadhili moyo kwa taabu, Wakajikwaa wala hakuna msaidizi."},{"v":13,"t":"Wakamlilia Bwana katika dhiki zao, Akawaponya na shida zao."},{"v":14,"t":"Aliwatoa katika giza na uvuli wa mauti, Akayavunja mafungo yao."},{"v":15,"t":"Na wamshukuru Bwana kwa fadhili zake, Na maajabu yake kwa wanadamu."},{"v":16,"t":"Maana ameivunja milango ya shaba, Ameyakata mapingo ya chuma."},{"v":17,"t":"Wapumbavu, kwa sababu ya ukosaji wao, Na kwa sababu ya maovu yao, hujitesa."},{"v":18,"t":"Nafsi zao zachukia kila namna ya chakula, Wameyakaribia malango ya mauti."},{"v":19,"t":"Wakamlilia Bwana katika dhiki zao, Akawaponya na shida zao."},{"v":20,"t":"Hulituma neno lake, huwaponya, Huwatoa katika maangamizo yao."},{"v":21,"t":"Na wamshukuru Bwana kwa fadhili zake, Na maajabu yake kwa wanadamu."},{"v":22,"t":"Na wamtolee dhabihu za kushukuru, Na kuyasimulia matendo yake kwa kuimba."},{"v":23,"t":"Washukao baharini katika merikebu, Wafanyao kazi yao katika maji mengi,"},{"v":24,"t":"Hao huziona kazi za Bwana, Na maajabu yake vilindini."},{"v":25,"t":"Maana husema, akavumisha upepo wa dhoruba, Ukayainua juu mawimbi yake."},{"v":26,"t":"Wapanda mbinguni, watelemka vilindini, Nafsi yao yayeyuka kwa hali mbaya."},{"v":27,"t":"Wayumba-yumba, wapepesuka kama mlevi, Akili zao zote zawapotea."},{"v":28,"t":"Wakamlilia Bwana katika dhiki zao, Akawaponya na shida zao."},{"v":29,"t":"Huituliza dhoruba, ikawa shwari, Mawimbi yake yakanyamaza."},{"v":30,"t":"Ndipo walipofurahi kwa kuwa yametulia Naye huwaleta mpaka bandari waliyoitamani."},{"v":31,"t":"Na wamshukuru Bwana kwa fadhili zake, Na maajabu yake kwa wanadamu."},{"v":32,"t":"Na wamtukuze katika kusanyiko la watu, Na wamhimidi katika baraza ya wazee."},{"v":33,"t":"Amegeuza mito ikawa jangwa, Na chemchemi za maji zikawa nchi ya kiu."},{"v":34,"t":"Nchi ya matunda mengi ikawa uwanda wa chumvi, Kwa sababu ya ubaya wao walioikaa."},{"v":35,"t":"Amegeuza jangwa ikawa ziwa la maji, Na nchi kavu ikawa chemchemi za maji."},{"v":36,"t":"Maana amewakalisha huko wenye njaa, Nao wametengeneza mji wa kukaa."},{"v":37,"t":"Wakapanda mbegu katika mashamba, Na kutia mizabibu iliyotoa matunda yake."},{"v":38,"t":"Naye huwabariki wakaongezeka sana, Wala hayapunguzi makundi yao."},{"v":39,"t":"Kisha wakapungua na kudhilika, Kwa kuonewa na mabaya na huzuni."},{"v":40,"t":"Akawamwagia wakuu dharau, Na kuwazungusha katika nyika isiyo na njia."},{"v":41,"t":"Akamweka mhitaji juu mbali na mateso, Akamfanyia jamaa kama kundi la kondoo."},{"v":42,"t":"Wanyofu wa moyo wataona na kufurahi, Na uovu wa kila namna utajifumba kinywa."},{"v":43,"t":"Aliye na hekima na ayaangalie hayo; Na wazitafakari fadhili za Bwana."}]},{"c":108,"verses":[{"v":1,"t":"Ee Mungu, moyo wangu u thabiti, Nitaimba, nitaimba zaburi, Naam, kwa utukufu wangu."},{"v":2,"t":"Amka, kinanda na kinubi, Nitaamka alfajiri."},{"v":3,"t":"Ee Bwana, nitakushukuru kati ya watu, Nitakuimbia zaburi kati ya mataifa."},{"v":4,"t":"Maana fadhili zako ni kubwa hata mbinguni, Na uaminifu wako hata mawinguni."},{"v":5,"t":"Ee Mungu, utukuzwe juu ya mbingu, Na juu ya nchi yote uwe utukufu wako."},{"v":6,"t":"Ili wapenzi wako waopolewe, Uokoe kwa mkono wako wa kuume, uniitikie."},{"v":7,"t":"Mungu amenena kwa utakatifu wake, Nami nitashangilia. Nitaigawanya Shekemu, Nitalipima bonde la Sukothi."},{"v":8,"t":"Gileadi ni yangu, na Manase ni yangu, Na Efraimu ni nguvu ya kichwa changu. Yuda ni fimbo yangu ya kifalme,"},{"v":9,"t":"Moabu ni bakuli langu la kunawia. Nitamtupia Edomu kiatu changu, Na kumpigia Filisti kelele za vita."},{"v":10,"t":"Ni nani atakayenipeleka hata mji wenye boma? Ni nani atakayeniongoza hata Edomu?"},{"v":11,"t":"Ee Mungu, si Wewe uliyetutupa? Wala, Ee Mungu, hutoki na majeshi yetu?"},{"v":12,"t":"Utuletee msaada juu ya mtesi, Maana wokovu wa binadamu haufai."},{"v":13,"t":"Kwa msaada wa Mungu tutatenda makuu, Maana Yeye atawakanyaga watesi wetu."}]},{"c":109,"verses":[{"v":1,"t":"Ee Mungu wa sifa zangu, usinyamaze,"},{"v":2,"t":"Kwa maana wamenifumbulia kinywa; Kinywa cha mtu asiye haki, cha hila, Wamesema nami kwa ulimi wa uongo."},{"v":3,"t":"Naam, kwa maneno ya chuki wamenizunguka, Wamepigana nami bure."},{"v":4,"t":"Badala ya upendo wangu wao hunishitaki, Ijapokuwa naliwaombea."},{"v":5,"t":"Wamenichukuza mabaya badala ya mema, Na chuki badala ya upendo wangu."},{"v":6,"t":"Uweke mtu mkorofi juu yake, Mshitaki asimame mkono wake wa kuume."},{"v":7,"t":"Katika kuhukumiwa ataonekana hana haki, Na sala yake itadhaniwa kuwa ni dhambi."},{"v":8,"t":"Siku zake na ziwe chache, Usimamizi wake na atwae mtu mwingine."},{"v":9,"t":"Wanawe na wawe yatima, Na mkewe na awe mjane."},{"v":10,"t":"Kutanga na watange wanawe na kuomba, Watafute chakula mbali na mahame yao."},{"v":11,"t":"Mdai na anase vitu vyote alivyo navyo, Wageni na wateke mapato ya kazi yake."},{"v":12,"t":"Asiwe na mtu wa kumfanyia fadhili, Wala mtu wa kuwahurumia yatima wake."},{"v":13,"t":"Wazao wake waangamizwe, Jina lao likafutwe katika kizazi cha pili."},{"v":14,"t":"Uovu wa baba zake ukumbukwe mbele za Bwana, Na dhambi ya mamaye isifutwe."},{"v":15,"t":"Ziwe mbele za Bwana daima, Aliondoe kumbukumbu lao duniani."},{"v":16,"t":"Kwa kuwa hakukumbuka kutenda fadhili, Bali alimfukuza mnyonge na mhitaji, Hata akamfisha mtu aliyevunjika moyo,"},{"v":17,"t":"Naye alipenda kulaani, nako kukampata. Hakupendezwa na kubariki, kukawa mbali naye,"},{"v":18,"t":"Alijivika laana kana kwamba ni vazi lake. Ikamwingilia moyoni kama maji, Na kama mafuta mifupani mwake."},{"v":19,"t":"Na iwe kwake kama vazi ajivikalo, Na kama mshipi ajifungao daima."},{"v":20,"t":"Ndiyo malipo ya washitaki wangu toka kwa Bwana, Na ya hao wanaoisingizia nafsi yangu mabaya."},{"v":21,"t":"Na Wewe, MUNGU, Bwana, unitendee kwa ajili ya jina lako, Kwa kuwa fadhili zako ni njema uniokoe."},{"v":22,"t":"Kwa maana mimi ni mnyonge na mhitaji, Na moyo wangu umejeruhi ndani yangu."},{"v":23,"t":"Ninapita kama kivuli kianzacho kutoweka, Ninapeperushwa kama nzige."},{"v":24,"t":"Magoti yangu yamedhoofu kwa kufunga, Na mwili wangu umekonda kwa kukosa mafuta."},{"v":25,"t":"Nami nalikuwa laumu kwao, Wanionapo hutikisa vichwa vyao."},{"v":26,"t":"Ee Bwana, Mungu wangu, unisaidie, Uniokoe sawasawa na fadhili zako."},{"v":27,"t":"Nao wakajue ya kuwa ndio mkono wako; Wewe, Bwana, umeyafanya hayo."},{"v":28,"t":"Wao walaani, bali Wewe utabariki, Wameondoka wao wakaaibishwa, Bali mtumishi wako atafurahi."},{"v":29,"t":"Washitaki wangu watavikwa fedheha, Watajivika aibu yao kama joho."},{"v":30,"t":"Nitamshukuru Bwana kwa kinywa changu, Naam, nitamsifu katikati ya mkutano."},{"v":31,"t":"Maana atasimama mkono wa kuume wa mhitaji Amwokoe na wanaoihukumu nafsi yake."}]},{"c":110,"verses":[{"v":1,"t":"Neno la Bwana kwa Bwana wangu, Uketi mkono wangu wa kuume, Hata niwafanyapo adui zako Kuwa chini ya miguu yako."},{"v":2,"t":"Bwana atainyosha toka Sayuni Fimbo ya nguvu zako. Uwe na enzi kati ya adui zako;"},{"v":3,"t":"Watu wako wanajitoa kwa hiari, Siku ya uwezo wako; Kwa uzuri wa utakatifu, Tokea tumbo la asubuhi, Unao umande wa ujana wako."},{"v":4,"t":"Bwana ameapa, Wala hataghairi, Ndiwe kuhani hata milele, Kwa mfano wa Melkizedeki."},{"v":5,"t":"Bwana yu mkono wako wa kuume; Ataseta wafalme, Siku ya ghadhabu yake."},{"v":6,"t":"Atahukumu kati ya mataifa, Ataijaza nchi mizoga; Ataseta kichwa katika nchi nyingi."},{"v":7,"t":"Atakunywa maji ya mto njiani; Kwa hiyo atakiinua kichwa chake."}]},{"c":111,"verses":[{"v":1,"t":"Haleluya Nitamshukuru Bwana kwa moyo wangu wote,Barazani pa wanyofu wa moyo na katika mkutano."},{"v":2,"t":"Matendo ya Bwana ni makuu, Yafikiriwa sana na wapendezwao nayo."},{"v":3,"t":"Kazi yake ni heshima na adhama, Na haki yake yakaa milele."},{"v":4,"t":"Amefanya ukumbusho wa matendo yake ya ajabu; Bwana ni mwenye fadhili na rehema."},{"v":5,"t":"Amewapa wamchao chakula; Atalikumbuka agano lake milele."},{"v":6,"t":"Amewajulisha watu wake uwezo wa matendo yake, Kwa kuwapa urithi wa mataifa."},{"v":7,"t":"Matendo ya mikono yake ni kweli na hukumu, Maagizo yake yote ni amini,"},{"v":8,"t":"Yamethibitika milele na milele, Yamefanywa katika kweli na adili."},{"v":9,"t":"Amewapelekea watu wake ukombozi, Ameamuru agano lake liwe la milele, Jina lake ni takatifu la kuogopwa."},{"v":10,"t":"Kumcha Bwana ndio mwanzo wa hekima, Wote wafanyao hayo wana akili njema, Sifa zake zakaa milele."}]},{"c":112,"verses":[{"v":1,"t":"Haleluya. Heri mtu yule amchaye Bwana, Apendezwaye sana na maagizo yake."},{"v":2,"t":"Wazao wake watakuwa hodari duniani; Kizazi cha wenye adili kitabarikiwa."},{"v":3,"t":"Nyumbani mwake mna utajiri na mali, Na haki yake yakaa milele."},{"v":4,"t":"Nuru huwazukia wenye adili gizani; Ana fadhili na huruma na haki."},{"v":5,"t":"Heri atendaye fadhili na kukopesha; Atengenezaye mambo yake kwa haki."},{"v":6,"t":"Kwa maana hataondoshwa kamwe; Mwenye haki atakumbukwa milele."},{"v":7,"t":"Hataogopa habari mbaya; Moyo wake u imara ukimtumaini Bwana."},{"v":8,"t":"Moyo wake umethibitika hataogopa, Hata awaone watesi wake wameshindwa."},{"v":9,"t":"Amekirimu, na kuwapa maskini, Haki yake yakaa milele, Pembe yake itatukuzwa kwa utukufu."},{"v":10,"t":"Asiye haki ataona na kusikitika, Atasaga meno yake na kuyeyuka, Tamaa ya wasio haki itapotea."}]},{"c":113,"verses":[{"v":1,"t":"Haleluya. Enyi watumishi wa Bwana, sifuni, Lisifuni jina la Bwana."},{"v":2,"t":"Jina la Bwana lihimidiwe Tangu leo na hata milele."},{"v":3,"t":"Toka maawio ya jua hata machweo yake Jina la Bwana husifiwa."},{"v":4,"t":"Bwana ni mkuu juu ya mataifa yote, Na utukufu wake ni juu ya mbingu."},{"v":5,"t":"Ni nani aliye mfano wa Bwana, Mungu wetu aketiye juu;"},{"v":6,"t":"Anyenyekeaye kutazama, Mbinguni na duniani?"},{"v":7,"t":"Humwinua mnyonge kutoka mavumbini, Na kumpandisha maskini kutoka jaani."},{"v":8,"t":"Amketishe pamoja na wakuu, Pamoja na wakuu wa watu wake."},{"v":9,"t":"Huweka nyumbani mwanamke aliye tasa, Awe mama ya watoto mwenye furaha."}]},{"c":114,"verses":[{"v":1,"t":"Haleluya. Israeli alipotoka Misri, Na Yakobo katika watu wa lugha ya kigeni."},{"v":2,"t":"Yuda ilikuwa patakatifu pake, Israeli milki yake."},{"v":3,"t":"Bahari iliona ikakimbia, Yordani ilirudishwa nyuma."},{"v":4,"t":"Milima iliruka kama kondoo waume, Vilima kama wana-kondoo."},{"v":5,"t":"Ee bahari, una nini, ukimbie? Yordani, urudi nyuma?"},{"v":6,"t":"Enyi milima, mruke kama kondoo waume? Enyi vilima, kama wana-kondoo?"},{"v":7,"t":"Tetemeka, Ee nchi, mbele za uso wa Bwana, Mbele za uso wa Mungu wa Yakobo."},{"v":8,"t":"Augeuza mwamba kuwa ziwa la maji, Jiwe gumu kuwa chemchemi."}]},{"c":115,"verses":[{"v":1,"t":"Ee Bwana, kutukuza usitutukuze sisi, Bali ulitukuze jina lako, Kwa ajili ya fadhili zako, Kwa ajili ya uaminifu wako."},{"v":2,"t":"Kwa nini mataifa kusema, Yuko wapi Mungu wao?"},{"v":3,"t":"Lakini Mungu wetu yuko mbinguni, Alitakalo lote amelitenda."},{"v":4,"t":"Sanamu zao ni fedha na dhahabu, Kazi ya mikono ya wanadamu."},{"v":5,"t":"Zina vinywa lakini hazisemi, Zina macho lakini hazioni,"},{"v":6,"t":"Zina masikio lakini hazisikii, Zina pua lakini hazisikii harufu,"},{"v":7,"t":"Mikono lakini hazishiki, miguu lakini haziendi, Wala hazitoi sauti kwa koo zake."},{"v":8,"t":"Wazifanyao watafanana nazo, Kila mmoja anayezitumainia."},{"v":9,"t":"Enyi Israeli, mtumainini Bwana; Yeye ni msaada wao na ngao yao."},{"v":10,"t":"Enyi mlango wa Haruni, mtumainini Bwana; Yeye ni msaada wao na ngao yao."},{"v":11,"t":"Enyi mmchao Bwana, mtumainini Bwana; Yeye ni msaada wao na ngao yao."},{"v":12,"t":"Bwana ametukumbuka, Naye atatubariki sisi. Ataubariki mlango wa Israeli, Ataubariki mlango wa Haruni,"},{"v":13,"t":"Atawabariki wamchao Bwana, Wadogo kwa wakubwa."},{"v":14,"t":"Bwana na awaongeze ninyi, Ninyi na watoto wenu."},{"v":15,"t":"Na mbarikiwe ninyi na Bwana, Aliyezifanya mbingu na nchi."},{"v":16,"t":"Mbingu ni mbingu za Bwana, Bali nchi amewapa wanadamu."},{"v":17,"t":"Sio wafu wamsifuo Bwana, Wala wo wote washukao kwenye kimya;"},{"v":18,"t":"Bali sisi tutamhimidi Bwana, Tangu leo na hata milele."}]},{"c":116,"verses":[{"v":1,"t":"Haleluya. Nampenda Bwana kwa kuwa anaisikiliza Sauti yangu na dua zangu."},{"v":2,"t":"Kwa maana amenitegea sikio lake, Kwa hiyo nitamwita siku zangu zote."},{"v":3,"t":"Kamba za mauti zilinizunguka, Shida za kuzimu zilinipata. Naliona taabu na huzuni;"},{"v":4,"t":"Nikaliitia jina la Bwana. Ee Bwana, nakuomba sana, Uniokoe nafsi yangu."},{"v":5,"t":"Bwana ni mwenye neema na haki, Naam, Mungu wetu ni mwenye rehema."},{"v":6,"t":"Bwana huwalinda wasio na hila; Nalidhilika, akaniokoa."},{"v":7,"t":"Ee nafsi yangu, urudi rahani mwako, Kwa kuwa Bwana amekutendea ukarimu."},{"v":8,"t":"Maana umeniponya nafsi yangu na mauti, Macho yangu na machozi, Na miguu yangu na kuanguka."},{"v":9,"t":"Nitaenenda mbele za Bwana Katika nchi za walio hai."},{"v":10,"t":"Naliamini, kwa maana nitasema, Mimi naliteswa sana."},{"v":11,"t":"Mimi nalisema kwa haraka yangu, Wanadamu wote ni waongo."},{"v":12,"t":"Nimrudishie Bwana nini Kwa ukarimu wake wote alionitendea?"},{"v":13,"t":"Nitakipokea kikombe cha wokovu; Na kulitangaza jina la Bwana;"},{"v":14,"t":"Nitaziondoa nadhiri zangu kwa Bwana, Naam, mbele ya watu wake wote."},{"v":15,"t":"Ina thamani machoni pa Bwana Mauti ya wacha Mungu wake."},{"v":16,"t":"Ee Bwana, hakika mimi ni mtumishi wako, Mtumishi wako, mwana wa mjakazi wako, Umevifungua vifungo vyangu."},{"v":17,"t":"Nitakutolea dhabihu ya kushukuru; Na kulitangaza jina la Bwana;"},{"v":18,"t":"Nitaziondoa nadhiri zangu kwa Bwana, Naam, mbele ya watu wake wote."},{"v":19,"t":"Katika nyua za nyumba ya Bwana, Ndani yako, Ee Yerusalemu."}]},{"c":117,"verses":[{"v":1,"t":"Haleluya. Enyi mataifa yote, msifuni Bwana, Enyi watu wote, mhimidini."},{"v":2,"t":"Maana fadhili zake kwetu sisi ni kuu, Na uaminifu wa Bwana ni wa milele."}]},{"c":118,"verses":[{"v":1,"t":"Haleluya. Mshukuruni Bwana kwa kuwa ni mwema, Kwa maana fadhili zake ni za milele."},{"v":2,"t":"Israeli na aseme sasa, Ya kwamba fadhili zake ni za milele."},{"v":3,"t":"Mlango wa Haruni na waseme sasa, Ya kwamba fadhili zake ni za milele."},{"v":4,"t":"Wamchao Bwana na waseme sasa, Ya kwamba fadhili zake ni za milele."},{"v":5,"t":"Katika shida yangu nalimwita Bwana; Bwana akanijibu akaniweka panapo nafasi."},{"v":6,"t":"Bwana yuko upande wangu, sitaogopa; Mwanadamu atanitenda nini?"},{"v":7,"t":"Bwana yuko upande wangu, msaidizi wangu, Kwa hiyo nitawaona wanaonichukia wameshindwa."},{"v":8,"t":"Ni heri kumkimbilia Bwana Kuliko kuwatumainia wanadamu."},{"v":9,"t":"Ni heri kumkimbilia Bwana. Kuliko kuwatumainia wakuu."},{"v":10,"t":"Mataifa yote walinizunguka; Kwa jina la Bwana naliwakatilia mbali."},{"v":11,"t":"Walinizunguka, naam, walinizunguka; Kwa jina la Bwana naliwakatilia mbali."},{"v":12,"t":"Walinizunguka kama nyuki, Walizimika kama moto wa miibani; Kwa jina la Bwana naliwakatilia mbali."},{"v":13,"t":"Ulinisukuma sana ili nianguke; Lakini Bwana akanisaidia."},{"v":14,"t":"Bwana ni nguvu zangu na wimbo wangu, Naye amekuwa wokovu wangu."},{"v":15,"t":"Sauti ya furaha na wokovu Imo hemani mwao wenye haki; Mkono wa kuume wa Bwana hutenda makuu."},{"v":16,"t":"Mkono wa kuume wa Bwana umetukuzwa; Mkono wa kuume wa Bwana hutenda makuu."},{"v":17,"t":"Sitakufa bali nitaishi, Nami nitayasimulia matendo ya Bwana."},{"v":18,"t":"Bwana ameniadhibu sana, Lakini hakuniacha nife."},{"v":19,"t":"Nifungulieni malango ya haki, Nitaingia na kumshukuru Bwana."},{"v":20,"t":"Lango hili ni la Bwana, Wenye haki ndio watakaoliingia."},{"v":21,"t":"Nitakushukuru kwa maana umenijibu, Nawe umekuwa wokovu wangu."},{"v":22,"t":"Jiwe walilolikataa waashi Limekuwa jiwe kuu la pembeni."},{"v":23,"t":"Neno hili limetoka kwa Bwana, Nalo ni ajabu machoni petu."},{"v":24,"t":"Siku hii ndiyo aliyoifanya Bwana, Tutashangilia na kuifurahia."},{"v":25,"t":"Ee Bwana, utuokoe, twakusihi; Ee Bwana, utufanikishe, twakusihi."},{"v":26,"t":"Na abarikiwe yeye ajaye kwa jina la Bwana; Tumewabarikia toka nyumbani mwa Bwana."},{"v":27,"t":"Bwana ndiye aliye Mungu, Naye ndiye aliyetupa nuru. Ifungeni dhabihu kwa kamba Pembeni mwa madhabahu."},{"v":28,"t":"Ndiwe Mungu wangu, nami nitakushukuru, Ndiwe Mungu wangu, nami nitakutukuza."},{"v":29,"t":"Mshukuruni Bwana kwa kuwa ni mwema, Kwa maana fadhili zake ni za milele."}]},{"c":119,"verses":[{"v":1,"t":"Heri walio kamili njia zao, Waendao katika sheria ya Bwana."},{"v":2,"t":"Heri wazitiio shuhuda zake, Wamtafutao kwa moyo wote."},{"v":3,"t":"Naam, hawakutenda ubatili, Wamekwenda katika njia zake."},{"v":4,"t":"Wewe umetuamuru mausia yako, Ili sisi tuyatii sana."},{"v":5,"t":"Ningependa njia zangu ziwe thabiti, Nizitii amri zako."},{"v":6,"t":"Ndipo mimi sitaaibika, Nikiyaangalia maagizo yako yote."},{"v":7,"t":"Nitakushukuru kwa unyofu wa moyo, Nikiisha kujifunza hukumu za haki yako"},{"v":8,"t":"Nitazitii amri zako, Usiniache kabisa"},{"v":9,"t":"Jinsi gani kijana aisafishe njia yake? Kwa kutii, akilifuata neno lako."},{"v":10,"t":"Kwa moyo wangu wote nimekutafuta, Usiniache nipotee mbali na maagizo yako."},{"v":11,"t":"Moyoni mwangu nimeliweka neno lako, Nisije nikakutenda dhambi."},{"v":12,"t":"Ee Bwana, umehimidiwa, Unifundishe amri zako."},{"v":13,"t":"Kwa midomo yangu nimezisimulia Hukumu zote za kinywa chako."},{"v":14,"t":"Nimeifurahia njia ya shuhuda zako Kana kwamba ni mali mengi."},{"v":15,"t":"Nitayatafakari mausia yako, Nami nitaziangalia njia zako."},{"v":16,"t":"Nitajifurahisha sana kwa amri zako, Sitalisahau neno lako."},{"v":17,"t":"Umtendee mtumishi wako ukarimu, Nipate kuishi, nami nitalitii neno lako."},{"v":18,"t":"Unifumbue macho yangu niyatazame Maajabu yatokayo katika sheria yako."},{"v":19,"t":"Mimi ni mgeni katika nchi, Usinifiche maagizo yako."},{"v":20,"t":"Roho yangu imepondeka kwa kutamani Hukumu zako kila wakati."},{"v":21,"t":"Umewakemea wenye kiburi, Wamelaaniwa waendao mbali na maagizo yako."},{"v":22,"t":"Uniondolee laumu na dharau, Kwa maana nimezishika shuhuda zako."},{"v":23,"t":"Wakuu nao waliketi wakaninena, Lakini mtumishi wako atazitafakari amri zako."},{"v":24,"t":"Shuhuda zako nazo ndizo furaha yangu, Na washauri wangu."},{"v":25,"t":"Nafsi yangu imeambatana na mavumbi, Unihuishe sawasawa na neno lako."},{"v":26,"t":"Nalizisimulia njia zangu ukanijibu, Unifundishe amri zako."},{"v":27,"t":"Unifahamishe njia ya mausia yako, Nami nitayatafakari maajabu yako."},{"v":28,"t":"Nafsi yangu imeyeyuka kwa uzito, Unitie nguvu sawasawa na neno lako."},{"v":29,"t":"Uniondolee njia ya uongo, Unineemeshe kwa sheria yako."},{"v":30,"t":"Nimeichagua njia ya uaminifu, Na kuziweka hukumu zako mbele yangu."},{"v":31,"t":"Nimeambatana na shuhuda zako, Ee Bwana, usiniaibishe."},{"v":32,"t":"Nitakwenda mbio katika njia ya maagizo yako, Utakaponikunjua moyo wangu."},{"v":33,"t":"Ee Bwana, unifundishe njia ya amri zako, Nami nitaishika hata mwisho."},{"v":34,"t":"Unifahamishe nami nitaishika sheria yako, Naam, nitaitii kwa moyo wangu wote."},{"v":35,"t":"Uniendeshe katika mapito ya maagizo yako, Kwa maana nimependezwa nayo."},{"v":36,"t":"Unielekeze moyo wangu na shuhuda zako, Wala usiielekee tamaa."},{"v":37,"t":"Unigeuze macho yangu nisitazame visivyofaa, Unihuishe katika njia yako."},{"v":38,"t":"Umthibitishie mtumishi wako ahadi yako, Inayohusu kicho chako."},{"v":39,"t":"Uniondolee laumu niiogopayo, Maana hukumu zako ni njema."},{"v":40,"t":"Tazama, nimeyatamani mausia yako, Unihuishe kwa haki yako."},{"v":41,"t":"Ee Bwana, fadhili zako zinifikie na mimi, Naam, wokovu wako sawasawa na ahadi yako."},{"v":42,"t":"Nami nitamjibu neno anilaumuye, Kwa maana nalitumainia neno lako."},{"v":43,"t":"Usiliondoe neno la kweli kinywani mwangu kamwe, Maana nimezingojea hukumu zako."},{"v":44,"t":"Nami nitaitii sheria yako daima, Naam, milele na milele."},{"v":45,"t":"Nami nitakwenda panapo nafasi, Kwa kuwa nimejifunza mausia yako."},{"v":46,"t":"Nitazinena shuhuda zako mbele ya wafalme, Wala sitaona aibu."},{"v":47,"t":"Nami nitajifurahisha sana kwa maagizo yako, Ambayo nimeyapenda."},{"v":48,"t":"Na mikono yangu nitayainulia maagizo yako niliyoyapenda, Nami nitazitafakari amri zako."},{"v":49,"t":"Likumbuke neno ulilomwambia mtumishi wako, Kwa sababu umenitumainisha."},{"v":50,"t":"Hii ndiyo faraja yangu katika taabu yangu, Ya kwamba ahadi yako imenihuisha."},{"v":51,"t":"Wenye kiburi wamenidharau mno, Sikujiepusha na sheria zako."},{"v":52,"t":"Nimezikumbuka hukumu zako za kale, Ee Bwana, nikajifariji."},{"v":53,"t":"Ghadhabu imenishika kwa sababu ya wasio haki, Waiachao sheria yako."},{"v":54,"t":"Amri zako zimekuwa nyimbo zangu, Katika nyumba ya ugeni wangu."},{"v":55,"t":"Wakati wa usiku nimelikumbuka jina lako, Ee Bwana, nikaitii sheria yako."},{"v":56,"t":"Hayo ndiyo niliyokuwa nayo, Kwa sababu nimeyashika mausia yako."},{"v":57,"t":"Bwana ndiye aliye fungu langu, Nimesema kwamba nitayatii maneno yake."},{"v":58,"t":"Nimekuomba radhi kwa moyo wangu wote, Unifadhili sawasawa na ahadi yako."},{"v":59,"t":"Nalizitafakari njia zangu, Na miguu yangu nalizielekezea shuhuda zako."},{"v":60,"t":"Nalifanya haraka wala sikukawia, Kuyatii maagizo yako."},{"v":61,"t":"Kamba za wasio haki zimenifunga, Sikuisahau sheria yako."},{"v":62,"t":"Katikati ya usiku nitaamka nikushukuru, Kwa sababu ya hukumu zako za haki."},{"v":63,"t":"Mimi ni mwenzao watu wote wakuchao, Na wale wayatiio mausia yako."},{"v":64,"t":"Bwana, dunia imejaa fadhili zako, Unifundishe amri zako."},{"v":65,"t":"Umemtendea mema mtumishi wako, Ee Bwana, sawasawa na neno lako."},{"v":66,"t":"Unifundishe akili na maarifa, Maana nimeyaamini maagizo yako."},{"v":67,"t":"Kabla sijateswa mimi nalipotea, Lakini sasa nimelitii neno lako."},{"v":68,"t":"Wewe U mwema na mtenda mema, Unifundishe amri zako."},{"v":69,"t":"Wenye kiburi wamenizulia uongo, Kwa moyo wangu wote nitayashika mausia yako."},{"v":70,"t":"Mioyo yao imenenepa kama shahamu, Mimi nimeifurahia sheria yako."},{"v":71,"t":"Ilikuwa vema kwangu kuwa naliteswa, Nipate kujifunza amri zako."},{"v":72,"t":"Sheria ya kinywa chako ni njema kwangu, Kuliko maelfu ya dhahabu na fedha."},{"v":73,"t":"Mikono yako ilinifanya ikanitengeneza, Unifahamishe nikajifunze maagizo yako."},{"v":74,"t":"Wakuchao na wanione na kufurahi, Kwa sababu nimelingojea neno lako."},{"v":75,"t":"Najua ya kuwa hukumu zako ni za haki, Ee Bwana, na kwa uaminifu umenitesa."},{"v":76,"t":"Nakuomba, fadhili zako ziwe faraja kwangu, Sawasawa na ahadi yako kwa mtumishi wako."},{"v":77,"t":"Rehema zako zinijie nipate kuishi, Maana sheria yako ni furaha yangu."},{"v":78,"t":"Wenye kiburi waaibike, maana wamenidhulumu kwa uongo, Mimi nitayatafakari mausia yako."},{"v":79,"t":"Wakuchao na wanirudie, Nao watazijua shuhuda zako."},{"v":80,"t":"Moyo wangu na uwe mkamilifu katika amri zako, Nisije mimi nikaaibika."},{"v":81,"t":"Nafsi yangu imefifia kwa kuutamani wokovu wako, Nimelingojea neno lako."},{"v":82,"t":"Macho yangu yamefifia kwa kuitazamia ahadi yako, Nisemapo, Lini utakaponifariji?"},{"v":83,"t":"Maana nimekuwa kama kiriba katika moshi, Sikuzisahau amri zako."},{"v":84,"t":"Siku za mtumishi wako ni ngapi, Lini utakapowahukumu wale wanaonifuatia?"},{"v":85,"t":"Wenye kiburi wamenichimbia mashimo, Ambao hawaifuati sheria yako."},{"v":86,"t":"Maagizo yako yote ni amini, Wananifuatia bure, unisaidie."},{"v":87,"t":"Walikuwa karibu na kunikomesha katika nchi, Lakini sikuyaacha mausia yako."},{"v":88,"t":"Unihuishe kwa fadhili zako, Nami nitazishika shuhuda za kinywa chako."},{"v":89,"t":"Ee Bwana, neno lako lasimama Imara mbinguni hata milele."},{"v":90,"t":"Uaminifu wako upo kizazi baada ya kizazi, Umeiweka nchi, nayo inakaa."},{"v":91,"t":"Kwa hukumu zako vimesimama imara hata leo, Maana vitu vyote ni watumishi wako."},{"v":92,"t":"Kama sheria yako isingalikuwa furaha yangu, Hapo ningalipotea katika taabu zangu."},{"v":93,"t":"Hata milele sitayasahau maagizo yako, Maana kwa hayo umenihuisha."},{"v":94,"t":"Mimi ni wako, uniokoe, Kwa maana nimejifunza mausia yako."},{"v":95,"t":"Wasio haki wameniotea ili kunipoteza, Nitazitafakari shuhuda zako."},{"v":96,"t":"Nimeona ukamilifu wote kuwa na mwisho, Bali agizo lako ni pana mno."},{"v":97,"t":"Sheria yako naipenda mno ajabu, Ndiyo kutafakari kwangu mchana kutwa."},{"v":98,"t":"Maagizo yako hunitia hekima kuliko adui zangu, Kwa maana ninayo sikuzote."},{"v":99,"t":"Ninazo akili kuliko wakufunzi wangu wote, Maana shuhuda zako ndizo nizifikirizo."},{"v":100,"t":"Ninao ufahamu kuliko wazee, Kwa kuwa nimeyashika mausia yako."},{"v":101,"t":"Nimeiepusha miguu yangu na kila njia mbaya, Ili nilitii neno lako."},{"v":102,"t":"Sikujiepusha na hukumu zako, Maana Wewe mwenyewe umenifundisha."},{"v":103,"t":"Mausia yako ni matamu sana kwangu, Kupita asali kinywani mwangu."},{"v":104,"t":"Kwa mausia yako najipatia ufahamu, Ndiyo maana naichukia kila njia ya uongo."},{"v":105,"t":"Neno lako ni taa ya miguu yangu, Na mwanga wa njia yangu."},{"v":106,"t":"Nimeapa nami nitaifikiliza, Kuzishika hukumu za haki yako."},{"v":107,"t":"Nimeteswa mno; Ee Bwana, unihuishe sawasawa na neno lako."},{"v":108,"t":"Ee Bwana, uziridhie sadaka za kinywa changu, Na kunifundisha hukumu zako."},{"v":109,"t":"Nafsi yangu imo mkononi mwangu daima, Lakini sheria yako sikuisahau."},{"v":110,"t":"Watendao uovu wamenitegea mtego, Lakini sikuikosa njia ya mausia yako."},{"v":111,"t":"Shuhuda zako nimezifanya urithi wa milele, Maana ndizo changamko la moyo wangu."},{"v":112,"t":"Nimeuelekeza moyo wangu nizitende amri zako, Daima, naam, hata milele."},{"v":113,"t":"Watu wa kusita-sita nawachukia, Lakini sheria yako naipenda."},{"v":114,"t":"Ndiwe sitara yangu na ngao yangu, Neno lako nimelingojea."},{"v":115,"t":"Enyi watenda mabaya, ondokeni kwangu, Niyashike maagizo ya Mungu wangu."},{"v":116,"t":"Unitegemeze sawasawa na ahadi yako, nikaishi, Wala usiniache niyaaibikie matumaini yangu."},{"v":117,"t":"Unisaidie nami nitakuwa salama, Nami nitaziangalia amri zako daima."},{"v":118,"t":"Umewakataa wote wazikosao amri zako, Kwa maana hila zao ni uongo."},{"v":119,"t":"Wabaya wa nchi pia umewaondoa kama takataka, Ndiyo maana nimezipenda shuhuda zako."},{"v":120,"t":"Mwili wangu unatetemeka kwa kukucha Wewe, Nami ninaziogopa hukumu zako."},{"v":121,"t":"Nimefanya hukumu na haki, Usiniache mikononi mwao wanaonionea."},{"v":122,"t":"Uwe mdhamini wa mtumishi wako, apate mema, Wenye kiburi wasinionee."},{"v":123,"t":"Macho yangu yamefifia kwa kuutamani wokovu wako, Na ahadi ya haki yako."},{"v":124,"t":"Kama zilivyo rehema zako umtendee mtumishi wako, Na amri zako unifundishe."},{"v":125,"t":"Mimi ni mtumishi wako, unifahamishe, Nipate kuzijua shuhuda zako."},{"v":126,"t":"Wakati umewadia Bwana atende kazi; Kwa kuwa wameitangua sheria yako."},{"v":127,"t":"Ndiyo maana nimeyapenda maagizo yako, Kuliko dhahabu, naam, dhahabu iliyo safi."},{"v":128,"t":"Maana nayaona mausia yako yote kuwa ya adili, Kila njia ya uongo naichukia."},{"v":129,"t":"Shuhuda zako ni za ajabu, Ndiyo maana roho yangu imezishika."},{"v":130,"t":"Kufafanusha maneno yako kwatia nuru, Na kumfahamisha mjinga."},{"v":131,"t":"Nalifunua kinywa changu nikatweta, Maana naliyatamani maagizo yako."},{"v":132,"t":"Unigeukie, unirehemu mimi, Kama iwahusuvyo walipendao jina lako."},{"v":133,"t":"Uzielekeze hatua zangu kwa neno lako, Uovu usije ukanimiliki."},{"v":134,"t":"Unikomboe na dhuluma ya mwanadamu, Nipate kuyashika mausia yako."},{"v":135,"t":"Umwangazie mtumishi wako uso wako, Na kunifundisha amri zako."},{"v":136,"t":"Macho yangu yachuruzika mito ya maji, Kwa sababu hawaitii sheria yako."},{"v":137,"t":"Ee Bwana, Wewe ndiwe mwenye haki, Na hukumu zako ni za adili."},{"v":138,"t":"Umeziagiza shuhuda zako kwa haki, Na kwa uaminifu mwingi."},{"v":139,"t":"Juhudi yangu imeniangamiza, Maana watesi wangu wameyasahau maneno yako."},{"v":140,"t":"Neno lako limesafika sana, Kwa hiyo mtumishi wako amelipenda."},{"v":141,"t":"Mimi ni mdogo, nadharauliwa, Lakini siyasahau mausia yako."},{"v":142,"t":"Haki yako ni haki ya milele, Na sheria yako ni kweli."},{"v":143,"t":"Taabu na dhiki zimenipata, Maagizo yako ni furaha yangu."},{"v":144,"t":"Haki ya shuhuda zako ni ya milele, Unifahamishe, nami nitaishi."},{"v":145,"t":"Nimeita kwa moyo wangu wote; Ee Bwana, uitike; Nitazishika amri zako."},{"v":146,"t":"Nimekuita Wewe, uniokoe, Nami nitazishika shuhuda zako."},{"v":147,"t":"Kutangulia mapambazuko naliomba msaada, Naliyangojea maneno yako kwa tumaini."},{"v":148,"t":"Macho yangu yalitangulia makesha ya usiku, Ili kuitafakari ahadi yako."},{"v":149,"t":"Uisikie sauti yangu sawasawa na fadhili zako, Ee Bwana, unihuishe sawasawa na hukumu yako."},{"v":150,"t":"Wanakaribia wanaonifuatia kwa chuki, Wamekwenda mbali na sheria yako."},{"v":151,"t":"Ee Bwana, Wewe U karibu, Na maagizo yako yote ni kweli."},{"v":152,"t":"Tokea zamani nimejua kwa shuhuda zako, Ya kuwa umeziweka zikae milele."},{"v":153,"t":"Uyaangalie mateso yangu, uniokoe, Maana sikuisahau sheria yako."},{"v":154,"t":"Unitetee na kunikomboa, Unihuishe sawasawa na ahadi yako."},{"v":155,"t":"Wokovu u mbali na wasio haki, Kwa maana hawajifunzi amri zako."},{"v":156,"t":"Ee Bwana, rehema zako ni nyingi, Unihuishe sawasawa na hukumu zako."},{"v":157,"t":"Wanaonifuatia na watesi wangu ni wengi, Lakini sikujiepusha na shuhuda zako."},{"v":158,"t":"Nimewaona watendao uhaini nikachukizwa, Kwa sababu hawakulitii neno lako."},{"v":159,"t":"Uangalie niyapendavyo mausia yako, Ee Bwana, unihuishe sawasawa na fadhili zako."},{"v":160,"t":"Jumla ya neno lako ni kweli, Na kila hukumu ya haki yako ni ya milele."},{"v":161,"t":"Wakuu wameniudhi bure, Ila moyo wangu unayahofia maneno yako."},{"v":162,"t":"Naifurahia ahadi yako, Kama apataye mateka mengi."},{"v":163,"t":"Nimeuchukia uongo, umenikirihi, Sheria yako nimeipenda."},{"v":164,"t":"Mara saba kila siku nakusifu, Kwa sababu ya hukumu za haki yako."},{"v":165,"t":"Wana amani nyingi waipendao sheria yako, Wala hawana la kuwakwaza."},{"v":166,"t":"Ee Bwana, nimeungojea wokovu wako, Na maagizo yako nimeyatenda."},{"v":167,"t":"Nafsi yangu imezishika shuhuda zako, Nami nazipenda mno."},{"v":168,"t":"Nimeyashika mausia yako na shuhuda zako, Maana njia zangu zote zi mbele zako."},{"v":169,"t":"Ee Bwana, kilio changu na kikukaribie, Unifahamishe sawasawa na neno lako."},{"v":170,"t":"Dua yangu na ifike mbele zako, Uniponye sawasawa na ahadi yako."},{"v":171,"t":"Midomo yangu na itoe sifa, Kwa kuwa unanifundisha mausia yako."},{"v":172,"t":"Ulimi wangu na uiimbe ahadi yako, Maana maagizo yako yote ni ya haki."},{"v":173,"t":"Mkono wako na uwe tayari kunisaidia, Maana nimeyachagua mausia yako."},{"v":174,"t":"Ee Bwana, nimeutamani wokovu wako, Na sheria yako ndiyo furaha yangu."},{"v":175,"t":"Nafsi yangu na iishi, ipate kukusifu, Na hukumu zako zinisaidie."},{"v":176,"t":"Nimetanga-tanga kama kondoo aliyepotea; Umtafute mtumishi wako; Kwa maana sikuyasahau maagizo yako."}]},{"c":120,"verses":[{"v":1,"t":"Katika shida yangu nalimlilia Bwana Naye akaniitikia."},{"v":2,"t":"Ee Bwana, uiponye nafsi yangu Na midomo ya uongo na ulimi wa hila."},{"v":3,"t":"Akupe nini, akuzidishie nini, Ewe ulimi wenye hila?"},{"v":4,"t":"Mishale ya mtu hodari iliyochongoka, Pamoja na makaa ya mretemu."},{"v":5,"t":"Ole wangu mimi! Kwa kuwa nimekaa katika Mesheki; Na kufanya maskani yangu Katikati ya hema za Kedari."},{"v":6,"t":"Nafsi yangu imekaa siku nyingi, Pamoja naye aichukiaye amani."},{"v":7,"t":"Mimi ni wa amani; Bali ninenapo, wao huelekea vita."}]},{"c":121,"verses":[{"v":1,"t":"Nitayainua macho yangu niitazame milima, Msaada wangu utatoka wapi?"},{"v":2,"t":"Msaada wangu u katika Bwana, Aliyezifanya mbingu na nchi."},{"v":3,"t":"Asiuache mguu wako usogezwe; Asisinzie akulindaye;"},{"v":4,"t":"Naam, hatasinzia wala hatalala usingizi, Yeye aliye mlinzi wa Israeli."},{"v":5,"t":"Bwana ndiye mlinzi wako; Bwana ni uvuli mkono wako wa kuume."},{"v":6,"t":"Jua halitakupiga mchana, Wala mwezi wakati wa usiku."},{"v":7,"t":"Bwana atakulinda na mabaya yote, Atakulinda nafsi yako."},{"v":8,"t":"Bwana atakulinda utokapo na uingiapo, Tangu sasa na hata milele."}]},{"c":122,"verses":[{"v":1,"t":"Nalifurahi waliponiambia, Na twende nyumbani kwa Bwana."},{"v":2,"t":"Miguu yetu imesimama Ndani ya malango yako, Ee Yerusalemu."},{"v":3,"t":"Ee Yerusalemu uliyejengwa Kama mji ulioshikamana,"},{"v":4,"t":"Huko ndiko walikopanda kabila, Kabila za Bwana; Ushuhuda kwa Israeli, Walishukuru jina la Bwana."},{"v":5,"t":"Maana huko viliwekwa viti vya hukumu, Viti vya enzi vya mbari ya Daudi."},{"v":6,"t":"Utakieni Yerusalemu amani; Na wafanikiwe wakupendao;"},{"v":7,"t":"Amani na ikae ndani ya kuta zako, Na kufanikiwa ndani ya majumba yako."},{"v":8,"t":"Kwa ajili ya ndugu zangu na rafiki zangu Niseme sasa, Amani ikae nawe."},{"v":9,"t":"Kwa ajili ya nyumba ya Bwana, Mungu wetu, Nikutafutie mema."}]},{"c":123,"verses":[{"v":1,"t":"Nimekuinulia macho yangu, Wewe uketiye mbinguni."},{"v":2,"t":"Kama vile macho ya watumishi Kwa mkono wa bwana zao Kama macho ya mjakazi Kwa mkono wa bibi yake; Hivyo macho yetu humwelekea Bwana, Mungu wetu, Hata atakapoturehemu."},{"v":3,"t":"Uturehemu, Ee Bwana, uturehemu sisi, Kwa maana tumeshiba dharau."},{"v":4,"t":"Nafsi zetu zimeshiba mzaha wa wenye raha, Na dharau ya wenye kiburi."}]},{"c":124,"verses":[{"v":1,"t":"Kama si Bwana aliyekuwa pamoja nasi, Israeli na aseme sasa,"},{"v":2,"t":"Kama si Bwana aliyekuwa pamoja nasi, Wanadamu walipotushambulia."},{"v":3,"t":"Papo hapo wangalitumeza hai, Hasira yao ilipowaka juu yetu"},{"v":4,"t":"Papo hapo maji yangalitugharikisha, Mto ungalipita juu ya roho zetu;"},{"v":5,"t":"Papo hapo yangalipita juu ya nafsi zetu Maji yafurikayo."},{"v":6,"t":"Na ahimidiwe Bwana; Asiyetutoa kuwa mawindo kwa meno yao."},{"v":7,"t":"Nafsi yetu imeokoka kama ndege Katika mtego wa wawindaji, Mtego umevunjika, nasi tumeokoka."},{"v":8,"t":"Msaada wetu u katika jina la Bwana, Aliyezifanya mbingu na nchi."}]},{"c":125,"verses":[{"v":1,"t":"Wamtumainio Bwana ni kama mlima Sayuni, Ambao hautatikisika, wakaa milele."},{"v":2,"t":"Kama milima inavyouzunguka Yerusalemu, Ndivyo Bwana anavyowazunguka watu wake, Tangu sasa na hata milele."},{"v":3,"t":"Kwa maana fimbo ya udhalimu Haitakaa juu ya fungu la wenye haki; Wenye haki wasije wakainyosha Mikono yao kwenye upotovu."},{"v":4,"t":"Ee Bwana, uwatendee mema walio wema, Nao walio wanyofu wa moyo."},{"v":5,"t":"Bali wao wanaozigeukia njia zao zilizopotoka, Bwana atawaondoa pamoja na watenda maovu. Amani ikae na Israeli."}]},{"c":126,"verses":[{"v":1,"t":"Bwana alipowarejeza mateka wa Sayuni, Tulikuwa kama waotao ndoto."},{"v":2,"t":"Ndipo kinywa chetu kilipojaa kicheko, Na ulimi wetu kelele za furaha. Ndipo waliposema katika mataifa, Bwana amewatendea mambo makuu."},{"v":3,"t":"Bwana alitutendea mambo makuu, Tulikuwa tukifurahi."},{"v":4,"t":"Ee Bwana, uwarejeze watu wetu waliofungwa, Kama vijito vya Kusini."},{"v":5,"t":"Wapandao kwa machozi Watavuna kwa kelele za furaha."},{"v":6,"t":"Ingawa mtu anakwenda zake akilia, Azichukuapo mbegu za kupanda. Hakika atarudi kwa kelele za furaha, Aichukuapo miganda yake."}]},{"c":127,"verses":[{"v":1,"t":"Bwana asipoijenga nyumba Waijengao wafanya kazi bure. Bwana asipoulinda mji Yeye aulindaye akesha bure."},{"v":2,"t":"Kazi yenu ni bure, mnaoamka mapema, Na kukawia kwenda kulala, Na kula chakula cha taabu; Yeye humpa mpenzi wake usingizi."},{"v":3,"t":"Tazama, wana ndio urithi wa Bwana, Uzao wa tumbo ni thawabu."},{"v":4,"t":"Kama mishale mkononi mwa shujaa, Ndivyo walivyo wana wa ujanani."},{"v":5,"t":"Heri mtu yule Aliyelijaza podo lake hivyo. Naam, hawataona aibu Wanaposema na adui langoni."}]},{"c":128,"verses":[{"v":1,"t":"Heri kila mtu amchaye Bwana, Aendaye katika njia yake."},{"v":2,"t":"Taabu ya mikono yako hakika utaila; Utakuwa heri, na kwako kwema."},{"v":3,"t":"Mkeo atakuwa kama mzabibu uzaao, Vyumbani mwa nyumba yako. Wanao kama miche ya mizeituni Wakiizunguka meza yako."},{"v":4,"t":"Tazama, atabarikiwa hivyo, yule amchaye Bwana."},{"v":5,"t":"Bwana akubariki toka Sayuni; Uone uheri wa Yerusalemu siku zote za maisha yako;"},{"v":6,"t":"Naam, ukawaone wana wa wanao. Amani ikae na Israeli."}]},{"c":129,"verses":[{"v":1,"t":"Mara nyingi wamenitesa tangu ujana wangu, Israeli na aseme sasa,"},{"v":2,"t":"Mara nyingi wamenitesa tangu ujana wangu, Lakini hawakuniweza."},{"v":3,"t":"Wakulima wamelima mgongoni mwangu, Wamefanya mirefu mifuo yao."},{"v":4,"t":"Bwana ndiye mwenye haki, Amezikata kamba zao wasio haki."},{"v":5,"t":"Na waaibishwe, warudishwe nyuma, Wote wanaoichukia Sayuni."},{"v":6,"t":"Na wawe kama majani ya darini Yanyaukayo kabla hayajamea."},{"v":7,"t":"Ambayo mvunaji haujazi mkono wake, Wala mfunga miganda kifua chake."},{"v":8,"t":"Wala hawasemi wapitao, Amani ya Bwana ikae nanyi, Twawabariki kwa jina la Bwana."}]},{"c":130,"verses":[{"v":1,"t":"Ee Bwana, toka vilindini nimekulilia."},{"v":2,"t":"Bwana, uisikie sauti yangu. Masikio yako na yaisikilize Sauti ya dua zangu."},{"v":3,"t":"Bwana, kama Wewe ungehesabu maovu, Ee Bwana, nani angesimama?"},{"v":4,"t":"Lakini kwako kuna msamaha, Ili Wewe uogopwe."},{"v":5,"t":"Nimemngoja Bwana, roho yangu imengoja, Na neno lake nimelitumainia."},{"v":6,"t":"Nafsi yangu inamngoja Bwana, Kuliko walinzi waingojavyo asubuhi, Naam, walinzi waingojao asubuhi."},{"v":7,"t":"Ee Israeli, umtarajie Bwana; Maana kwa Bwana kuna fadhili, Na kwake kuna ukombozi mwingi."},{"v":8,"t":"Yeye atamkomboa Israeli na maovu yake yote."}]},{"c":131,"verses":[{"v":1,"t":"Bwana, moyo wangu hauna kiburi, Wala macho yangu hayainuki. Wala sijishughulishi na mambo makuu, Wala na mambo yashindayo nguvu zangu."},{"v":2,"t":"Hakika nimeituliza nafsi yangu, Na kuinyamazisha. Kama mtoto aliyeachishwa Kifuani mwa mama yake; Kama mtoto aliyeachishwa, Ndivyo roho yangu ilivyo kwangu."},{"v":3,"t":"Ee Israeli, umtarajie Bwana, Tangu leo na hata milele."}]},{"c":132,"verses":[{"v":1,"t":"Bwana, umkumbukie Daudi Taabu zake zote alizotaabika."},{"v":2,"t":"Ndiye aliyemwapia Bwana, Akaweka nadhiri kwa Shujaa wa Yakobo."},{"v":3,"t":"Sitaingia hemani mwa nyumba yangu, Wala sitapanda matandiko ya kitanda changu;"},{"v":4,"t":"Sitaacha macho yangu kuwa na usingizi, Wala kope zangu kusinzia;"},{"v":5,"t":"Hata nitakapompatia Bwana mahali, Na Shujaa wa Yakobo maskani."},{"v":6,"t":"Tazama, tulisikia habari zake katika Efrata, Katika konde la Yearimu tuliiona."},{"v":7,"t":"Na tuingie katika maskani yake, Tusujudu penye kiti cha kuwekea miguu yake."},{"v":8,"t":"Ee Bwana, uinuke, uende kwenye raha yako, Wewe na sanduku la nguvu zako."},{"v":9,"t":"Makuhani wako na wavikwe haki, Watauwa wako na washangilie."},{"v":10,"t":"Kwa ajili ya Daudi, mtumishi wako, Usiurudishe nyuma uso wa masihi"},{"v":11,"t":"Bwana amemwapia Daudi neno la kweli, Hatarudi nyuma akalihalifu, Baadhi ya wazao wa mwili wako Nitawaweka katika kiti chako cha enzi."},{"v":12,"t":"Wanao wakiyashika maagano yangu, Na shuhuda nitakazowafundisha; Watoto wao nao wataketi Katika kiti chako cha enzi milele."},{"v":13,"t":"Kwa kuwa Bwana ameichagua Sayuni, Ameitamani akae ndani yake."},{"v":14,"t":"Hapo ndipo mahali pangu pa raha milele, Hapo nitakaa kwa maana nimepatamani."},{"v":15,"t":"Hakika nitavibariki vyakula vyake Wahitaji wake nitawashibisha chakula."},{"v":16,"t":"Na makuhani wake nitawavika wokovu, Na watauwa wake watashangilia."},{"v":17,"t":"Hapo nitamchipushia Daudi pembe, Na taa nimemtengenezea masihi wangu."},{"v":18,"t":"Adui zake nitawavika aibu, Bali juu yake taji yake itasitawi."}]},{"c":133,"verses":[{"v":1,"t":"Tazama, jinsi ilivyo vema, na kupendeza, Ndugu wakae pamoja, kwa umoja."},{"v":2,"t":"Ni kama mafuta mazuri kichwani, Yashukayo ndevuni, ndevu za Haruni, Yashukayo mpaka upindo wa mavazi yake."},{"v":3,"t":"Kama umande wa Hermoni ushukao milimani pa Sayuni. Maana ndiko Bwana alikoamuru baraka, Naam, uzima hata milele."}]},{"c":134,"verses":[{"v":1,"t":"Tazama, enyi watumishi wa Bwana, Mhimidini Bwana, nyote pia. Ninyi mnaosimama usiku Katika nyumba ya Bwana."},{"v":2,"t":"Painulieni patakatifu mikono yenu, Na kumhimidi Bwana."},{"v":3,"t":"Bwana akubariki toka Sayuni, Aliyezifanya mbingu na nchi."}]},{"c":135,"verses":[{"v":1,"t":"Haleluya. Lisifuni jina la Bwana, Enyi watumishi wa Bwana, sifuni."},{"v":2,"t":"Ninyi msimamao nyumbani mwa Bwana, Nyuani mwa nyumba ya Mungu wenu."},{"v":3,"t":"Msifuni Bwana kwa kuwa Bwana ni mwema, Liimbieni jina lake kwa maana lapendeza."},{"v":4,"t":"Kwa sababu Bwana amejichagulia Yakobo, Na Israeli, wawe watu wake hasa."},{"v":5,"t":"Maana najua mimi ya kuwa Bwana ni mkuu, Na Bwana wetu yu juu ya miungu yote."},{"v":6,"t":"Bwana amefanya kila lililompendeza, Katika mbingu na katika nchi, Katika bahari na katika vilindi vyote."},{"v":7,"t":"Ndiye apandishaye mvuke toka miisho ya nchi; Huifanyia mvua umeme; Hutoa upepo katika hazina zake."},{"v":8,"t":"Aliwapiga wazaliwa wa kwanza wa Misri, Wa wanadamu na wa wanyama."},{"v":9,"t":"Alipeleka ishara na maajabu kati yako, Ee Misri, Juu ya Farao na watumishi wake wote."},{"v":10,"t":"Aliwapiga mataifa mengi, Akawaua wafalme wenye nguvu;"},{"v":11,"t":"Sihoni, mfalme wa Waamori, Na Ogu, mfalme wa Bashani, Na falme zote za Kanaani."},{"v":12,"t":"Akaitoa nchi yao iwe urithi, Urithi wa Israeli watu wake."},{"v":13,"t":"Ee Bwana, jina lako ni la milele, Bwana, kumbukumbu lako vizazi hata vizazi."},{"v":14,"t":"Kwa kuwa Bwana atawaamua watu wake, Atawahurumia watumishi wake."},{"v":15,"t":"Sanamu za mataifa ni fedha na dhahabu, Kazi ya mikono ya wanadamu."},{"v":16,"t":"Zina vinywa lakini hazisemi, Zina macho lakini hazioni,"},{"v":17,"t":"Zina masikio lakini hazisikii, Wala hamna pumzi vinywani mwake."},{"v":18,"t":"Wazifanyao watafanana nazo, Na kila mmoja anayezitumainia."},{"v":19,"t":"Enyi mlango wa Israeli, mhimidini Bwana; Enyi mlango wa Haruni, mhimidini Bwana;"},{"v":20,"t":"Enyi mlango wa Lawi, mhimidini Bwana; Ninyi mnaomcha Bwana, mhimidini Bwana."},{"v":21,"t":"Na ahimidiwe Bwana toka Sayuni, Akaaye Yerusalemu. Haleluya."}]},{"c":136,"verses":[{"v":1,"t":"Mshukuruni Bwana kwa kuwa ni mwema; Kwa maana fadhili zake ni za milele."},{"v":2,"t":"Mshukuruni Mungu wa miungu; Kwa maana fadhili zake ni za milele."},{"v":3,"t":"Mshukuruni Bwana wa mabwana; Kwa maana fadhili zake ni za milele."},{"v":4,"t":"Yeye peke yake afanya maajabu makuu; Kwa maana fadhili zake ni za milele."},{"v":5,"t":"Yeye aliyefanya mbingu kwa fahamu zake; Kwa maana fadhili zake ni za milele."},{"v":6,"t":"Yeye aliyeitandaza nchi juu ya maji; Kwa maana fadhili zake ni za milele."},{"v":7,"t":"Yeye aliyefanya mianga mikubwa; Kwa maana fadhili zake ni za milele."},{"v":8,"t":"Jua litawale mchana; Kwa maana fadhili zake ni za milele."},{"v":9,"t":"Mwezi na nyota zitawale usiku; Kwa maana fadhili zake ni za milele."},{"v":10,"t":"Yeye aliyewapiga Wamisri kwa kuwaua wazaliwa wa kwanza wao; Kwa maana fadhili zake ni za milele."},{"v":11,"t":"Akawatoa Waisraeli katikati yao; Kwa maana fadhili zake ni za milele."},{"v":12,"t":"Kwa mkono hodari na mkono ulionyoshwa; Kwa maana fadhili zake ni za milele."},{"v":13,"t":"Yeye aliyeigawa Bahari ya Shamu; Kwa maana fadhili zake ni za milele."},{"v":14,"t":"Akawavusha Israeli katikati yake; Kwa maana fadhili zake ni za milele."},{"v":15,"t":"Akamwangusha Farao na jeshi lake katika Bahari ya Shamu; Kwa maana fadhili zake ni za milele."},{"v":16,"t":"Yeye aliyewaongoza watu wake jangwani; Kwa maana fadhili zake ni za milele."},{"v":17,"t":"Yeye aliyewapiga wafalme wakuu; Kwa maana fadhili zake ni za milele."},{"v":18,"t":"Akawaua wafalme mashuhuri; Kwa maana fadhili zake ni za milele."},{"v":19,"t":"Sihoni, mfalme wa Waamori; Kwa maana fadhili zake ni za milele."},{"v":20,"t":"Na Ogu, mfalme wa Bashani; Kwa maana fadhili zake ni za milele."},{"v":21,"t":"Akaitoa nchi yao iwe urithi; Kwa maana fadhili zake ni za milele."},{"v":22,"t":"Urithi wa Israeli mtumishi wake; Kwa maana fadhili zake ni za milele."},{"v":23,"t":"Aliyetukumbuka katika unyonge wetu; Kwa maana fadhili zake ni za milele."},{"v":24,"t":"Akatuokoa na watesi wetu; Kwa maana fadhili zake ni za milele."},{"v":25,"t":"Kila chenye mwili akipa chakula chake; Kwa maana fadhili zake ni za milele."},{"v":26,"t":"Mshukuruni Mungu wa mbingu; Kwa maana fadhili zake ni za milele."}]},{"c":137,"verses":[{"v":1,"t":"Kando ya mito ya Babeli ndiko tulikoketi, Tukalia tulipoikumbuka Sayuni."},{"v":2,"t":"Katika miti iliyo katikati yake Tulivitundika vinubi vyetu."},{"v":3,"t":"Maana huko waliotuchukua mateka Walitaka tuwaimbie; Na waliotuonea walitaka furaha; Tuimbieni baadhi ya nyimbo za Sayuni."},{"v":4,"t":"Tuuimbeje wimbo wa Bwana Katika nchi ya ugeni?"},{"v":5,"t":"Ee Yerusalemu, nikikusahau wewe, Mkono wangu wa kuume na usahau."},{"v":6,"t":"Ulimi wangu na ugandamane Na kaakaa la kinywa changu, nisipokukumbuka. Nisipoikuza Yerusalemu Zaidi ya furaha yangu iliyo kuu."},{"v":7,"t":"Ee Bwana, uwakumbuke wana wa Edomu, Siku ya Yerusalemu. Waliosema, Bomoeni! Bomoeni hata misingini!"},{"v":8,"t":"Ee binti Babeli, uliye karibu na kuangamia, Heri atakayekupatiliza, ulivyotupatiliza sisi."},{"v":9,"t":"Heri yeye atakayewakamata wadogo wako, Na kuwaseta wao juu ya mwamba."}]},{"c":138,"verses":[{"v":1,"t":"Nitakushukuru kwa moyo wangu wote, Mbele ya miungu nitakuimbia zaburi."},{"v":2,"t":"Nitasujudu nikilikabili hekalu lako takatifu, Nitalishukuru jina lako, Kwa ajili ya fadhili zako na uaminifu wako, Kwa maana umeikuza ahadi yako, Kuliko jina lako lote."},{"v":3,"t":"Siku ile niliyokuita uliniitikia, Ukanifariji nafsi kwa kunitia nguvu."},{"v":4,"t":"Ee Bwana, wafalme wote wa dunia watakushukuru, Watakapoyasikia maneno ya kinywa chako."},{"v":5,"t":"Naam, wataziimba njia za Bwana, Kwa maana utukufu wa Bwana ni mkuu."},{"v":6,"t":"Ingawa Bwana yuko juu, amwona mnyenyekevu, Naye amjua mwenye kujivuna tokea mbali."},{"v":7,"t":"Nijapokwenda kati ya shida utanihuisha, Utanyosha mkono juu ya hasira ya adui zangu, Na mkono wako wa kuume utaniokoa."},{"v":8,"t":"Bwana atanitimilizia mambo yangu; Ee Bwana, fadhili zako ni za milele; Usiziache kazi za mikono yako."}]},{"c":139,"verses":[{"v":1,"t":"Ee Bwana, umenichunguza na kunijua."},{"v":2,"t":"Wewe wajua kuketi kwangu na kuondoka kwangu; Umelifahamu wazo langu tokea mbali."},{"v":3,"t":"Umepepeta kwenda kwangu na kulala kwangu, Umeelewa na njia zangu zote."},{"v":4,"t":"Maana hamna neno ulimini mwangu Usilolijua kabisa, Bwana."},{"v":5,"t":"Umenizingira nyuma na mbele, Ukaniwekea mkono wako."},{"v":6,"t":"Maarifa hayo ni ya ajabu, yanishinda mimi, Hayadirikiki, siwezi kuyafikia."},{"v":7,"t":"Niende wapi nijiepushe na roho yako? Niende wapi niukimbie uso wako?"},{"v":8,"t":"Kama ningepanda mbinguni, Wewe uko; Ningefanya kuzimu kitanda changu, Wewe uko."},{"v":9,"t":"Ningezitwaa mbawa za asubuhi, Na kukaa pande za mwisho za bahari;"},{"v":10,"t":"Huko nako mkono wako utaniongoza, Na mkono wako wa kuume utanishika."},{"v":11,"t":"Kama nikisema, Hakika giza litanifunika, Na nuru inizungukayo ingekuwa usiku;"},{"v":12,"t":"Giza nalo halikufichi kitu, Bali usiku huangaza kama mchana; Giza na mwanga kwako ni sawasawa."},{"v":13,"t":"Maana Wewe ndiwe uliyeniumba mtima wangu, Uliniunga tumboni mwa mama yangu."},{"v":14,"t":"Nitakushukuru kwa kuwa nimeumbwa Kwa jinsi ya ajabu ya kutisha. Matendo yako ni ya ajabu, Na nafsi yangu yajua sana,"},{"v":15,"t":"Mifupa yangu haikusitirika kwako, Nilipoumbwa kwa siri, Nilipoungwa kwa ustadi pande za chini za nchi;"},{"v":16,"t":"Macho yako yaliniona kabla sijakamilika; Chuoni mwako ziliandikwa zote pia, Siku zilizoamriwa kabla hazijawa bado."},{"v":17,"t":"Mungu, fikira zako zina thamani nyingi kwangu; Jinsi ilivyo kubwa jumla yake!"},{"v":18,"t":"Kama ningezihesabu ni nyingi kuliko mchanga; Niamkapo nikali pamoja nawe."},{"v":19,"t":"Ee Mungu, laiti ungewafisha waovu! Enyi watu wa damu, ondokeni kwangu;"},{"v":20,"t":"Kwa maana wakuasi kwa ubaya, Adui zako wakutaja jina lako bure."},{"v":21,"t":"Je! Bwana nisiwachukie wanaokuchukia? Nisikirihike nao wakuasio?"},{"v":22,"t":"Nawachukia kwa ukomo wa chuki, Wamekuwa adui kwangu."},{"v":23,"t":"Ee Mungu, unichunguze, uujue moyo wangu, Unijaribu, uyajue mawazo yangu;"},{"v":24,"t":"Uone kama iko njia iletayo majuto ndani yangu, Ukaniongoze katika njia ya milele."}]},{"c":140,"verses":[{"v":1,"t":"Ee Bwana, uniokoe na mtu mbaya, Unihifadhi na mtu wa jeuri."},{"v":2,"t":"Waliowaza mabaya mioyoni mwao, Kila siku huondokesha vita."},{"v":3,"t":"Wamenoa ndimi zao kama nyoka, Sumu ya fira i chini ya midomo yao."},{"v":4,"t":"Ee Bwana, unilinde na mikono ya mtu asiye haki; Unihifadhi na mtu wa jeuri; Waliowaza kuzipotosha hatua zangu."},{"v":5,"t":"Wenye kiburi wamenifichia mtego na kamba; Wametandika wavu kando ya njia; Wameniwekea matanzi."},{"v":6,"t":"Nimemwambia Bwana, Ndiwe Mungu wangu; Ee Bwana, uisikie sauti ya dua zangu."},{"v":7,"t":"Ee MUNGU Bwana, nguvu za wokovu wangu, Umenifunika kichwa changu siku ya vita."},{"v":8,"t":"Ee Bwana, usimpe asiye haki tamaa zake, Usiifanikishe hila yake, wasije wakajiinua."},{"v":9,"t":"Nao wainuapo vichwa watu wanaonizunguka, Madhara ya midomo yao yawafunike."},{"v":10,"t":"Makaa ya moto yawaangukie, watupwe motoni, Na katika mashimo, wasipate kusimama tena."},{"v":11,"t":"Msingiziaji hatawekwa imara katika nchi, Mtu wa jeuri, uovu humwinda kumwangamiza."},{"v":12,"t":"Najua ya kuwa Bwana atamfanyia mnyonge hukumu, Na wahitaji haki yao."},{"v":13,"t":"Hakika wenye haki watalishukuru jina lako, Wenye adili watakaa mahali ulipo Wewe."}]},{"c":141,"verses":[{"v":1,"t":"Ee Bwana, nimekuita, unijie hima, Uisikie sauti yangu nikuitapo."},{"v":2,"t":"Sala yangu ipae mbele zako kama uvumba, Kuinuliwa mikono yangu kama dhabihu ya jioni."},{"v":3,"t":"Ee Bwana, uweke mlinzi kinywani pangu, Mngojezi mlangoni pa midomo yangu."},{"v":4,"t":"Usiuelekeze moyo wangu kunako jambo baya, Nisiyazoelee matendo yasiyofaa, Pamoja na watu watendao maovu; Wala nisile vyakula vyao vya anasa."},{"v":5,"t":"Mwenye haki na anipige, itakuwa fadhili; Anikemee, itakuwa kama mafuta kichwani; Kichwa changu kisikatae, Maana siachi kusali kati ya mabaya yao."},{"v":6,"t":"Makadhi wao wakiangushwa kando ya genge, Watayasikia maneno yangu, maana ni matamu."},{"v":7,"t":"Kama kupasua kuni na kuzichanja juu ya nchi, Ndivyo ilivyo mifupa yetu mdomoni pa kuzimu."},{"v":8,"t":"Macho yangu yanakuelekea Wewe, MUNGU Bwana, Nimekukimbilia Wewe, usiniache nafsi yangu."},{"v":9,"t":"Unilinde na mtego walionitegea, Na matanzi yao watendao maovu."},{"v":10,"t":"Wabaya na waanguke katika nyavu zao wenyewe, Pindi mimi ninapopita salama."}]},{"c":142,"verses":[{"v":1,"t":"Kwa sauti yangu nitamlilia Bwana, Kwa sauti yangu nitamwomba Bwana dua."},{"v":2,"t":"Nitafunua mbele zake malalamiko yangu, Shida yangu nitaitangaza mbele zake."},{"v":3,"t":"Nilipozimia roho uliyajua mapito yangu; Katika njia niendayo wamenifichia mtego."},{"v":4,"t":"Utazame mkono wa kuume ukaone, Kwa maana sina mtu anijuaye. Makimbilio yamenipotea, Hakuna wa kunitunza roho."},{"v":5,"t":"Bwana, nimekuita nikasema, Ndiwe kimbilio langu, Fungu langu katika nchi ya walio hai."},{"v":6,"t":"Ukisikilize kilio changu, Kwa maana nimedhilika sana. Uniponye nao wanaonifuatia, Kwa maana wao ni hodari kuliko mimi."},{"v":7,"t":"Uitoe nafsi yangu kifungoni. Nipate kulishukuru jina lako. Wenye haki watanizunguka, Kwa kuwa Wewe unanikirimu."}]},{"c":143,"verses":[{"v":1,"t":"Ee Bwana, uisikie sala yangu, uzisikilize dua zangu, Kwa uaminifu wako unijibu kwa haki yako."},{"v":2,"t":"Wala usimhukumu mtumishi wako, Maana kwako hakuna aliye hai mwenye haki."},{"v":3,"t":"Maana adui ameifuatia nafsi yangu, Ameutupa chini uzima wangu. Amenikalisha mahali penye giza, Kama watu waliokufa zamani."},{"v":4,"t":"Na roho yangu imezimia ndani yangu, Moyo wangu ndani yangu umesituka."},{"v":5,"t":"Nimezikumbuka siku za kale, Nimeyatafakari matendo yako yote, Naziwaza kazi za mikono yako."},{"v":6,"t":"Nakunyoshea mikono yangu; Nafsi yangu inakuonea kiu kama nchi kame."},{"v":7,"t":"Ee Bwana, unijibu hima, roho yangu imelegea; Usinifiche uso wako, Nisifanane nao washukao shimoni"},{"v":8,"t":"Unifanye kusikia fadhili zako asubuhi, Kwa maana nimekutumaini Wewe. Unijulishe njia nitakayoiendea, Kwa maana nakuinulia nafsi yangu."},{"v":9,"t":"Ee Bwana, uniponye na adui zangu; Nimekukimbilia Wewe, unifiche."},{"v":10,"t":"Unifundishe kuyatenda mapenzi yako, Kwa maana ndiwe Mungu wangu; Roho yako mwema aniongoze kwenye nchi sawa,"},{"v":11,"t":"Ee Bwana, unihuishe kwa ajili ya jina lako, Kwa haki yako unitoe roho yangu taabuni;"},{"v":12,"t":"Kwa fadhili zako utawakatilia mbali adui zangu; Na kuwaangamiza wote wanitesao nafsi, Kwa maana mimi ni mtumishi wako."}]},{"c":144,"verses":[{"v":1,"t":"Na ahimidiwe Bwana, mwamba wangu, Anifundishaye mikono yangu vita, Vidole vyangu kupigana."},{"v":2,"t":"Mhisani wangu na boma langu, Ngome yangu na mwokozi wangu, Ngao yangu niliyemkimbilia, Huwatiisha watu wangu chini yangu."},{"v":3,"t":"Ee Bwana, mtu ni kitu gani hata umjue? Na binadamu hata umwangalie?"},{"v":4,"t":"Binadamu amefanana na ubatili, Siku zake ni kama kivuli kipitacho."},{"v":5,"t":"Bwana, uziinamishe mbingu zako, ushuke, Uiguse milima nayo itatoka moshi."},{"v":6,"t":"Utupe umeme, uwatawanye, Uipige mishale yako, uwafadhaishe."},{"v":7,"t":"Uinyoshe mikono yako toka juu, uniponye, Unitoe katika maji mengi, katika mkono wa wageni."},{"v":8,"t":"Vinywa vyao vyasema visivyofaa, Na mkono wao wa kuume ni mkono wa uongo."},{"v":9,"t":"Ee Mungu, nitakuimbia wimbo mpya, Kwa kinanda chenye nyuzi kumi nitakuimbia."},{"v":10,"t":"Awapaye wafalme wokovu, Amwokoa Daudi, mtumishi wake, na upanga wa uovu."},{"v":11,"t":"Uniponye, unitoe, Katika mkono wa wageni. Vinywa vyao vyasema visivyofaa, Na mkono wao wa kuume ni mkono wa uongo."},{"v":12,"t":"Wana wetu na wawe kama miche Waliokua ujanani. Binti zetu kama nguzo za pembeni Zilizonakishwa kwa kupamba hekalu."},{"v":13,"t":"Ghala zetu na zijae Zenye akiba za jinsi zote. Kondoo zetu na wazae Elfu na makumi elfu mashambani mwetu."},{"v":14,"t":"Ng'ombe zetu na wachukue mizigo, Kusiwe na kushambuliwa. Wala kusiwe na kuhamishwa, Wala malalamiko katika njia zetu."},{"v":15,"t":"Heri watu wenye hali hiyo, Heri watu wenye Bwana kuwa Mungu wao."}]},{"c":145,"verses":[{"v":1,"t":"Ee Mungu wangu, Mfalme, nitakutukuza, Nitalihimidi jina lako milele na milele."},{"v":2,"t":"Kila siku nitakuhimidi, Nitalisifu jina lako milele na milele."},{"v":3,"t":"Bwana ndiye mkuu mwenye kusifiwa sana, Wala ukuu wake hautambulikani."},{"v":4,"t":"Kizazi kwa kizazi kitayasifu matendo yako, Kitayatangaza matendo yako makuu."},{"v":5,"t":"Nitaifikiri fahari ya utukufu wa adhama yako, Na matendo yako yote ya ajabu."},{"v":6,"t":"Watu watayataja matendo yako ya kutisha, Nami nitausimulia ukuu wako."},{"v":7,"t":"Watalihubiri kumbukumbu la wema wako mkuu. Wataiimba haki yako."},{"v":8,"t":"Bwana ana fadhili, ni mwingi wa huruma, Si mwepesi wa hasira, ni mwingi wa rehema,"},{"v":9,"t":"Bwana ni mwema kwa watu wote, Na rehema zake zi juu ya kazi zake zote."},{"v":10,"t":"Ee Bwana, kazi zako zote zitakushukuru, Na wacha Mungu wako watakuhimidi."},{"v":11,"t":"Wataunena utukufu wa ufalme wako, Na kuuhadithia uweza wako."},{"v":12,"t":"Ili kuwajulisha watu matendo yake makuu, Na utukufu wa fahari ya ufalme wake."},{"v":13,"t":"Ufalme wako ni ufalme wa zamani zote, Na mamlaka yako ni ya vizazi vyote."},{"v":14,"t":"Bwana huwategemeza wote waangukao, Huwainua wote walioinama chini."},{"v":15,"t":"Macho ya watu wote yakuelekea Wewe, Nawe huwapa chakula chao wakati wake."},{"v":16,"t":"Waufumbua mkono wako, Wakishibisha kila kilicho hai matakwa yake."},{"v":17,"t":"Bwana ni mwenye haki katika njia zake zote, Na mwenye fadhili juu ya kazi zake zote."},{"v":18,"t":"Bwana yu karibu na wote wamwitao, Wote wamwitao kwa uaminifu."},{"v":19,"t":"Atawafanyia wamchao matakwa yao, Naye atakisikia kilio chao na kuwaokoa."},{"v":20,"t":"Bwana huwahifadhi wote wampendao, Na wote wasio haki atawaangamiza."},{"v":21,"t":"Kinywa changu kitazinena sifa za Bwana; Wote wenye mwili na walihimidi jina lake takatifu milele na milele."}]},{"c":146,"verses":[{"v":1,"t":"Haleluya. Ee nafsi yangu, umsifu Bwana."},{"v":2,"t":"Nitamsifu Bwana muda ninaoishi, Nitamwimbia Mungu wangu ningali ni hai."},{"v":3,"t":"Msiwatumainie wakuu, Wala binadamu ambaye hakuna wokovu kwake."},{"v":4,"t":"Pumzi yake hutoka, huurudia udongo wake, Siku hiyo mawazo yake yapotea."},{"v":5,"t":"Heri ambaye Mungu wa Yakobo ni msaada wake, Na tumaini lake ni kwa Bwana, Mungu wake,"},{"v":6,"t":"Aliyezifanya mbingu na nchi, Bahari na vitu vyote vilivyomo. Huishika kweli milele,"},{"v":7,"t":"Huwafanyia hukumu walioonewa, Huwapa wenye njaa chakula; Bwana hufungua waliofungwa;"},{"v":8,"t":"Bwana huwafumbua macho waliopofuka; Bwana huwainua walioinama; Bwana huwapenda wenye haki;"},{"v":9,"t":"Bwana huwahifadhi wageni; Huwategemeza yatima na mjane; Bali njia ya wasio haki huipotosha."},{"v":10,"t":"Bwana atamiliki milele, Mungu wako, Ee Sayuni, kizazi hata kizazi. Haleluya."}]},{"c":147,"verses":[{"v":1,"t":"Haleluya. Msifuni Bwana; Maana ni vema kumwimbia Mungu wetu, Maana kwapendeza, kusifu ni kuzuri."},{"v":2,"t":"Bwana ndiye aijengaye Yerusalemu, Huwakusanya waliotawanyika wa Israeli."},{"v":3,"t":"Huwaponya waliopondeka moyo, Na kuziganga jeraha zao."},{"v":4,"t":"Huihesabu idadi ya nyota, Huzipa zote majina."},{"v":5,"t":"Bwana wetu ni mkuu na mwingi wa nguvu, Akili zake hazina mpaka."},{"v":6,"t":"Bwana huwategemeza wenye upole, Huwaangusha chini wenye jeuri."},{"v":7,"t":"Mwimbieni Bwana kwa kushukuru, Mwimbieni Mungu wetu kwa kinubi."},{"v":8,"t":"Huzifunika mbingu kwa mawingu, Huitengenezea nchi mvua, Na kuyameesha majani milimani."},{"v":9,"t":"Humpa mnyama chakula chake, Wana-kunguru waliao."},{"v":10,"t":"Hapendezwi na nguvu za farasi, Wala hairidhii miguu ya mtu."},{"v":11,"t":"Bwana huwaridhia wao wamchao, Na kuzitarajia fadhili zake."},{"v":12,"t":"Msifu Bwana, Ee Yerusalemu; Msifu Mungu wako, Ee Sayuni."},{"v":13,"t":"Maana ameyakaza mapingo ya malango yako, Amewabariki wanao ndani yako."},{"v":14,"t":"Ndiye afanyaye amani mipakani mwako, Akushibishaye kwa unono wa ngano."},{"v":15,"t":"Huipeleka amri yake juu ya nchi, Neno lake lapiga mbio sana."},{"v":16,"t":"Ndiye atoaye theluji kama sufu, Huimwaga barafu yake kama majivu,"},{"v":17,"t":"Hutupa mvua ya mawe kama makombo, Mbele ya baridi yake ni nani awezaye kusimama?"},{"v":18,"t":"Hulituma neno lake na kuviyeyusha, Huuvumisha upepo wake, maji yakatiririka."},{"v":19,"t":"Humhubiri Yakobo neno lake, Na Israeli amri zake na hukumu zake."},{"v":20,"t":"Hakulitendea taifa lo lote mambo kama hayo, Wala hukumu zake hawakuzijua. Haleluya."}]},{"c":148,"verses":[{"v":1,"t":"Haleluya. Msifuni Bwana kutoka mbinguni; Msifuni katika mahali palipo juu."},{"v":2,"t":"Msifuni, enyi malaika wake wote; Msifuni, majeshi yake yote."},{"v":3,"t":"Msifuni, jua na mwezi; Msifuni, nyota zote zenye mwanga."},{"v":4,"t":"Msifuni, enyi mbingu za mbingu, Nanyi maji mlioko juu ya mbingu."},{"v":5,"t":"Na vilisifu jina la Bwana, Kwa maana aliamuru, vikaumbwa."},{"v":6,"t":"Amevithibitisha hata milele na milele, Ametoa amri wala haitapita."},{"v":7,"t":"Msifuni Bwana kutoka nchi, Enyi nyangumi na vilindi vyote."},{"v":8,"t":"Moto na mvua ya mawe, theluji na mvuke, Upepo wa dhoruba ulitendao neno lake."},{"v":9,"t":"Milima na vilima vyote, Miti yenye matunda na mierezi yote."},{"v":10,"t":"Hayawani, na wanyama wafugwao, Vitambaavyo, na ndege wenye mbawa."},{"v":11,"t":"Wafalme wa dunia, na watu wote, Wakuu, na makadhi wote wa dunia."},{"v":12,"t":"Vijana waume, na wanawali, Wazee, na watoto;"},{"v":13,"t":"Na walisifu jina la Bwana, Maana jina lake peke yake limetukuka; Adhama yake i juu ya nchi na mbingu."},{"v":14,"t":"Naye amewainulia watu wake pembe, Sifa za watauwa wake wote; Wana wa Israeli, watu walio karibu naye. Haleluya."}]},{"c":149,"verses":[{"v":1,"t":"Haleluya. Mwimbieni Bwana wimbo mpya, Sifa zake katika kusanyiko la watauwa."},{"v":2,"t":"Israeli na amfurahie Yeye aliyemfanya, Wana wa Sayuni na wamshangilie mfalme wao."},{"v":3,"t":"Na walisifu jina lake kwa kucheza, Kwa matari na kinubi wamwimbie."},{"v":4,"t":"Kwa kuwa Bwana awaridhia watu wake, Huwapamba wenye upole kwa wokovu."},{"v":5,"t":"Watauwa na waushangilie utukufu, Waimbe kwa sauti kuu vitandani mwao."},{"v":6,"t":"Sifa kuu za Mungu na ziwe vinywani mwao, Na upanga mkali kuwili mikononi mwao."},{"v":7,"t":"Ili kufanya kisasi juu ya mataifa, Na adhabu juu ya kabila za watu."},{"v":8,"t":"Wawafunge wafalme wao kwa minyororo, Na wakuu wao kwa pingu za chuma."},{"v":9,"t":"Kuwafanyia hukumu iliyoandikwa; Hiyo ndiyo heshima ya watauwa wake wote. Haleluya."}]},{"c":150,"verses":[{"v":1,"t":"Haleluya. Msifuni Mungu katika patakatifu pake; Msifuni katika anga la uweza wake."},{"v":2,"t":"Msifuni kwa matendo yake makuu; Msifuni kwa kadiri ya wingi wa ukuu wake."},{"v":3,"t":"Msifuni kwa mvumo wa baragumu; Msifuni kwa kinanda na kinubi;"},{"v":4,"t":"Msifuni kwa matari na kucheza; Msifuni kwa zeze na filimbi;"},{"v":5,"t":"Msifuni kwa matoazi yaliayo; Msifuni kwa matoazi yavumayo sana."},{"v":6,"t":"Kila mwenye pumzi na amsifu Bwana. Haleluya."}]}]};
